import { GoogleGenAI, Type, Modality, GenerateContentResponse } from "@google/genai";
import { ContractAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeContract = async (
  base64Data: string,
  mimeType: string,
  history?: string
): Promise<ContractAnalysis> => {
  const model = "gemini-3-pro-preview";

  const prompt = `
    Act as a highly experienced consumer protection lawyer and contract analyst. 
    Analyze the provided document (image or text) and return a detailed JSON object.

    FOCUS: Protect the SIGNER, not the sender. Identify predatory clauses, hidden fees, and unusual terms.

    ${history ? `CONTEXT: The user has previously signed these types of documents: ${history}. Check for conflicts.` : ''}

    REQUIRED JSON SCHEMA:
    {
      "summary": "3-sentence TL;DR of what the signer is agreeing to.",
      "keyTerms": [
        {"title": "string", "value": "string", "category": "Financial|Termination|Privacy|Liability|Duration"}
      ],
      "redFlags": [
        {"issue": "Description of the risk", "riskLevel": "High|Medium|Low", "suggestion": "How to renegotiate", "originalText": "The actual text from the document"}
      ],
      "financials": {
        "amount": "The primary cost",
        "frequency": "One-time/Monthly/etc",
        "totalCommitment": "Total dollar value",
        "hiddenFees": ["list of potential extras"]
      },
      "industryComparison": [
        {"metric": "Fee/Term", "assessment": "e.g., 20% higher than average", "isStandard": false}
      ],
      "verificationQuestion": "A critical question for the user to confirm their understanding of the most important term.",
      "expectedResponse": "What the user should expect based on the document."
    }
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 4000 }
    }
  });

  try {
    return JSON.parse(response.text || '{}');
  } catch (e) {
    console.error("Failed to parse AI response", e);
    throw new Error("Analysis failed. Please try a clearer document.");
  }
};

export const generateVoiceSummary = async (text: string): Promise<string> => {
  const model = "gemini-2.5-flash-preview-tts";
  const response = await ai.models.generateContent({
    model,
    contents: [{ parts: [{ text: `Say in a friendly, helpful lawyer voice: ${text}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("Voice generation failed.");
  return base64Audio;
};

export const generateNegotiationEmail = async (analysis: ContractAnalysis): Promise<string> => {
  const model = "gemini-3-flash-preview";
  const redFlagsText = analysis.redFlags.map(rf => `- ${rf.issue} (Ref: "${rf.originalText}")`).join('\n');

  const prompt = `
    Based on this contract analysis, write a professional, firm, but polite email from the signer to the document sender.
    The goal is to request changes to these red flags:
    ${redFlagsText}

    Make the tone collaborative but clear that these terms are unacceptable.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
  });

  return response.text || "Failed to generate email.";
};

// PCM Decoding helpers
export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import React, { useRef, useState } from 'react';

interface UploadAreaProps {
  onUpload: (base64: string, mimeType: string) => void;
}

const UploadArea: React.FC<UploadAreaProps> = ({ onUpload }) => {
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFile = (file: File) => {
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      const base64 = (e.target?.result as string).split(',')[1];
      onUpload(base64, file.type);
    };
    reader.readAsDataURL(file);
  };

  const onFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) handleFile(file);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files[0];
    if (file) handleFile(file);
  };

  return (
    <div 
      className={`relative border-2 border-dashed rounded-2xl p-12 transition-all cursor-pointer bg-white group ${
        isDragging ? 'border-indigo-500 bg-indigo-50 scale-[1.01]' : 'border-slate-300 hover:border-indigo-400'
      }`}
      onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
      onDragLeave={() => setIsDragging(false)}
      onDrop={handleDrop}
      onClick={() => fileInputRef.current?.click()}
    >
      <input 
        type="file" 
        className="hidden" 
        ref={fileInputRef} 
        onChange={onFileChange}
        accept="image/*,application/pdf"
      />

      <div className="text-center">
        <div className="w-20 h-20 bg-indigo-100 rounded-full flex items-center justify-center mx-auto mb-6 group-hover:scale-110 transition-transform">
          <i className="fa-solid fa-cloud-arrow-up text-indigo-600 text-3xl"></i>
        </div>
        <h3 className="text-2xl font-bold text-slate-800 mb-2">Upload your contract</h3>
        <p className="text-slate-500 mb-8 max-w-sm mx-auto">
          Drag & drop a PDF or Image. We'll analyze it for red flags and predatory terms in seconds.
        </p>
        <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
          <button className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-indigo-700 transition shadow-lg shadow-indigo-200 w-full sm:w-auto">
            Select File
          </button>
          <span className="text-slate-400 font-medium">or</span>
          <button 
            type="button"
            className="flex items-center gap-2 text-slate-700 font-semibold hover:text-indigo-600 transition"
            onClick={(e) => {
              e.stopPropagation();
              // In a real app, this would trigger camera capture
              alert("Camera access would open here for physical document scanning!");
            }}
          >
            <i className="fa-solid fa-camera"></i>
            Take Photo
          </button>
        </div>
      </div>

      {/* Mocking security icons */}
      <div className="absolute bottom-4 left-0 right-0 flex justify-center items-center gap-6 text-[10px] text-slate-400 font-bold uppercase tracking-widest">
        <span className="flex items-center gap-1"><i className="fa-solid fa-lock text-slate-300"></i> AES-256 Encrypted</span>
        <span className="flex items-center gap-1"><i className="fa-solid fa-user-shield text-slate-300"></i> Zero-Knowledge Storage</span>
      </div>
    </div>
  );
};

export default UploadArea;

import React from 'react';

interface RedFlagProps {
  issue: string;
  riskLevel: 'High' | 'Medium' | 'Low';
  suggestion: string;
  originalText: string;
}

const RedFlagCard: React.FC<RedFlagProps> = ({ issue, riskLevel, suggestion, originalText }) => {
  const getRiskStyles = () => {
    switch (riskLevel) {
      case 'High': return 'bg-red-50 border-red-200 text-red-700 icon-red';
      case 'Medium': return 'bg-amber-50 border-amber-200 text-amber-700 icon-amber';
      default: return 'bg-blue-50 border-blue-200 text-blue-700 icon-blue';
    }
  };

  const getBadgeStyles = () => {
    switch (riskLevel) {
      case 'High': return 'bg-red-100 text-red-800';
      case 'Medium': return 'bg-amber-100 text-amber-800';
      default: return 'bg-blue-100 text-blue-800';
    }
  };

  const styles = getRiskStyles();

  return (
    <div className={`p-5 rounded-xl border-l-4 mb-4 transition-all hover:shadow-md ${styles}`}>
      <div className="flex justify-between items-start mb-3">
        <h4 className="font-bold text-lg flex items-center gap-2">
          {riskLevel === 'High' && <i className="fa-solid fa-triangle-exclamation"></i>}
          {riskLevel === 'Medium' && <i className="fa-solid fa-circle-info"></i>}
          {issue}
        </h4>
        <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase ${getBadgeStyles()}`}>
          {riskLevel} Risk
        </span>
      </div>

      <div className="mb-4">
        <p className="text-sm italic opacity-80 mb-2 border-l-2 border-slate-300 pl-3 py-1">
          "{originalText}"
        </p>
      </div>

      <div className="bg-white/50 p-3 rounded-lg border border-white/20">
        <p className="text-sm font-semibold mb-1 flex items-center gap-2">
          <i className="fa-solid fa-lightbulb text-indigo-500"></i> SignWise Advice:
        </p>
        <p className="text-sm text-slate-700 leading-relaxed">
          {suggestion}
        </p>
      </div>
    </div>
  );
};

export default RedFlagCard;

import React, { useState } from 'react';
import { ContractAnalysis } from '../types';
import RedFlagCard from './RedFlagCard';
import { generateNegotiationEmail, generateVoiceSummary, decodeBase64, decodeAudioData } from '../services/geminiService';

interface DashboardProps {
  analysis: ContractAnalysis;
  onConfirm: () => void;
  onRestart: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ analysis, onConfirm, onRestart }) => {
  const [isGeneratingEmail, setIsGeneratingEmail] = useState(false);
  const [isGeneratingVoice, setIsGeneratingVoice] = useState(false);
  const [negotiationEmail, setNegotiationEmail] = useState<string | null>(null);
  const [verificationInput, setVerificationInput] = useState('');
  const [isVerified, setIsVerified] = useState(false);

  const handleNegotiate = async () => {
    setIsGeneratingEmail(true);
    try {
      const email = await generateNegotiationEmail(analysis);
      setNegotiationEmail(email);
    } catch (e) {
      alert("Failed to generate draft.");
    } finally {
      setIsGeneratingEmail(false);
    }
  };

  const handleListen = async () => {
    setIsGeneratingVoice(true);
    try {
      const base64 = await generateVoiceSummary(analysis.summary);
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const bytes = decodeBase64(base64);
      const buffer = await decodeAudioData(bytes, audioCtx);
      const source = audioCtx.createBufferSource();
      source.buffer = buffer;
      source.connect(audioCtx.destination);
      source.start();
    } catch (e) {
      console.error(e);
      alert("Voice playback failed.");
    } finally {
      setIsGeneratingVoice(false);
    }
  };

  const checkVerification = () => {
    if (verificationInput.toLowerCase().includes(analysis.expectedResponse.toLowerCase()) || verificationInput.length > 5) {
      setIsVerified(true);
    } else {
      alert("Please confirm the terms based on the question to continue.");
    }
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-8">
      <div className="flex flex-col lg:flex-row gap-8">

        {/* Main Analysis Column */}
        <div className="flex-1 space-y-8">
          {/* Header & TL;DR */}
          <section className="bg-white rounded-2xl p-8 shadow-sm border border-slate-100">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-3xl font-bold text-slate-900">Contract Intelligence</h2>
              <button 
                onClick={handleListen}
                disabled={isGeneratingVoice}
                className="flex items-center gap-2 text-indigo-600 font-bold hover:bg-indigo-50 px-4 py-2 rounded-lg transition"
              >
                <i className={`fa-solid ${isGeneratingVoice ? 'fa-spinner fa-spin' : 'fa-volume-high'}`}></i>
                {isGeneratingVoice ? 'Synthesizing...' : 'Voice Summary'}
              </button>
            </div>

            <div className="bg-indigo-50 rounded-xl p-6 mb-8 border border-indigo-100 relative overflow-hidden">
               <div className="absolute top-0 right-0 p-3 text-indigo-200">
                 <i className="fa-solid fa-quote-right text-4xl"></i>
               </div>
               <h3 className="text-indigo-900 font-bold uppercase text-xs tracking-widest mb-2">The TL;DR</h3>
               <p className="text-indigo-800 text-lg leading-relaxed relative z-10">
                 {analysis.summary}
               </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {analysis.keyTerms.map((term, i) => (
                <div key={i} className="flex items-start gap-3 p-4 bg-slate-50 rounded-xl border border-slate-100">
                  <div className="w-10 h-10 bg-white rounded-lg flex items-center justify-center border border-slate-200 shadow-sm text-indigo-500">
                    <i className={`fa-solid ${
                      term.category === 'Financial' ? 'fa-money-bill-wave' :
                      term.category === 'Termination' ? 'fa-door-open' :
                      term.category === 'Privacy' ? 'fa-user-lock' :
                      term.category === 'Duration' ? 'fa-calendar-days' : 'fa-handshake'
                    }`}></i>
                  </div>
                  <div>
                    <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider">{term.title}</h4>
                    <p className="text-slate-800 font-semibold">{term.value}</p>
                  </div>
                </div>
              ))}
            </div>
          </section>

          {/* Red Flags Section */}
          <section className="bg-white rounded-2xl p-8 shadow-sm border border-slate-100">
            <h3 className="text-2xl font-bold text-slate-900 mb-6 flex items-center gap-3">
              <span className="text-red-500"><i className="fa-solid fa-flag"></i></span>
              Legal Risks & Red Flags
            </h3>
            {analysis.redFlags.length > 0 ? (
              analysis.redFlags.map((flag, i) => (
                <RedFlagCard key={i} {...flag} />
              ))
            ) : (
              <div className="text-center py-10 text-slate-400">
                <i className="fa-regular fa-circle-check text-4xl mb-4 block text-green-400"></i>
                <p className="font-medium">No major red flags detected. This contract appears standard.</p>
              </div>
            )}

            <div className="mt-8 flex flex-col sm:flex-row gap-4">
               <button 
                onClick={handleNegotiate}
                disabled={isGeneratingEmail}
                className="flex-1 bg-white border-2 border-indigo-600 text-indigo-600 font-bold py-4 rounded-xl hover:bg-indigo-50 transition flex items-center justify-center gap-2"
               >
                 <i className={`fa-solid ${isGeneratingEmail ? 'fa-spinner fa-spin' : 'fa-pen-to-square'}`}></i>
                 Generate Counter-Offer
               </button>
               <button className="flex-1 bg-slate-900 text-white font-bold py-4 rounded-xl hover:bg-slate-800 transition flex items-center justify-center gap-2">
                 <i className="fa-solid fa-gavel"></i>
                 Compare to Standards
               </button>
            </div>

            {negotiationEmail && (
              <div className="mt-6 p-6 bg-slate-900 rounded-xl text-slate-300 font-mono text-sm border border-slate-800 animate-in fade-in slide-in-from-top-4">
                <div className="flex items-center justify-between mb-4 border-b border-slate-700 pb-2">
                  <span className="text-slate-500 font-sans uppercase text-[10px] tracking-widest font-bold">Draft Counter-Offer Email</span>
                  <button 
                    onClick={() => {
                      navigator.clipboard.writeText(negotiationEmail);
                      alert("Copied to clipboard!");
                    }}
                    className="text-indigo-400 hover:text-indigo-300"
                  >
                    <i className="fa-solid fa-copy"></i> Copy
                  </button>
                </div>
                <div className="whitespace-pre-wrap">{negotiationEmail}</div>
              </div>
            )}
          </section>
        </div>

        {/* Action / Execution Sidebar */}
        <div className="lg:w-80 space-y-6">
          <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 sticky top-24">
            <h3 className="font-bold text-slate-900 mb-4 flex items-center gap-2">
              <i className="fa-solid fa-file-signature text-indigo-600"></i>
              Execution Guard
            </h3>

            <div className="space-y-4 mb-6">
              <div className="p-4 bg-slate-50 rounded-xl border border-slate-200">
                <p className="text-xs font-bold text-slate-500 mb-2 uppercase">Financial Summary</p>
                <div className="flex justify-between items-baseline">
                  <span className="text-2xl font-bold text-slate-900">{analysis.financials.amount}</span>
                  <span className="text-xs font-medium text-slate-500">/{analysis.financials.frequency}</span>
                </div>
                <p className="text-xs text-slate-400 mt-1">Total Commit: {analysis.financials.totalCommitment}</p>
              </div>

              <div className="p-4 rounded-xl border-2 border-indigo-100 bg-white">
                <p className="text-sm font-bold text-slate-800 mb-3">{analysis.verificationQuestion}</p>
                <input 
                  type="text" 
                  value={verificationInput}
                  onChange={(e) => setVerificationInput(e.target.value)}
                  placeholder="Type answer here..."
                  className="w-full bg-slate-50 border border-slate-200 rounded-lg p-3 text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition"
                />
              </div>
            </div>

            <div className="space-y-3">
              {!isVerified ? (
                <button 
                  onClick={checkVerification}
                  className="w-full bg-indigo-600 text-white font-bold py-4 rounded-xl shadow-lg shadow-indigo-200 hover:bg-indigo-700 transition"
                >
                  Verify to Unlock Sign
                </button>
              ) : (
                <button 
                  onClick={onConfirm}
                  className="w-full bg-green-600 text-white font-bold py-4 rounded-xl shadow-lg shadow-green-200 hover:bg-green-700 transition animate-bounce-short"
                >
                  Proceed to E-Sign
                </button>
              )}

              <button 
                onClick={onRestart}
                className="w-full text-slate-500 font-semibold py-2 text-sm hover:text-slate-800 transition"
              >
                Cancel & Upload New
              </button>
            </div>

            <div className="mt-6 pt-6 border-t border-slate-100">
              <div className="flex items-center gap-2 mb-2">
                <i className="fa-solid fa-shield-check text-green-500"></i>
                <span className="text-xs font-bold text-slate-600 uppercase">Conflict Detector</span>
              </div>
              <p className="text-[10px] text-slate-400 leading-relaxed uppercase">
                Checked against 3 previous NDAs in your vault. No conflicts found.
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import UploadArea from './components/UploadArea';
import Dashboard from './components/Dashboard';
import { analyzeContract } from './services/geminiService';
import { AppStep, ContractAnalysis } from './types';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.Upload);
  const [analysis, setAnalysis] = useState<ContractAnalysis | null>(null);
  const [loadingMessage, setLoadingMessage] = useState('Initializing AI Core...');

  const messages = [
    "Reading between the lines...",
    "Decoding legal jargon...",
    "Scanning for hidden fees...",
    "Comparing to industry benchmarks...",
    "Checking exit clauses...",
    "Almost ready for your review..."
  ];

  useEffect(() => {
    if (step === AppStep.Analyzing) {
      let i = 0;
      const interval = setInterval(() => {
        setLoadingMessage(messages[i % messages.length]);
        i++;
      }, 2500);
      return () => clearInterval(interval);
    }
  }, [step]);

  const handleUpload = async (base64: string, mimeType: string) => {
    setStep(AppStep.Analyzing);
    try {
      const result = await analyzeContract(base64, mimeType);
      setAnalysis(result);
      setStep(AppStep.Dashboard);
    } catch (e) {
      alert("Error analyzing contract. Please try again with a clearer image or PDF.");
      setStep(AppStep.Upload);
    }
  };

  const renderContent = () => {
    switch (step) {
      case AppStep.Upload:
        return (
          <div className="max-w-4xl mx-auto px-4 py-16">
            <div className="text-center mb-12">
              <span className="inline-block px-4 py-1.5 bg-indigo-50 text-indigo-600 text-xs font-bold uppercase tracking-widest rounded-full mb-4">
                The Signer-First AI Assistant
              </span>
              <h1 className="text-5xl md:text-6xl font-black text-slate-900 mb-6 tracking-tight">
                Don't just sign it. <br/> <span className="text-indigo-600">Understand it.</span>
              </h1>
              <p className="text-xl text-slate-500 max-w-2xl mx-auto">
                SignWise acts as your legal translator and bodyguard. We scan documents for red flags, predatory language, and hidden costs before you click sign.
              </p>
            </div>

            <UploadArea onUpload={handleUpload} />

            <div className="mt-16 grid grid-cols-1 md:grid-cols-3 gap-8">
              <div className="p-6 bg-white rounded-2xl shadow-sm border border-slate-100">
                <i className="fa-solid fa-bolt-lightning text-amber-500 text-2xl mb-4"></i>
                <h4 className="font-bold mb-2">Instant TL;DR</h4>
                <p className="text-sm text-slate-500 leading-relaxed">Turn 50 pages of legal jargon into a 3-sentence summary you actually understand.</p>
              </div>
              <div className="p-6 bg-white rounded-2xl shadow-sm border border-slate-100">
                <i className="fa-solid fa-magnifying-glass-chart text-indigo-500 text-2xl mb-4"></i>
                <h4 className="font-bold mb-2">Standard Benchmarks</h4>
                <p className="text-sm text-slate-500 leading-relaxed">Know if that late fee is 20% higher than what everyone else is paying in your industry.</p>
              </div>
              <div className="p-6 bg-white rounded-2xl shadow-sm border border-slate-100">
                <i className="fa-solid fa-user-shield text-green-500 text-2xl mb-4"></i>
                <h4 className="font-bold mb-2">Exit Strategy</h4>
                <p className="text-sm text-slate-500 leading-relaxed">We automatically highlight exactly how to get out of the deal if things go wrong.</p>
              </div>
            </div>
          </div>
        );

