import { GoogleGenAI, Type, Modality, GenerateContentResponse } from "@google/genai";
import { ContractAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeContract = async (
  base64Data: string,
  mimeType: string,
  history?: string
): Promise<ContractAnalysis> => {
  const model = "gemini-3-pro-preview";

  const prompt = `
    Act as a highly experienced consumer protection lawyer and contract analyst. 
    Analyze the provided document (image or text) and return a detailed JSON object.

    FOCUS: Protect the SIGNER, not the sender. Identify predatory clauses, hidden fees, and unusual terms.

    ${history ? `CONTEXT: The user has previously signed these types of documents: ${history}. Check for conflicts.` : ''}

    REQUIRED JSON SCHEMA:
    {
      "summary": "3-sentence TL;DR of what the signer is agreeing to.",
      "keyTerms": [
        {"title": "string", "value": "string", "category": "Financial|Termination|Privacy|Liability|Duration"}
      ],
      "redFlags": [
        {
          "issue": "Description of the risk",
          "riskLevel": "High|Medium|Low",
          "suggestion": {
            "whyItMatters": "Explanation of how this term harms the signer specifically.",
            "strategy": "Tactical advice on how to approach the negotiation.",
            "counterOffer": "A specific alternative sentence or clause to propose."
          },
          "originalText": "The actual text from the document"
        }
      ],
      "financials": {
        "amount": "The primary cost",
        "frequency": "One-time/Monthly/etc",
        "totalCommitment": "Total dollar value",
        "hiddenFees": ["list of potential extras"]
      },
      "industryComparison": [
        {"metric": "Fee/Term", "assessment": "e.g., 20% higher than average", "isStandard": false}
      ],
      "verificationQuestion": "A critical question for the user to confirm their understanding of the most important term.",
      "expectedResponse": "What the user should expect based on the document."
    }
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 4000 }
    }
  });

  try {
    return JSON.parse(response.text || '{}');
  } catch (e) {
    console.error("Failed to parse AI response", e);
    throw new Error("Analysis failed. Please try a clearer document.");
  }
};

export const generateVoiceSummary = async (text: string): Promise<string> => {
  const model = "gemini-2.5-flash-preview-tts";
  const response = await ai.models.generateContent({
    model,
    contents: [{ parts: [{ text: `Say in a friendly, helpful lawyer voice: ${text}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("Voice generation failed.");
  return base64Audio;
};

export const generateNegotiationEmail = async (analysis: ContractAnalysis): Promise<string> => {
  const model = "gemini-3-flash-preview";
  const redFlagsText = analysis.redFlags.map(rf => `- ${rf.issue} (Ref: "${rf.originalText}")`).join('\n');

  const prompt = `
    Based on this contract analysis, write a professional, firm, but polite email from the signer to the document sender.
    The goal is to request changes to these red flags:
    ${redFlagsText}

    Make the tone collaborative but clear that these terms are unacceptable.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
  });

  return response.text || "Failed to generate email.";
};

// PCM Decoding helpers
export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

