        </div>
      </div>

      <div className="absolute bottom-4 left-0 right-0 flex justify-center items-center gap-6 text-[10px] text-slate-400 font-bold uppercase tracking-widest">
        <span className="flex items-center gap-1"><i className="fa-solid fa-magic text-indigo-400"></i> AI-Powered Classification</span>
