  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("Voice generation failed.");
  return base64Audio;
};

export const generateNegotiationEmail = async (analysis: ContractAnalysis): Promise<string> => {
  const model = "gemini-3-flash-preview";
  const redFlagsText = analysis.redFlags.map(rf => `- ${rf.issue} (Ref: "${rf.originalText}")`).join('\n');

  const prompt = `
    Write a professional, collaborative negotiation email for the signer to send.
    Focus on these red flags:
    ${redFlagsText}
    Request fair modifications while maintaining a positive relationship.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
  });

  return response.text || "";
};

export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import React, { useRef, useEffect, useState } from 'react';

interface SignaturePadProps {
  onSign: (dataUrl: string) => void;
  onClear: () => void;
}

const SignaturePad: React.FC<SignaturePadProps> = ({ onSign, onClear }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.strokeStyle = '#1e293b';
    ctx.lineWidth = 3;
    ctx.lineCap = 'round';
  }, []);

  const getPos = (e: React.MouseEvent | React.TouchEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;
    return {
      x: clientX - rect.left,
      y: clientY - rect.top
    };
  };

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    const { x, y } = getPos(e);
    const ctx = canvasRef.current?.getContext('2d');
    if (!ctx) return;
    ctx.beginPath();
    ctx.moveTo(x, y);
    setIsDrawing(true);
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing) return;
    const { x, y } = getPos(e);
    const ctx = canvasRef.current?.getContext('2d');
    if (!ctx) return;
    ctx.lineTo(x, y);
    ctx.stroke();
  };

  const endDrawing = () => {
    setIsDrawing(false);
    if (canvasRef.current) {
      onSign(canvasRef.current.toDataURL());
    }
  };

  const clear = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    onClear();
  };

  return (
    <div className="relative w-full h-48 bg-white border-2 border-slate-200 rounded-2xl overflow-hidden cursor-crosshair group hover:border-indigo-400 transition-all">
      <canvas
        ref={canvasRef}
        width={600}
        height={200}
        className="w-full h-full touch-none"
        onMouseDown={startDrawing}
        onMouseMove={draw}
        onMouseUp={endDrawing}
        onMouseLeave={endDrawing}
        onTouchStart={startDrawing}
        onTouchMove={draw}
        onTouchEnd={endDrawing}
      />
      {!isDrawing && (
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-20 text-2xl font-serif italic select-none">
          Sign here...
        </div>
      )}
      <button 
        onClick={(e) => { e.stopPropagation(); clear(); }}
        className="absolute top-2 right-2 bg-slate-100 hover:bg-slate-200 text-slate-500 p-2 rounded-lg text-xs font-bold transition"
      >
        Clear
      </button>
    </div>
  );
};

export default SignaturePad;

import React, { useRef, useState } from 'react';

interface UploadAreaProps {
  onUpload: (base64: string, mimeType: string) => void;
}

const UploadArea: React.FC<UploadAreaProps> = ({ onUpload }) => {
  const [isDragging, setIsDragging] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [recordingType, setRecordingType] = useState<'audio' | 'video' | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  const handleFile = (file: File) => {
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      const base64 = (e.target?.result as string).split(',')[1];
      onUpload(base64, file.type);
    };
    reader.readAsDataURL(file);
  };

  const startRecording = async (type: 'audio' | 'video') => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        audio: true, 
        video: type === 'video' 
      });
      setRecordingType(type);
      setIsRecording(true);
      chunksRef.current = [];

      const recorder = new MediaRecorder(stream);
      mediaRecorderRef.current = recorder;

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      recorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: recorder.mimeType });
        const reader = new FileReader();
        reader.onloadend = () => {
          const base64 = (reader.result as string).split(',')[1];
          onUpload(base64, recorder.mimeType);
        };
        reader.readAsDataURL(blob);
        stream.getTracks().forEach(track => track.stop());
      };

      recorder.start();
    } catch (err) {
      alert("Microphone/Camera access denied.");
      console.error(err);
    }
  };

  const stopRecording = () => {
    mediaRecorderRef.current?.stop();
    setIsRecording(false);
    setRecordingType(null);
  };

  return (
    <div 
      className={`relative border-2 border-dashed rounded-2xl p-12 transition-all cursor-pointer bg-white group ${
        isDragging ? 'border-indigo-500 bg-indigo-50 scale-[1.01]' : 'border-slate-300 hover:border-indigo-400'
      }`}
      onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
      onDragLeave={() => setIsDragging(false)}
      onDrop={(e) => {
        e.preventDefault();
        setIsDragging(false);
        const file = e.dataTransfer.files[0];
        if (file) handleFile(file);
      }}
      onClick={() => !isRecording && fileInputRef.current?.click()}
    >
      <input 
        type="file" 
        className="hidden" 
        ref={fileInputRef} 
        onChange={(e) => e.target.files?.[0] && handleFile(e.target.files[0])}
        accept="*"
      />

      {isRecording ? (
        <div className="text-center py-4">
          <div className="w-20 h-20 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-6 animate-pulse">
            <div className="w-6 h-6 bg-red-600 rounded-sm"></div>
          </div>
          <h3 className="text-2xl font-bold text-slate-800 mb-2 uppercase tracking-tight">Recording {recordingType}...</h3>
          <p className="text-slate-500 mb-8">Speak clearly about the terms you want in your contract.</p>
          <button 
            onClick={(e) => { e.stopPropagation(); stopRecording(); }}
            className="bg-slate-900 text-white px-12 py-4 rounded-xl font-bold hover:bg-slate-800 transition shadow-xl"
          >
            Finish & Generate
          </button>
        </div>
      ) : (
        <div className="text-center">
          <div className="flex justify-center -space-x-2 mb-6">
            <div className="w-12 h-12 bg-indigo-100 rounded-full flex items-center justify-center border-2 border-white shadow-sm text-indigo-600">
              <i className="fa-solid fa-file-pdf"></i>
            </div>
            <div className="w-12 h-12 bg-emerald-100 rounded-full flex items-center justify-center border-2 border-white shadow-sm text-emerald-600 z-10 scale-110">
              <i className="fa-solid fa-cloud-arrow-up"></i>
            </div>
            <div className="w-12 h-12 bg-amber-100 rounded-full flex items-center justify-center border-2 border-white shadow-sm text-amber-600">
              <i className="fa-solid fa-video"></i>
            </div>
          </div>

          <h3 className="text-2xl font-bold text-slate-800 mb-2">Universal Document Hub</h3>
          <p className="text-slate-500 mb-8 max-w-sm mx-auto">
            Upload <b>any file type</b> for review, or use the mic/camera to brief the AI for a new contract.
          </p>

          <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
            <button className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-indigo-700 transition shadow-lg shadow-indigo-200 w-full sm:w-auto">
              Select File
            </button>
            <span className="text-slate-400 font-medium">or</span>
            <div className="flex gap-2">
              <button 
                type="button"
                className="flex items-center gap-2 text-slate-700 font-semibold hover:text-indigo-600 transition bg-slate-50 px-4 py-2 rounded-lg border border-slate-200"
                onClick={(e) => { e.stopPropagation(); startRecording('audio'); }}
              >
                <i className="fa-solid fa-microphone"></i>
                Voice
              </button>
              <button 
                type="button"
                className="flex items-center gap-2 text-slate-700 font-semibold hover:text-indigo-600 transition bg-slate-50 px-4 py-2 rounded-lg border border-slate-200"
                onClick={(e) => { e.stopPropagation(); startRecording('video'); }}
              >
                <i className="fa-solid fa-video"></i>
                Video
              </button>
            </div>
          </div>
        </div>
      )}

      {!isRecording && (
        <div className="absolute bottom-4 left-0 right-0 flex justify-center items-center gap-6 text-[10px] text-slate-400 font-bold uppercase tracking-widest">
          <span className="flex items-center gap-1"><i className="fa-solid fa-magic text-indigo-400"></i> AI-Powered Classification</span>
          <span className="flex items-center gap-1"><i className="fa-solid fa-user-shield text-slate-300"></i> Secure & Private</span>
        </div>
      )}
    </div>
  );
};

