        );

      case AppStep.Finalized:
        return (
          <div className="max-w-xl mx-auto py-20 px-4 text-center">
            <div className="w-24 h-24 bg-green-500 rounded-full flex items-center justify-center mx-auto mb-8 shadow-xl shadow-green-200"><i className="fa-solid fa-check text-white text-5xl"></i></div>
