            <p className="text-slate-500 text-lg mb-10 leading-relaxed">Document securely encrypted and saved to your personal vault.</p>
            {signature && (
               <div className="mb-8 p-4 bg-slate-50 rounded-xl border border-slate-200">
                 <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2">Authenticated Signature Preview</p>
                 <img src={signature} alt="Signature" className="mx-auto h-20 object-contain opacity-70" />
