            <div className="flex flex-col gap-4">
              <button className="bg-slate-900 text-white font-bold py-4 rounded-xl hover:bg-slate-800 transition flex items-center justify-center gap-2"><i className="fa-solid fa-download"></i>Download Signed PDF</button>
