            </div>
          </div>
        );
    }
  };

  return (
    <Layout>
      <div className="relative">{renderContent()}</div>
      <div className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-sm border-t border-slate-200 p-3 z-[60] text-center shadow-lg md:block hidden">
        <p className="text-[10px] text-slate-500 font-medium max-w-4xl mx-auto uppercase tracking-tighter">SignWise AI v3.5 - High-fidelity legal analysis. Vault sync active ({vault.length} docs).</p>
      </div>
    </Layout>
  );
};

