import { GoogleGenAI, Type, Modality, GenerateContentResponse } from "@google/genai";
import { ContractAnalysis, ClassificationResult, ContractHistoryItem } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const classifyUpload = async (
  base64Data: string,
  mimeType: string
): Promise<ClassificationResult> => {
  const model = "gemini-3-flash-preview";
  const prompt = `
    Analyze this file carefully. 
    Is this an existing legal document/contract that needs analysis (REVIEW)? 
    Or is this a request, notes, or media (audio/video/text) intended to be turned into a new legal document (CREATE)?

    Return JSON:
    {
      "intent": "REVIEW" | "CREATE",
      "reasoning": "Brief explanation",
      "suggestedFileName": "A meaningful filename based on content"
    }
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: prompt }
      ]
    },
    config: { responseMimeType: "application/json" }
  });

  return JSON.parse(response.text || '{"intent": "REVIEW"}');
};

export const generateContractContent = async (
  base64Data: string,
  mimeType: string
): Promise<string> => {
  const model = "gemini-3-pro-preview";
  const prompt = `
    Act as a professional legal drafter. 
    Based on the provided content (instructions, video/audio brief, or notes), 
    generate a complete, professional, and legally-sound contract. 
    Ensure it is fair to the signer and covers all necessary protections for both parties.
    Return only the contract text in Markdown format.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: prompt }
      ]
    },
    config: { thinkingConfig: { thinkingBudget: 8000 } }
  });

  return response.text || "";
};

export const refineContract = async (content: string, instruction: string): Promise<string> => {
  const model = "gemini-3-flash-preview";
  const prompt = `Refine this legal contract content based on the following instruction: ${instruction}. 
  Content:
  ${content}
  Return only the refined Markdown text. Do not add any conversational text.`;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
  });

  return response.text || content;
};

export const analyzeContract = async (
  base64Data: string,
  mimeType: string,
  history: ContractHistoryItem[] = []
): Promise<ContractAnalysis> => {
  const model = "gemini-3-pro-preview";

  const historyText = history.length > 0 
    ? `CONTEXT: The user has previously signed these documents: ${history.map(h => `${h.name} (${h.type}): ${h.summary}`).join('; ')}. Check the current document for any legal or logical conflicts with these past terms.`
    : '';

  const prompt = `
    Act as a highly experienced consumer protection lawyer. 
    Analyze the provided document and return a detailed JSON object.
    FOCUS: Protect the SIGNER.

    ${historyText}

    REQUIRED JSON SCHEMA:
    {
      "summary": "3-sentence TL;DR of what the signer is agreeing to.",
      "keyTerms": [
        {"title": "string", "value": "string", "category": "Financial|Termination|Privacy|Liability|Duration"}
      ],
      "redFlags": [
        {
          "issue": "Description of the risk",
          "riskLevel": "High|Medium|Low",
          "suggestion": {
            "whyItMatters": "How this harms the signer",
            "strategy": "How to negotiate",
            "counterOffer": "Specific alternative clause"
          },
          "originalText": "The actual text"
        }
      ],
      "financials": {
        "amount": "Primary cost",
        "frequency": "Frequency",
        "totalCommitment": "Total dollar value",
        "hiddenFees": ["List of potential extra costs"]
      },
      "industryComparison": [
        {"metric": "Fee/Term", "assessment": "e.g., 20% higher than average", "isStandard": false}
      ],
      "verificationQuestion": "Critical question for user confirmation",
      "expectedResponse": "Expected confirmation based on doc",
      "conflictCheck": {
        "hasConflict": boolean,
        "conflictDetails": "Details of any conflicts with previous documents provided in context"
      }
    }
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 8000 }
    }
  });

  try {
    return JSON.parse(response.text || '{}');
  } catch (e) {
    throw new Error("Analysis failed. Content might be too complex or unclear.");
  }
};

export const compareWithStandards = async (analysis: ContractAnalysis): Promise<string> => {
  const model = "gemini-3-flash-preview";
  const prompt = `Based on this contract analysis, provide a detailed comparison with industry standards. 
  Highlight where the terms are better or worse for the signer. 
  Analysis Data: ${JSON.stringify(analysis)}
  Return a Markdown formatted summary.`;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
  });

  return response.text || "Comparison unavailable.";
};

export const generateVoiceSummary = async (text: string): Promise<string> => {
  const model = "gemini-2.5-flash-preview-tts";
  const response = await ai.models.generateContent({
    model,
    contents: [{ parts: [{ text: `Say in a friendly, helpful lawyer voice: ${text}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("Voice generation failed.");
  return base64Audio;
};

export const generateNegotiationEmail = async (analysis: ContractAnalysis): Promise<string> => {
  const model = "gemini-3-flash-preview";
  const redFlagsText = analysis.redFlags.map(rf => `- ${rf.issue} (Ref: "${rf.originalText}")`).join('\n');

  const prompt = `
    Write a professional, collaborative negotiation email for the signer to send.
    Focus on these red flags:
    ${redFlagsText}
    Request fair modifications while maintaining a positive relationship.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
  });

  return response.text || "";
};

export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import React, { useState } from 'react';
import { ContractAnalysis } from '../types';
