import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import UploadArea from './components/UploadArea';
import Dashboard from './components/Dashboard';
import ContractCreator from './components/ContractCreator';
import SignaturePad from './components/SignaturePad';
import { analyzeContract, classifyUpload, generateContractContent } from './services/geminiService';
import { AppStep, ContractAnalysis, ContractHistoryItem } from './types';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.Upload);
  const [analysis, setAnalysis] = useState<ContractAnalysis | null>(null);
  const [generatedContent, setGeneratedContent] = useState<string>('');
  const [loadingMessage, setLoadingMessage] = useState('Initializing AI Core...');
  const [vault, setVault] = useState<ContractHistoryItem[]>([]);
  const [signature, setSignature] = useState<string | null>(null);

  useEffect(() => {
    const savedVault = localStorage.getItem('signwise_vault');
    if (savedVault) setVault(JSON.parse(savedVault));
  }, []);

  const saveToVault = (item: ContractHistoryItem) => {
    const updated = [item, ...vault];
    setVault(updated);
    localStorage.setItem('signwise_vault', JSON.stringify(updated));
  };

  useEffect(() => {
    if (step === AppStep.Analyzing) {
      const messages = ["Reading content...", "Identifying intent...", "Scanning risks...", "Cross-referencing vault..."];
      let i = 0;
      const interval = setInterval(() => {
        setLoadingMessage(messages[i % messages.length]);
        i++;
      }, 2000);
      return () => clearInterval(interval);
    }
  }, [step]);

  const handleUpload = async (base64: string, mimeType: string) => {
    setStep(AppStep.Analyzing);
    try {
      const classification = await classifyUpload(base64, mimeType);

      if (classification.intent === 'REVIEW') {
        const result = await analyzeContract(base64, mimeType, vault);
        setAnalysis(result);
        setStep(AppStep.Dashboard);
      } else {
        const result = await generateContractContent(base64, mimeType);
        setGeneratedContent(result);
        setStep(AppStep.Creator);
      }
    } catch (e) {
      console.error(e);
      alert("Processing failed. Please use a clearer file.");
      setStep(AppStep.Upload);
    }
  };

  const finalizeSigning = () => {
    if (!signature) {
      alert("Please provide a signature.");
      return;
    }

    const newItem: ContractHistoryItem = {
      id: Date.now().toString(),
      name: analysis?.summary.slice(0, 30) || "New Contract",
      date: new Date().toLocaleDateString(),
      type: analysis ? "Review & Sign" : "Draft & Sign",
      summary: analysis?.summary || generatedContent.slice(0, 100)
    };
    saveToVault(newItem);
    setStep(AppStep.Finalized);
  };

  const handleNavigate = (view: string) => {
    if (view === 'upload') setStep(AppStep.Upload);
    if (view === 'vault') setStep(AppStep.Vault);
    if (view === 'help' || view === 'pricing') {
       alert(`${view.charAt(0).toUpperCase() + view.slice(1)} view is under development.`);
    }
  };

  const renderContent = () => {
    switch (step) {
      case AppStep.Upload:
        return (
          <div className="max-w-4xl mx-auto px-4 py-16">
            <div className="text-center mb-12">
              <span className="inline-block px-4 py-1.5 bg-indigo-50 text-indigo-600 text-xs font-bold uppercase tracking-widest rounded-full mb-4">The Universal Legal Bodyguard</span>
              <h1 className="text-5xl md:text-6xl font-black text-slate-900 mb-6 tracking-tight leading-tight">Review or <span className="text-indigo-600 underline">Create.</span> <br/> Total Document Control.</h1>
              <p className="text-xl text-slate-500 max-w-2xl mx-auto">Upload any file type for analysis or brief the AI to draft a secure, signer-first contract ready for e-signature.</p>
            </div>
            <UploadArea onUpload={handleUpload} />
          </div>
        );

      case AppStep.Analyzing:
        return (
          <div className="flex flex-col items-center justify-center min-h-[70vh]">
            <div className="relative">
              <div className="w-32 h-32 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center"><i className="fa-solid fa-wand-magic-sparkles text-indigo-600 text-3xl"></i></div>
            </div>
            <h2 className="text-2xl font-bold mt-8 text-slate-800">{loadingMessage}</h2>
          </div>
        );

      case AppStep.Dashboard:
        return <Dashboard analysis={analysis!} onRestart={() => setStep(AppStep.Upload)} onConfirm={() => setStep(AppStep.Signing)} />;

      case AppStep.Creator:
        return <ContractCreator initialContent={generatedContent} onRestart={() => setStep(AppStep.Upload)} onConfirm={() => setStep(AppStep.Signing)} />;

      case AppStep.Vault:
        return (
          <div className="max-w-5xl mx-auto px-4 py-12">
            <div className="flex justify-between items-center mb-12">
              <h2 className="text-4xl font-black text-slate-900">Personal Vault</h2>
              <button onClick={() => setStep(AppStep.Upload)} className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-bold hover:bg-indigo-700 transition">Scan New</button>
            </div>
            {vault.length === 0 ? (
              <div className="bg-white rounded-3xl p-20 text-center border border-slate-100 shadow-sm">
                <i className="fa-solid fa-vault text-slate-200 text-6xl mb-6"></i>
                <p className="text-slate-400 font-bold">Your secure vault is empty.</p>
                <button onClick={() => setStep(AppStep.Upload)} className="mt-4 text-indigo-600 font-bold hover:underline">Get started by uploading a contract</button>
              </div>
            ) : (
              <div className="grid gap-6">
                {vault.map(item => (
                  <div key={item.id} className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm flex items-center justify-between group hover:border-indigo-200 transition">
                    <div className="flex items-center gap-6">
                       <div className="w-12 h-12 bg-slate-50 rounded-xl flex items-center justify-center text-slate-400 group-hover:text-indigo-600 transition">
                          <i className="fa-solid fa-file-contract text-xl"></i>
                       </div>
                       <div>
                         <h4 className="font-bold text-slate-900">{item.name}</h4>
                         <p className="text-xs text-slate-400 uppercase font-bold tracking-widest">{item.type} • {item.date}</p>
                       </div>
                    </div>
                    <button className="text-slate-400 hover:text-indigo-600 font-bold text-sm">View Analysis</button>
                  </div>
                ))}
              </div>
            )}
          </div>
        );

      case AppStep.Signing:
        return (
          <div className="max-w-xl mx-auto py-20 px-4 text-center">
             <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-6"><i className="fa-solid fa-file-contract text-green-600 text-3xl"></i></div>
             <h2 className="text-3xl font-bold text-slate-900 mb-4">Execute Document</h2>
             <p className="text-slate-500 mb-10 leading-relaxed">Sign within the secure container below. Your signature is encrypted and permanently bound to this document version.</p>
             <SignaturePad onSign={(data) => setSignature(data)} onClear={() => setSignature(null)} />
             <div className="flex gap-4 mt-8">
                <button onClick={finalizeSigning} className="flex-1 bg-indigo-600 text-white font-bold py-4 rounded-xl shadow-lg hover:bg-indigo-700 transition">Finalize & Sign</button>
                <button onClick={() => setStep(AppStep.Upload)} className="flex-1 bg-slate-100 text-slate-600 font-bold py-4 rounded-xl hover:bg-slate-200 transition">Cancel</button>
             </div>
          </div>
        );

      case AppStep.Finalized:
        return (
          <div className="max-w-xl mx-auto py-20 px-4 text-center">
            <div className="w-24 h-24 bg-green-500 rounded-full flex items-center justify-center mx-auto mb-8 shadow-xl shadow-green-200"><i className="fa-solid fa-check text-white text-5xl"></i></div>
            <h2 className="text-4xl font-black text-slate-900 mb-4">Signed & Archived</h2>
            <p className="text-slate-500 text-lg mb-10 leading-relaxed">Document securely encrypted and saved to your personal vault.</p>
            {signature && (
               <div className="mb-8 p-4 bg-slate-50 rounded-xl border border-slate-200">
                 <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2">Authenticated Signature Preview</p>
                 <img src={signature} alt="Signature" className="mx-auto h-20 object-contain opacity-70" />
               </div>
            )}
            <div className="flex flex-col gap-4">
              <button onClick={() => setStep(AppStep.Vault)} className="bg-slate-900 text-white font-bold py-4 rounded-xl hover:bg-slate-800 transition flex items-center justify-center gap-2"><i className="fa-solid fa-vault"></i>Go to Vault</button>
              <button onClick={() => setStep(AppStep.Upload)} className="bg-white border-2 border-slate-200 text-slate-700 font-bold py-4 rounded-xl hover:border-indigo-400 hover:text-indigo-600 transition">Start New Document</button>
            </div>
          </div>
        );
    }
  };

  return (
    <Layout onNavigate={handleNavigate}>
      <div className="relative">{renderContent()}</div>
      <div className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-sm border-t border-slate-200 p-3 z-[60] text-center shadow-lg md:block hidden">
        <p className="text-[10px] text-slate-500 font-medium max-w-4xl mx-auto uppercase tracking-tighter">SignWise AI v3.5 - High-fidelity legal analysis. Vault sync active ({vault.length} docs).</p>
      </div>
    </Layout>
  );
};

export default App;

