const Dashboard: React.FC<DashboardProps> = ({ analysis, onConfirm, onRestart }) => {
  const [isGeneratingEmail, setIsGeneratingEmail] = useState(false);
  const [isGeneratingVoice, setIsGeneratingVoice] = useState(false);
