  const [editableEmail, setEditableEmail] = useState<string>('');
  const [verificationInput, setVerificationInput] = useState('');
  const [isVerified, setIsVerified] = useState(false);

  // Chat Assistant State
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [chatInput, setChatInput] = useState('');
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [isChatLoading, setIsChatLoading] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (chatEndRef.current) {
      chatEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [chatHistory, isChatOpen]);

  const handleNegotiate = async () => {
    setIsGeneratingEmail(true);
    try {
      const email = await generateNegotiationEmail(analysis);
      setNegotiationEmail(email);
      setEditableEmail(email);
    } catch (e) {
      alert("Failed to generate draft.");
    } finally {
      setIsGeneratingEmail(false);
    }
  };

  const handleListen = async () => {
    setIsGeneratingVoice(true);
    try {
      const base64 = await generateVoiceSummary(analysis.summary);
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const bytes = decodeBase64(base64);
      const buffer = await decodeAudioData(bytes, audioCtx);
      const source = audioCtx.createBufferSource();
      source.buffer = buffer;
      source.connect(audioCtx.destination);
      source.start();
    } catch (e) {
      console.error(e);
      alert("Voice playback failed.");
    } finally {
      setIsGeneratingVoice(false);
    }
  };

  const handleCompare = async () => {
    setIsComparing(true);
    try {
      const text = await compareWithStandards(analysis);
      setComparisonText(text);
    } catch (e) {
      alert("Comparison failed.");
    } finally {
      setIsComparing(false);
    }
  };

  const handleSendChatMessage = async () => {
    if (!chatInput.trim()) return;
    const userMsg: ChatMessage = { role: 'user', text: chatInput };
    setChatHistory(prev => [...prev, userMsg]);
    setChatInput('');
    setIsChatLoading(true);

    try {
      const response = await chatWithBodyguard(chatInput, analysis, chatHistory);
      setChatHistory(prev => [...prev, { role: 'model', text: response }]);
    } catch (e) {
      setChatHistory(prev => [...prev, { role: 'model', text: "Error connecting to your bodyguard." }]);
    } finally {
      setIsChatLoading(false);
    }
