import { GoogleGenAI, Type, Modality, GenerateContentResponse } from "@google/genai";
import { ContractAnalysis, ClassificationResult, ContractHistoryItem, ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const classifyUpload = async (
  base64Data: string,
  mimeType: string
): Promise<ClassificationResult> => {
  const model = "gemini-3-flash-preview";
  const prompt = `
    Analyze this file carefully. It could be an image, PDF, audio recording, video, or text file.
    Determine the user's intent:
    1. REVIEW: The user is providing an ALREADY EXISTING legal document/contract and wants you to analyze, explain, or check it for risks.
    2. CREATE: The user is providing instructions, a verbal brief, notes, or raw data (even if it looks like a rough draft) with the intent of HAVING A NEW professional contract drafted.

    Return JSON:
    {
      "intent": "REVIEW" | "CREATE",
      "reasoning": "Brief explanation of why you chose this intent",
      "suggestedFileName": "A meaningful filename based on the content (e.g., 'Freelance_Agreement_Draft.pdf')"
    }
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: prompt }
      ]
    },
    config: { responseMimeType: "application/json" }
  });

  return JSON.parse(response.text || '{"intent": "REVIEW"}');
};

export const generateContractContent = async (
  base64Data: string,
  mimeType: string
): Promise<string> => {
  const model = "gemini-3-pro-preview";
  const prompt = `
    Act as a professional legal drafter and strategist. 
    Based on the provided input (which could be a video brief, audio recording, rough notes, or an image of a handwritten agreement), 
    generate a comprehensive, professional, and legally-binding contract. 

    REQUIREMENTS:
    - Use clear, modern language (signer-first approach).
    - Ensure all standard protections (liability, termination, confidentiality) are included.
    - If the input is a recording, listen carefully for specific terms mentioned (rates, dates, names).

    Return only the contract text in clean Markdown format.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: prompt }
      ]
    },
    config: { thinkingConfig: { thinkingBudget: 8000 } }
  });

  return response.text || "";
};

export const analyzeContract = async (
  base64Data: string,
  mimeType: string,
  history: ContractHistoryItem[] = []
): Promise<ContractAnalysis> => {
  const model = "gemini-3-pro-preview";

  const historyText = history.length > 0 
    ? `CONTEXT: The user has previously signed these documents: ${history.map(h => `${h.name} (${h.type}): ${h.summary}`).join('; ')}. Check the current document for any legal or logical conflicts with these past terms.`
    : '';

  const prompt = `
    Act as a high-powered consumer protection attorney (The Signer's Bodyguard). 
    Analyze the provided input (PDF, Image, Video of a document, or Audio of terms).

    If the input is a video or image of a physical document, perform OCR/Visual analysis to extract all terms.
    If the input is audio/video of someone reading a contract, listen for the binding terms.

    REQUIRED JSON SCHEMA:
    {
      "summary": "3-sentence TL;DR of what the signer is agreeing to.",
      "signerScore": 85,
      "keyTerms": [
        {"title": "string", "value": "string", "category": "Financial|Termination|Privacy|Liability|Duration"}
      ],
      "redFlags": [
        {
          "issue": "Description of the risk",
          "riskLevel": "High|Medium|Low",
          "suggestion": {
            "whyItMatters": "How this harms the signer",
            "strategy": "Professional negotiation strategy",
            "counterOffer": "Specific alternative clause",
            "renegotiationKeywords": ["Keywords to use"],
            "tacticalTips": ["Specific actions to take"]
          },
          "originalText": "The relevant excerpt found in the document"
        }
      ],
      "financials": {
        "amount": "Primary cost",
        "frequency": "Frequency",
        "totalCommitment": "Total dollar value",
        "hiddenFees": ["List potential extra costs"]
      },
      "industryComparison": [
        {"metric": "Fee/Term", "assessment": "comparison assessment", "isStandard": false}
      ],
      "verificationQuestion": "Critical question for user confirmation",
      "expectedResponse": "Expected confirmation based on doc",
      "conflictCheck": {
        "hasConflict": boolean,
        "conflictDetails": "Details of any conflicts"
      },
      "fullText": "Full extracted plain text of the document/recording for reference"
    }
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 8000 }
    }
  });

  try {
    return JSON.parse(response.text || '{}');
  } catch (e) {
    throw new Error("Analysis failed. Content might be too complex or unclear.");
  }
};

export const chatWithBodyguard = async (
  message: string,
  analysis: ContractAnalysis,
  history: ChatMessage[]
): Promise<string> => {
  const model = "gemini-3-flash-preview";
  const chat = ai.chats.create({
    model,
    config: {
      systemInstruction: `You are the SignWise Bodyguard, a protective legal assistant for the signer. 
      Base your answers on this contract analysis: ${JSON.stringify(analysis)}. 
      Be brief, protective, and conversational. Use "I" and "you". 
      Always prioritize the user's safety and rights. Mention specific clauses if needed.`
    }
  });

  const historyParts = history.map(h => ({
    role: h.role,
    parts: [{ text: h.text }]
  }));

  const response = await chat.sendMessage({
    message: message
  });

  return response.text || "I'm sorry, I couldn't process that request.";
};

