    model,
    contents: [{ parts: [{ text: `Say in a friendly, helpful lawyer voice: ${text}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("Voice generation failed.");
  return base64Audio;
};

export const generateNegotiationEmail = async (analysis: ContractAnalysis): Promise<string> => {
  const model = "gemini-3-flash-preview";
  const redFlagsText = analysis.redFlags.map(rf => `- ${rf.issue} (Ref: "${rf.originalText}")`).join('\n');

  const prompt = `
    Write a professional, collaborative negotiation email for the signer to send.
    Focus on these red flags:
    ${redFlagsText}
    Request fair modifications while maintaining a positive relationship.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
  });

  return response.text || "";
};

export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import React, { useRef, useState } from 'react';

interface UploadAreaProps {
  onUpload: (base64: string, mimeType: string) => void;
}

const UploadArea: React.FC<UploadAreaProps> = ({ onUpload }) => {
  const [isDragging, setIsDragging] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [recordingType, setRecordingType] = useState<'audio' | 'video' | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  const handleFile = (file: File) => {
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      const base64 = (e.target?.result as string).split(',')[1];
      onUpload(base64, file.type);
    };
    reader.readAsDataURL(file);
  };

  const startRecording = async (type: 'audio' | 'video') => {
    try {
      const constraints: MediaStreamConstraints = { 
        audio: true, 
        video: type === 'video' ? { facingMode: 'user' } : false 
      };
      const stream = await navigator.mediaDevices.getUserMedia(constraints);
      setRecordingType(type);
      setIsRecording(true);
      chunksRef.current = [];

      const recorder = new MediaRecorder(stream);
      mediaRecorderRef.current = recorder;

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      recorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: recorder.mimeType });
        const reader = new FileReader();
        reader.onloadend = () => {
          const base64 = (reader.result as string).split(',')[1];
          onUpload(base64, recorder.mimeType);
        };
        reader.readAsDataURL(blob);
        stream.getTracks().forEach(track => track.stop());
      };

      recorder.start();
    } catch (err) {
      alert("Permission denied or device not found. Please enable microphone/camera access.");
      console.error(err);
    }
  };

  const stopRecording = () => {
    mediaRecorderRef.current?.stop();
    setIsRecording(false);
    setRecordingType(null);
  };

  return (
    <div 
      className={`relative border-2 border-dashed rounded-3xl p-12 transition-all cursor-pointer bg-white group shadow-sm ${
        isDragging ? 'border-indigo-500 bg-indigo-50 scale-[1.01]' : 'border-slate-200 hover:border-indigo-300'
      }`}
      onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
      onDragLeave={() => setIsDragging(false)}
      onDrop={(e) => {
        e.preventDefault();
        setIsDragging(false);
        const file = e.dataTransfer.files[0];
        if (file) handleFile(file);
      }}
      onClick={() => !isRecording && fileInputRef.current?.click()}
    >
      <input 
        type="file" 
        className="hidden" 
        ref={fileInputRef} 
        onChange={(e) => e.target.files?.[0] && handleFile(e.target.files[0])}
        accept="*"
      />

      {isRecording ? (
        <div className="text-center py-10 animate-in zoom-in-95">
          <div className="relative w-28 h-28 mx-auto mb-8">
            <div className="absolute inset-0 bg-red-500/10 rounded-full animate-ping"></div>
            <div className="relative w-full h-full bg-red-100 rounded-full flex items-center justify-center border-4 border-white shadow-lg">
              <i className={`fa-solid ${recordingType === 'video' ? 'fa-video' : 'fa-microphone'} text-red-600 text-4xl`}></i>
            </div>
          </div>
          <h3 className="text-3xl font-black text-slate-900 mb-2 uppercase tracking-tight">Listening to your {recordingType}...</h3>
          <p className="text-slate-500 mb-10 max-w-md mx-auto font-medium">Talk naturally about your deal. We'll extract the terms and draft the protection you need.</p>
          <button 
            onClick={(e) => { e.stopPropagation(); stopRecording(); }}
            className="bg-slate-900 text-white px-12 py-5 rounded-2xl font-black hover:bg-slate-800 transition shadow-2xl hover:scale-105 active:scale-95"
          >
            Process & Protect
          </button>
        </div>
      ) : (
        <div className="text-center py-6">
          <div className="flex justify-center -space-x-3 mb-10">
            <div className="w-14 h-14 bg-indigo-100 rounded-2xl flex items-center justify-center border-4 border-white shadow-xl text-indigo-600 transform -rotate-6">
              <i className="fa-solid fa-file-invoice text-xl"></i>
            </div>
            <div className="w-16 h-16 bg-emerald-600 rounded-2xl flex items-center justify-center border-4 border-white shadow-2xl text-white z-10 scale-110">
              <i className="fa-solid fa-fingerprint text-3xl"></i>
            </div>
            <div className="w-14 h-14 bg-amber-100 rounded-2xl flex items-center justify-center border-4 border-white shadow-xl text-amber-600 transform rotate-6">
              <i className="fa-solid fa-file-shield text-xl"></i>
            </div>
          </div>

          <h3 className="text-3xl font-black text-slate-900 mb-3 tracking-tight">The Universal Intake</h3>
          <p className="text-slate-500 mb-12 max-w-sm mx-auto font-medium leading-relaxed">
            Upload <b>PDFs, Images, Videos, Audio, or Notes</b>. Our AI will automatically determine if you need an analysis or a new draft.
          </p>

          <div className="flex flex-col sm:flex-row items-center justify-center gap-5">
            <button className="bg-slate-900 text-white px-10 py-4 rounded-2xl font-black hover:bg-slate-800 transition shadow-xl shadow-slate-200 w-full sm:w-auto">
              Select Document
            </button>
            <div className="flex items-center gap-2">
              <div className="h-px w-6 bg-slate-200"></div>
              <span className="text-slate-400 font-black text-[10px] uppercase tracking-widest">OR USE AI MODALITY</span>
              <div className="h-px w-6 bg-slate-200"></div>
            </div>
            <div className="flex gap-3">
              <button 
                type="button"
                className="flex items-center gap-3 text-slate-700 font-black hover:text-indigo-600 transition bg-slate-50 px-6 py-4 rounded-2xl border border-slate-200 hover:border-indigo-200 hover:shadow-md"
                onClick={(e) => { e.stopPropagation(); startRecording('audio'); }}
              >
                <i className="fa-solid fa-microphone text-indigo-500"></i>
                Voice
              </button>
              <button 
                type="button"
                className="flex items-center gap-3 text-slate-700 font-black hover:text-indigo-600 transition bg-slate-50 px-6 py-4 rounded-2xl border border-slate-200 hover:border-indigo-200 hover:shadow-md"
                onClick={(e) => { e.stopPropagation(); startRecording('video'); }}
              >
                <i className="fa-solid fa-video text-amber-500"></i>
                Video
              </button>
            </div>
          </div>
        </div>
      )}

      {!isRecording && (
        <div className="mt-12 flex justify-center items-center gap-8 text-[10px] text-slate-400 font-black uppercase tracking-[0.2em]">
          <span className="flex items-center gap-2"><i className="fa-solid fa-bolt text-indigo-500"></i> Instant Intelligence</span>
          <span className="flex items-center gap-2"><i className="fa-solid fa-lock text-emerald-500"></i> Zero-Knowledge Encryption</span>
          <span className="flex items-center gap-2"><i className="fa-solid fa-globe text-slate-300"></i> 100+ File Formats</span>
        </div>
      )}
