import React, { useState, useRef, useEffect } from 'react';
import { ContractAnalysis, ChatMessage } from '../types';
import RedFlagCard from './RedFlagCard';
import { 
  generateNegotiationEmail, 
  generateVoiceSummary, 
  decodeBase64, 
  decodeAudioData, 
  compareWithStandards,
  chatWithBodyguard
} from '../services/geminiService';

interface DashboardProps {
  analysis: ContractAnalysis;
  onConfirm: () => void;
  onRestart: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ analysis, onConfirm, onRestart }) => {
  const [isGeneratingEmail, setIsGeneratingEmail] = useState(false);
  const [isGeneratingVoice, setIsGeneratingVoice] = useState(false);
  const [isComparing, setIsComparing] = useState(false);
  const [comparisonText, setComparisonText] = useState<string | null>(null);
  const [negotiationEmail, setNegotiationEmail] = useState<string | null>(null);
  const [editableEmail, setEditableEmail] = useState<string>('');
  const [verificationInput, setVerificationInput] = useState('');
  const [isVerified, setIsVerified] = useState(false);

  // Chat Assistant State
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [chatInput, setChatInput] = useState('');
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [isChatLoading, setIsChatLoading] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const textAreaRef = useRef<HTMLTextAreaElement>(null);

  useEffect(() => {
    if (chatEndRef.current) {
      chatEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [chatHistory, isChatOpen]);

  const handleNegotiate = async () => {
    setIsGeneratingEmail(true);
    try {
      const email = await generateNegotiationEmail(analysis);
      setNegotiationEmail(email);
      setEditableEmail(email);
    } catch (e) {
      alert("Failed to generate draft.");
    } finally {
      setIsGeneratingEmail(false);
    }
  };

  const applyFormatting = (prefix: string, suffix: string = '') => {
    const el = textAreaRef.current;
    if (!el) return;
    const start = el.selectionStart;
    const end = el.selectionEnd;
    const text = el.value;
    const before = text.substring(0, start);
    const selection = text.substring(start, end);
    const after = text.substring(end);

    const newText = `${before}${prefix}${selection}${suffix}${after}`;
    setEditableEmail(newText);

    // Restore focus and selection
    setTimeout(() => {
      el.focus();
      el.setSelectionRange(start + prefix.length, end + prefix.length);
    }, 0);
  };

  const handleListen = async () => {
    setIsGeneratingVoice(true);
    try {
      const base64 = await generateVoiceSummary(analysis.summary);
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const bytes = decodeBase64(base64);
      const buffer = await decodeAudioData(bytes, audioCtx);
      const source = audioCtx.createBufferSource();
      source.buffer = buffer;
      source.connect(audioCtx.destination);
      source.start();
    } catch (e) {
      console.error(e);
      alert("Voice playback failed.");
    } finally {
      setIsGeneratingVoice(false);
    }
  };

  const handleCompare = async () => {
    setIsComparing(true);
    try {
      const text = await compareWithStandards(analysis);
      setComparisonText(text);
    } catch (e) {
      alert("Comparison failed.");
    } finally {
      setIsComparing(false);
    }
  };

  const handleSendChatMessage = async () => {
    if (!chatInput.trim()) return;
    const userMsg: ChatMessage = { role: 'user', text: chatInput };
    setChatHistory(prev => [...prev, userMsg]);
    setChatInput('');
    setIsChatLoading(true);

    try {
      const response = await chatWithBodyguard(chatInput, analysis, chatHistory);
      setChatHistory(prev => [...prev, { role: 'model', text: response }]);
    } catch (e) {
      setChatHistory(prev => [...prev, { role: 'model', text: "Error connecting to your bodyguard." }]);
    } finally {
      setIsChatLoading(false);
    }
  };

  const checkVerification = () => {
    if (verificationInput.toLowerCase().includes(analysis.expectedResponse.toLowerCase()) || verificationInput.length > 5) {
      setIsVerified(true);
    } else {
      alert("Please confirm the terms correctly based on the summary.");
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 relative">
      <div className="flex flex-col lg:flex-row gap-8">

        {/* Main Analysis Column */}
        <div className="flex-1 space-y-8">

          {/* Top Score & Summary Section */}
          <section className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100">
            <div className="flex flex-col md:flex-row items-center gap-8 mb-8">
              {/* Signer Score Widget */}
              <div className="relative w-40 h-40 flex-shrink-0">
                <svg className="w-full h-full" viewBox="0 0 100 100">
                  <circle className="text-slate-100 stroke-current" strokeWidth="10" fill="transparent" r="40" cx="50" cy="50" />
                  <circle 
                    className={`${analysis.signerScore > 70 ? 'text-green-500' : analysis.signerScore > 40 ? 'text-amber-500' : 'text-red-500'} stroke-current`}
                    strokeWidth="10" 
                    strokeDasharray={`${analysis.signerScore * 2.51} 251`}
                    strokeLinecap="round" 
                    fill="transparent" 
                    r="40" cx="50" cy="50"
                  />
                </svg>
                <div className="absolute inset-0 flex flex-col items-center justify-center">
                  <span className="text-3xl font-black text-slate-900">{analysis.signerScore}</span>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Signer Score</span>
                </div>
              </div>

              <div className="flex-1">
                <div className="flex items-center justify-between mb-4">
                  <h2 className="text-3xl font-black text-slate-900">Analysis Dashboard</h2>
                  <button 
                    onClick={handleListen}
                    disabled={isGeneratingVoice}
                    className="flex items-center gap-2 text-indigo-600 font-bold hover:bg-indigo-50 px-4 py-2 rounded-lg transition"
                  >
                    <i className={`fa-solid ${isGeneratingVoice ? 'fa-spinner fa-spin' : 'fa-volume-high'}`}></i>
                    {isGeneratingVoice ? 'Summarizing...' : 'Voice Brief'}
                  </button>
                </div>
                <div className="bg-slate-50 rounded-2xl p-5 border border-slate-100">
                  <p className="text-slate-700 leading-relaxed italic text-lg font-serif">
                    "{analysis.summary}"
                  </p>
                </div>
              </div>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-3">
              {analysis.keyTerms.map((term, i) => (
                <div key={i} className="p-3 bg-slate-50 rounded-xl border border-slate-100 text-center">
                  <div className="w-8 h-8 bg-white rounded-lg flex items-center justify-center border border-slate-200 shadow-sm mx-auto mb-2 text-indigo-500">
                    <i className={`fa-solid ${
                      term.category === 'Financial' ? 'fa-money-bill-wave' :
                      term.category === 'Termination' ? 'fa-door-open' :
                      term.category === 'Privacy' ? 'fa-user-lock' :
                      term.category === 'Duration' ? 'fa-calendar-days' : 'fa-handshake'
                    }`}></i>
                  </div>
                  <h4 className="text-[10px] font-bold text-slate-400 uppercase tracking-wider truncate">{term.title}</h4>
                  <p className="text-slate-800 font-bold text-xs truncate">{term.value}</p>
                </div>
              ))}
            </div>
          </section>

          {/* Red Flags Section */}
          <section className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100">
            <h3 className="text-2xl font-black text-slate-900 mb-6 flex items-center gap-3">
              <span className="text-red-500 bg-red-50 w-10 h-10 rounded-full flex items-center justify-center"><i className="fa-solid fa-bolt-lightning"></i></span>
              Predatory Clauses Detected
            </h3>
            {analysis.redFlags.length > 0 ? (
              analysis.redFlags.map((flag, i) => (
                <RedFlagCard key={i} {...flag} />
              ))
            ) : (
              <div className="text-center py-12 text-slate-400">
                <i className="fa-regular fa-circle-check text-5xl mb-4 block text-green-400"></i>
                <p className="font-bold text-lg text-slate-600">This contract is SignWise Certified.</p>
                <p className="text-sm">No standard predatory language was found in this version.</p>
              </div>
            )}

            <div className="mt-10 flex flex-col sm:flex-row gap-4">
               <button 
                onClick={handleNegotiate}
                disabled={isGeneratingEmail}
                className="flex-1 bg-white border-2 border-slate-900 text-slate-900 font-black py-4 rounded-2xl hover:bg-slate-50 transition flex items-center justify-center gap-3"
               >
                 <i className={`fa-solid ${isGeneratingEmail ? 'fa-spinner fa-spin' : 'fa-feather-pointed'}`}></i>
                 {negotiationEmail ? 'Regenerate Counter-Offer' : 'Negotiation Draft'}
               </button>
               <button 
                onClick={handleCompare}
                disabled={isComparing}
                className="flex-1 bg-indigo-600 text-white font-black py-4 rounded-2xl hover:bg-indigo-700 transition flex items-center justify-center gap-3 shadow-xl shadow-indigo-100"
               >
                 <i className={`fa-solid ${isComparing ? 'fa-spinner fa-spin' : 'fa-microscope'}`}></i>
                 Industry Benchmark
               </button>
            </div>

            {comparisonText && (
               <div className="mt-6 p-8 bg-indigo-50 border border-indigo-100 rounded-3xl animate-in fade-in slide-in-from-top-4">
                  <div className="flex justify-between items-start mb-6">
                    <h4 className="font-black text-slate-900 text-xl flex items-center gap-2">
                      <i className="fa-solid fa-scale-balanced text-indigo-600"></i>
                      Market Benchmarking Report
                    </h4>
                    <button onClick={() => setComparisonText(null)} className="text-indigo-400 hover:text-indigo-600"><i className="fa-solid fa-circle-xmark text-xl"></i></button>
                  </div>
                  <div className="prose prose-indigo max-w-none text-slate-700 whitespace-pre-wrap leading-relaxed">
                    {comparisonText}
                  </div>
               </div>
