            {negotiationEmail && (
              <div className="mt-8 bg-slate-900 rounded-3xl overflow-hidden border border-slate-800 animate-in fade-in slide-in-from-top-4 shadow-2xl">
                <div className="flex items-center justify-between px-8 py-4 bg-slate-800 border-b border-slate-700">
