  const historyText = history.length > 0 
    ? `CONTEXT: The user has previously signed these documents: ${history.map(h => `${h.name} (${h.type}): ${h.summary}`).join('; ')}.`
    : '';

  const prefText = `USER PREFERENCES: 
    - Strict Mode: ${preferences.strictMode ? 'High sensitivity to risks' : 'Standard sensitivity'}.
    - Focus Areas: ${preferences.focusAreas.join(', ')}.
    - Preferred Language for analysis: ${preferences.languagePreference}.`;

  const prompt = `
    Act as a high-powered consumer protection attorney (The Signer's Bodyguard). 
    Analyze the provided input (PDF, Image, Video of a document, or Audio of terms).

    ${historyText}
    ${prefText}

    REQUIRED JSON SCHEMA:
    {
      "summary": "3-sentence TL;DR of what the signer is agreeing to.",
      "signerScore": 85,
      "keywords": ["List 5-10 legal keywords found like 'Indemnity', 'Arbitration', 'Auto-renewal'"],
      "keyTerms": [
        {"title": "string", "value": "string", "category": "Financial|Termination|Privacy|Liability|Duration"}
      ],
      "redFlags": [
        {
          "id": "unique-id-1",
          "issue": "Description of the risk",
          "riskLevel": "High|Medium|Low",
          "suggestion": {
            "whyItMatters": "How this harms the signer",
            "strategy": "Professional negotiation strategy",
            "counterOffer": "Specific alternative clause",
            "renegotiationKeywords": ["Keywords to use"],
            "tacticalTips": ["Specific actions to take"]
          },
          "originalText": "The relevant excerpt found in the document"
        }
      ],
      "financials": {
        "amount": "Primary cost",
        "frequency": "Frequency",
        "totalCommitment": "Total dollar value",
        "hiddenFees": ["List potential extra costs"]
      },
      "industryComparison": [
        {"metric": "Fee/Term", "assessment": "comparison assessment", "isStandard": false}
      ],
      "verificationQuestion": "Critical question for user confirmation",
      "expectedResponse": "Expected confirmation based on doc",
      "conflictCheck": {
        "hasConflict": boolean,
        "conflictDetails": "Details of any conflicts"
      },
      "fullText": "Full extracted plain text of the document/recording for reference",
      "detectedLanguage": "string"
    }
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 8000 }
    }
  });

  try {
    return JSON.parse(response.text || '{}');
  } catch (e) {
    throw new Error("Analysis failed. Content might be too complex or unclear.");
  }
};

