                  <h4 className="text-[10px] font-bold text-slate-400 uppercase tracking-wider truncate">{term.title}</h4>
                  <p className="text-slate-800 font-bold text-xs truncate">{term.value}</p>
                </div>
              ))}
            </div>
          </section>

          {/* View Toggles */}
          <div className="flex items-center gap-4 bg-white p-2 rounded-2xl border border-slate-100 shadow-sm w-fit mx-auto">
