                  <span className="text-slate-500 text-[9px] font-bold">Drafting Counter-Offer</span>
                </div>
                <div className="flex gap-4">
                  <button 
                    onClick={() => { navigator.clipboard.writeText(editableEmail); alert("Copied!"); }} 
                    className="text-emerald-400 hover:text-emerald-300 text-xs font-bold transition flex items-center gap-2"
                  >
                    <i className="fa-solid fa-copy"></i> Copy
                  </button>
                  <button 
                    onClick={() => alert("Simulation: Dispatched.")} 
                    className="text-indigo-400 hover:text-indigo-300 text-xs font-bold transition flex items-center gap-2"
                  >
                    <i className="fa-solid fa-paper-plane"></i> Send
                  </button>
                </div>
              </div>

              <div className="bg-slate-800/50 border-b border-slate-700 px-6 py-2 flex items-center gap-4">
                <button onClick={() => applyFormatting('**', '**')} className="text-slate-400 hover:text-white transition p-1"><i className="fa-solid fa-bold"></i></button>
                <button onClick={() => applyFormatting('*', '*')} className="text-slate-400 hover:text-white transition p-1"><i className="fa-solid fa-italic"></i></button>
