            className="w-16 h-16 bg-indigo-600 text-white rounded-full flex items-center justify-center shadow-2xl hover:bg-indigo-700 transition transform hover:scale-110 active:scale-95 animate-bounce-short"
          >
            <i className="fa-solid fa-user-ninja text-2xl"></i>
            <span className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 border-2 border-white rounded-full flex items-center justify-center text-[10px] font-black">1</span>
          </button>
        )}
      </div>
    </div>
  );
};

