import React, { useRef, useState } from 'react';
import { UserPreferences } from '../types';

interface UploadAreaProps {
  onUpload: (base64: string, mimeType: string, preferences: UserPreferences) => void;
}

const UploadArea: React.FC<UploadAreaProps> = ({ onUpload }) => {
  const [isDragging, setIsDragging] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [recordingType, setRecordingType] = useState<'audio' | 'video' | null>(null);
  const [preferences, setPreferences] = useState<UserPreferences>({
    strictMode: false,
    focusAreas: ['Liability', 'Financial'],
    languagePreference: 'English'
  });
  const [showPrefs, setShowPrefs] = useState(false);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  const handleFile = (file: File) => {
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      const base64 = (e.target?.result as string).split(',')[1];
      if (file.type.startsWith('image/')) {
        setPreviewUrl(URL.createObjectURL(file));
      }
      onUpload(base64, file.type, preferences);
    };
    reader.readAsDataURL(file);
  };

  const startRecording = async (type: 'audio' | 'video') => {
    try {
      const constraints: MediaStreamConstraints = { 
        audio: true, 
        video: type === 'video' ? { facingMode: 'user' } : false 
      };
      const stream = await navigator.mediaDevices.getUserMedia(constraints);
      setRecordingType(type);
      setIsRecording(true);
      chunksRef.current = [];

      const recorder = new MediaRecorder(stream);
      mediaRecorderRef.current = recorder;

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      recorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: recorder.mimeType });
        const reader = new FileReader();
        reader.onloadend = () => {
          const base64 = (reader.result as string).split(',')[1];
          onUpload(base64, recorder.mimeType, preferences);
        };
        reader.readAsDataURL(blob);
        stream.getTracks().forEach(track => track.stop());
      };

      recorder.start();
    } catch (err) {
      alert("Permission denied or device not found.");
      console.error(err);
    }
  };

  const stopRecording = () => {
    mediaRecorderRef.current?.stop();
    setIsRecording(false);
    setRecordingType(null);
  };

  const toggleFocusArea = (area: string) => {
    setPreferences(prev => ({
      ...prev,
      focusAreas: prev.focusAreas.includes(area) 
        ? prev.focusAreas.filter(a => a !== area)
        : [...prev.focusAreas, area]
    }));
  };

  return (
    <div className="space-y-6">
      {/* Risk Settings Hub */}
      <div className="max-w-xl mx-auto">
        <button 
          onClick={() => setShowPrefs(!showPrefs)}
          className="flex items-center justify-between w-full bg-white px-6 py-4 rounded-2xl border border-slate-200 shadow-sm hover:border-indigo-300 transition group"
        >
          <div className="flex items-center gap-3">
            <i className={`fa-solid fa-sliders text-indigo-500 transition-transform ${showPrefs ? 'rotate-90' : ''}`}></i>
            <span className="text-sm font-black text-slate-700 uppercase tracking-widest">Customize Guardian Engine</span>
          </div>
          <div className="flex gap-2">
            {preferences.strictMode && <span className="text-[8px] bg-red-100 text-red-600 px-2 py-0.5 rounded-full font-black uppercase">Strict Mode</span>}
            <span className="text-[8px] bg-indigo-50 text-indigo-600 px-2 py-0.5 rounded-full font-black uppercase">{preferences.languagePreference}</span>
          </div>
        </button>

        {showPrefs && (
          <div className="mt-4 bg-white p-6 rounded-3xl border border-slate-200 shadow-xl animate-in fade-in slide-in-from-top-4">
            <div className="space-y-6">
              <div>
                <div className="flex items-center justify-between mb-2">
                  <h4 className="text-xs font-black text-slate-900 uppercase">Risk Sensitivity</h4>
                  <input 
                    type="checkbox" 
                    checked={preferences.strictMode}
                    onChange={(e) => setPreferences({...preferences, strictMode: e.target.checked})}
                    className="w-5 h-5 rounded text-indigo-600 focus:ring-indigo-500"
                  />
                </div>
                <p className="text-[10px] text-slate-400 font-bold leading-relaxed">STRICT MODE: Flag even standard legal boilerplate that favors the sender.</p>
              </div>

              <div>
                <h4 className="text-xs font-black text-slate-900 uppercase mb-3">Focus Domains</h4>
                <div className="flex flex-wrap gap-2">
                  {['Financial', 'Liability', 'Privacy', 'Termination', 'Intellectual Property'].map(area => (
                    <button
                      key={area}
                      onClick={() => toggleFocusArea(area)}
                      className={`px-3 py-1.5 rounded-xl text-[10px] font-black uppercase transition ${
                        preferences.focusAreas.includes(area) 
                          ? 'bg-indigo-600 text-white shadow-lg' 
                          : 'bg-slate-50 text-slate-400 border border-slate-200'
                      }`}
                    >
                      {area}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <h4 className="text-xs font-black text-slate-900 uppercase mb-2">Output Language</h4>
                <select 
                  value={preferences.languagePreference}
                  onChange={(e) => setPreferences({...preferences, languagePreference: e.target.value})}
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none"
                >
                  <option>English</option>
                  <option>Spanish</option>
                  <option>French</option>
                  <option>German</option>
                  <option>Chinese</option>
                </select>
              </div>
            </div>
          </div>
        )}
      </div>

      <div 
        className={`relative border-2 border-dashed rounded-[2.5rem] p-12 transition-all cursor-pointer bg-white group shadow-sm ${
          isDragging ? 'border-indigo-500 bg-indigo-50 scale-[1.01]' : 'border-slate-200 hover:border-indigo-300'
        }`}
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={(e) => {
          e.preventDefault();
          setIsDragging(false);
          const file = e.dataTransfer.files[0];
          if (file) handleFile(file);
        }}
        onClick={() => !isRecording && fileInputRef.current?.click()}
      >
        <input 
          type="file" 
          className="hidden" 
          ref={fileInputRef} 
          onChange={(e) => e.target.files?.[0] && handleFile(e.target.files[0])}
          accept="*"
        />

        {isRecording ? (
          <div className="text-center py-10 animate-in zoom-in-95">
            <div className="relative w-28 h-28 mx-auto mb-8">
              <div className="absolute inset-0 bg-red-500/10 rounded-full animate-ping"></div>
              <div className="relative w-full h-full bg-red-100 rounded-full flex items-center justify-center border-4 border-white shadow-lg">
                <i className={`fa-solid ${recordingType === 'video' ? 'fa-video' : 'fa-microphone'} text-red-600 text-4xl`}></i>
              </div>
            </div>
            <h3 className="text-3xl font-black text-slate-900 mb-2 uppercase tracking-tight">Listening to your {recordingType}...</h3>
            <p className="text-slate-500 mb-10 max-w-md mx-auto font-medium">Recording terms for analysis...</p>
            <button 
              onClick={(e) => { e.stopPropagation(); stopRecording(); }}
              className="bg-slate-900 text-white px-12 py-5 rounded-2xl font-black hover:bg-slate-800 transition shadow-2xl"
            >
              Stop & Process
            </button>
          </div>
        ) : (
          <div className="text-center py-6">
            {previewUrl ? (
              <div className="mb-10 animate-in zoom-in-50 duration-500">
                <div className="relative w-32 h-44 mx-auto rounded-xl border-4 border-white shadow-2xl overflow-hidden group/preview">
                  <img src={previewUrl} className="w-full h-full object-cover" alt="OCR Preview" />
                  <div className="absolute inset-0 bg-indigo-600/60 flex items-center justify-center opacity-0 group-hover/preview:opacity-100 transition-opacity">
                    <span className="text-white text-[10px] font-black uppercase tracking-widest">Change File</span>
                  </div>
                </div>
                <p className="mt-4 text-emerald-600 font-black text-[10px] uppercase tracking-widest">Visual Data Captured • OCR Ready</p>
              </div>
            ) : (
              <div className="flex justify-center -space-x-3 mb-10">
                <div className="w-14 h-14 bg-indigo-100 rounded-2xl flex items-center justify-center border-4 border-white shadow-xl text-indigo-600 transform -rotate-6">
                  <i className="fa-solid fa-file-invoice text-xl"></i>
                </div>
                <div className="w-16 h-16 bg-emerald-600 rounded-2xl flex items-center justify-center border-4 border-white shadow-2xl text-white z-10 scale-110">
                  <i className="fa-solid fa-fingerprint text-3xl"></i>
                </div>
                <div className="w-14 h-14 bg-amber-100 rounded-2xl flex items-center justify-center border-4 border-white shadow-xl text-amber-600 transform rotate-6">
                  <i className="fa-solid fa-file-shield text-xl"></i>
                </div>
              </div>
            )}

            <h3 className="text-3xl font-black text-slate-900 mb-3 tracking-tight">The Universal Intake</h3>
            <p className="text-slate-500 mb-12 max-w-sm mx-auto font-medium leading-relaxed">
              Upload <b>PDFs, Images, Videos, Audio, or Notes</b>. Our AI will automatically determine if you need an analysis or a new draft.
            </p>

            <div className="flex flex-col sm:flex-row items-center justify-center gap-5">
              <button className="bg-slate-900 text-white px-10 py-4 rounded-2xl font-black hover:bg-slate-800 transition shadow-xl shadow-slate-200 w-full sm:w-auto">
                Select Document
              </button>
              <div className="flex items-center gap-2">
                <div className="h-px w-6 bg-slate-200"></div>
                <span className="text-slate-400 font-black text-[10px] uppercase tracking-widest">OR AI CAPTURE</span>
                <div className="h-px w-6 bg-slate-200"></div>
              </div>
              <div className="flex gap-3">
                <button 
                  type="button"
                  className="flex items-center gap-3 text-slate-700 font-black hover:text-indigo-600 transition bg-slate-50 px-6 py-4 rounded-2xl border border-slate-200 hover:border-indigo-200"
                  onClick={(e) => { e.stopPropagation(); startRecording('audio'); }}
                >
                  <i className="fa-solid fa-microphone text-indigo-500"></i>
                  Voice
                </button>
                <button 
                  type="button"
                  className="flex items-center gap-3 text-slate-700 font-black hover:text-indigo-600 transition bg-slate-50 px-6 py-4 rounded-2xl border border-slate-200 hover:border-indigo-200"
                  onClick={(e) => { e.stopPropagation(); startRecording('video'); }}
                >
                  <i className="fa-solid fa-video text-amber-500"></i>
                  Visual
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

