import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import UploadArea from './components/UploadArea';
import Dashboard from './components/Dashboard';
import ContractCreator from './components/ContractCreator';
import SignaturePad from './components/SignaturePad';
import { analyzeContract, classifyUpload, generateContractContent } from './services/geminiService';
import { AppStep, ContractAnalysis, ContractHistoryItem, UserPreferences } from './types';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.Upload);
  const [analysis, setAnalysis] = useState<ContractAnalysis | null>(null);
  const [generatedContent, setGeneratedContent] = useState<string>('');
  const [loadingMessage, setLoadingMessage] = useState('Activating Legal Engine...');
  const [vault, setVault] = useState<ContractHistoryItem[]>([]);
  const [signature, setSignature] = useState<string | null>(null);
  const [activeIntent, setActiveIntent] = useState<'REVIEW' | 'CREATE' | null>(null);

  useEffect(() => {
    const savedVault = localStorage.getItem('signwise_vault');
    if (savedVault) setVault(JSON.parse(savedVault));
  }, []);

  const saveToVault = (item: ContractHistoryItem) => {
    const updated = [item, ...vault];
    setVault(updated);
    localStorage.setItem('signwise_vault', JSON.stringify(updated));
  };

  useEffect(() => {
    if (step === AppStep.Analyzing) {
      const messages = [
        "Analyzing intent...",
        "Scanning for hidden terms...",
        "Reading between the lines...",
        activeIntent === 'CREATE' ? "Drafting professional agreement..." : "Cross-referencing vault history...",
        "Finalizing protection strategy..."
      ];
      let i = 0;
      const interval = setInterval(() => {
        setLoadingMessage(messages[i % messages.length]);
        i++;
      }, 2500);
      return () => clearInterval(interval);
    }
  }, [step, activeIntent]);

  const handleUpload = async (base64: string, mimeType: string, preferences: UserPreferences) => {
    setStep(AppStep.Analyzing);
    try {
      const classification = await classifyUpload(base64, mimeType);
      setActiveIntent(classification.intent);

      if (classification.intent === 'REVIEW') {
        const result = await analyzeContract(base64, mimeType, vault, preferences);
        setAnalysis(result);
        setStep(AppStep.Dashboard);
      } else {
        const result = await generateContractContent(base64, mimeType);
        setGeneratedContent(result);
        setStep(AppStep.Creator);
      }
    } catch (e) {
      console.error(e);
      alert("Analysis failed. Content might be too complex or unclear.");
      setStep(AppStep.Upload);
    } finally {
      setActiveIntent(null);
    }
  };

  const finalizeSigning = () => {
    if (!signature) {
      alert("Please provide a digital signature to continue.");
      return;
    }

    const newItem: ContractHistoryItem = {
      id: Date.now().toString(),
      name: analysis?.summary.slice(0, 30) || "New Contract Agreement",
      date: new Date().toLocaleDateString(),
      type: analysis ? "Analysis & Signature" : "AI-Drafted & Signature",
      summary: analysis?.summary || generatedContent.slice(0, 100),
      analysis: analysis || undefined,
      content: generatedContent || undefined
    };
    saveToVault(newItem);
    setStep(AppStep.Finalized);
  };

  const handleNavigate = (view: 'upload' | 'vault' | 'help' | 'pricing' | 'privacy' | 'terms') => {
    switch(view) {
      case 'upload': setStep(AppStep.Upload); break;
      case 'vault': setStep(AppStep.Vault); break;
      case 'privacy': setStep(AppStep.Privacy); break;
      case 'terms': setStep(AppStep.Terms); break;
      case 'pricing': setStep(AppStep.Pricing); break;
      case 'help': setStep(AppStep.Help); break;
    }
  };

  const viewVaultItem = (item: ContractHistoryItem) => {
    if (item.analysis) {
      setAnalysis(item.analysis);
      setStep(AppStep.Dashboard);
    } else if (item.content) {
      setGeneratedContent(item.content);
      setStep(AppStep.Creator);
    }
  };

  const renderContent = () => {
    switch (step) {
      case AppStep.Upload:
        return (
          <div className="max-w-4xl mx-auto px-4 py-16">
            <div className="text-center mb-16 animate-in fade-in slide-in-from-bottom-6 duration-1000">
              <span className="inline-block px-5 py-2 bg-indigo-50 text-indigo-700 text-[10px] font-black uppercase tracking-[0.25em] rounded-full mb-6 border border-indigo-100">AI-Powered Legal Guardian</span>
              <h1 className="text-6xl md:text-7xl font-black text-slate-900 mb-8 tracking-tighter leading-[0.9]">Total Signer <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-600 to-emerald-600">Autonomy.</span></h1>
              <p className="text-xl text-slate-500 max-w-2xl mx-auto leading-relaxed">Stop clicking 'I agree' without reading. Our AI instantly translates dense contracts or drafts custom ones from your voice briefs.</p>
            </div>
            <UploadArea onUpload={handleUpload} />
          </div>
        );

      case AppStep.Analyzing:
        return (
          <div className="flex flex-col items-center justify-center min-h-[70vh] animate-in fade-in">
            <div className="relative">
              <div className="w-40 h-40 border-8 border-indigo-50 border-t-indigo-600 rounded-full animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                <div className="w-20 h-20 bg-white rounded-3xl shadow-2xl flex items-center justify-center">
                  <i className="fa-solid fa-brain text-indigo-600 text-4xl animate-pulse"></i>
                </div>
              </div>
            </div>
            <h2 className="text-3xl font-black mt-12 text-slate-900 tracking-tight">{loadingMessage}</h2>
            <p className="text-slate-400 mt-4 font-bold uppercase text-xs tracking-widest">Processing Secure Stream...</p>
          </div>
        );

      case AppStep.Dashboard:
        return <Dashboard analysis={analysis!} onRestart={() => setStep(AppStep.Upload)} onConfirm={() => setStep(AppStep.Signing)} />;

      case AppStep.Creator:
        return <ContractCreator initialContent={generatedContent} onRestart={() => setStep(AppStep.Upload)} onConfirm={() => setStep(AppStep.Signing)} />;

      case AppStep.Vault:
        return (
          <div className="max-w-5xl mx-auto px-4 py-12 animate-in fade-in duration-500">
            <div className="flex justify-between items-end mb-12">
              <div>
                <h2 className="text-5xl font-black text-slate-900 tracking-tight">Personal Vault</h2>
                <p className="text-slate-500 font-medium mt-2">Your historical protection records and signed agreements.</p>
              </div>
              <button onClick={() => setStep(AppStep.Upload)} className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black hover:bg-slate-800 transition shadow-xl">Secure New Scan</button>
            </div>
            {vault.length === 0 ? (
              <div className="bg-white rounded-[2.5rem] p-24 text-center border border-slate-100 shadow-sm ring-8 ring-slate-50">
                <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-8 border border-slate-100">
                  <i className="fa-solid fa-vault text-slate-200 text-5xl"></i>
                </div>
                <h3 className="text-2xl font-black text-slate-900 mb-2">The Vault is Offline</h3>
                <p className="text-slate-400 font-bold mb-8">No documents have been indexed yet.</p>
                <button onClick={() => setStep(AppStep.Upload)} className="text-indigo-600 font-black hover:underline uppercase tracking-widest text-xs">Analyze Your First Deal</button>
              </div>
            ) : (
              <div className="grid gap-6">
                {vault.map(item => (
                  <div key={item.id} className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm flex items-center justify-between group hover:border-indigo-200 hover:shadow-xl hover:shadow-indigo-50/50 transition-all duration-300">
                    <div className="flex items-center gap-8">
                       <div className="w-16 h-16 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-400 group-hover:text-indigo-600 group-hover:bg-indigo-50 transition-colors">
                          <i className="fa-solid fa-file-shield text-2xl"></i>
                       </div>
                       <div>
                         <h4 className="font-black text-xl text-slate-900 mb-1">{item.name}</h4>
                         <div className="flex items-center gap-3">
                            <span className="text-[10px] bg-slate-100 px-2 py-1 rounded font-black text-slate-500 uppercase tracking-widest">{item.type}</span>
                            <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Signed {item.date}</span>
                         </div>
                       </div>
                    </div>
                    <button onClick={() => viewVaultItem(item)} className="bg-slate-900 text-white px-6 py-3 rounded-xl text-sm font-black hover:bg-indigo-600 transition shadow-lg shadow-slate-100 group-hover:shadow-indigo-100">
                      Access Records
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>
        );

      case AppStep.Signing:
        return (
          <div className="max-w-2xl mx-auto py-20 px-4 text-center">
             <div className="w-24 h-24 bg-emerald-50 rounded-3xl flex items-center justify-center mx-auto mb-8 transform rotate-12 border-4 border-white shadow-2xl"><i className="fa-solid fa-file-contract text-emerald-600 text-4xl"></i></div>
             <h2 className="text-5xl font-black text-slate-900 mb-6 tracking-tight leading-tight">Authorize Document</h2>
             <p className="text-slate-500 mb-12 text-lg leading-relaxed font-medium">Your signature will be cryptographically bound to this analyzed document. This action is binding and secure.</p>
             <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl border border-slate-100 mb-10">
                <SignaturePad onSign={(data) => setSignature(data)} onClear={() => setSignature(null)} />
             </div>
             <div className="flex gap-5">
                <button onClick={finalizeSigning} className="flex-[2] bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-2xl shadow-indigo-100 hover:bg-indigo-700 transition transform hover:-translate-y-1 active:translate-y-0">Apply Signature & Close</button>
                <button onClick={() => setStep(AppStep.Upload)} className="flex-1 bg-white text-slate-400 border border-slate-200 font-black py-5 rounded-2xl hover:bg-slate-50 hover:text-slate-600 transition">Cancel</button>
             </div>
          </div>
        );

      case AppStep.Finalized:
        return (
          <div className="max-w-2xl mx-auto py-20 px-4 text-center animate-in zoom-in-95">
            <div className="w-32 h-32 bg-emerald-500 rounded-full flex items-center justify-center mx-auto mb-10 shadow-2xl shadow-emerald-200 ring-8 ring-emerald-50"><i className="fa-solid fa-shield-check text-white text-6xl"></i></div>
            <h2 className="text-5xl font-black text-slate-900 mb-6 tracking-tight">Securely Sealed.</h2>
            <p className="text-slate-500 text-xl mb-12 leading-relaxed font-medium">Agreement finalized, encrypted, and synced to your zero-knowledge vault.</p>
            {signature && (
               <div className="mb-10 p-6 bg-white rounded-3xl border border-slate-100 shadow-inner">
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-4">Digital Identity Token</p>
                 <img src={signature} alt="Signature" className="mx-auto h-24 object-contain opacity-80" />
               </div>
            )}
            <div className="flex flex-col gap-4">
              <button onClick={() => setStep(AppStep.Vault)} className="bg-slate-900 text-white font-black py-5 rounded-2xl hover:bg-slate-800 transition flex items-center justify-center gap-3 shadow-2xl"><i className="fa-solid fa-vault"></i>View in Vault</button>
              <button onClick={() => setStep(AppStep.Upload)} className="bg-white border-2 border-slate-200 text-slate-700 font-black py-5 rounded-2xl hover:border-indigo-400 hover:text-indigo-600 transition">Analyze New Deal</button>
            </div>
          </div>
        );

      default:
        return <div className="text-center py-20">View not implemented.</div>;
    }
  };

  return (
    <Layout onNavigate={handleNavigate}>
      <div className="relative overflow-hidden min-h-screen">{renderContent()}</div>
      <div className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t border-slate-200 p-4 z-[60] text-center shadow-2xl md:block hidden">
        <div className="max-w-6xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
            <p className="text-[9px] text-slate-500 font-black uppercase tracking-widest">AI Core 3.5 Active • AES-256 Vault Synced • {vault.length} Protected Docs</p>
