import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import UploadArea from './components/UploadArea';
import Dashboard from './components/Dashboard';
import ContractCreator from './components/ContractCreator';
import SignaturePad from './components/SignaturePad';
import { analyzeContract, classifyUpload, generateContractContent } from './services/geminiService';
import { AppStep, ContractAnalysis, ContractHistoryItem, UserPreferences, AuditEntry } from './types';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.Upload);
  const [analysis, setAnalysis] = useState<ContractAnalysis | null>(null);
  const [generatedContent, setGeneratedContent] = useState<string>('');
  const [loadingMessage, setLoadingMessage] = useState('Activating Legal Engine...');
  const [vault, setVault] = useState<ContractHistoryItem[]>([]);
  const [signature, setSignature] = useState<string | null>(null);
  const [activeIntent, setActiveIntent] = useState<'REVIEW' | 'CREATE' | null>(null);
  const [currentAuditTrail, setCurrentAuditTrail] = useState<AuditEntry[]>([]);

  useEffect(() => {
    const savedVault = localStorage.getItem('signwise_vault');
    if (savedVault) setVault(JSON.parse(savedVault));
  }, []);

  const addToAudit = (event: string, details: string) => {
    const entry: AuditEntry = {
      event,
      timestamp: new Date().toISOString(),
      details
    };
    setCurrentAuditTrail(prev => [...prev, entry]);
  };

  const saveToVault = (item: ContractHistoryItem) => {
    const updated = [item, ...vault];
    setVault(updated);
    localStorage.setItem('signwise_vault', JSON.stringify(updated));
  };

  useEffect(() => {
    if (step === AppStep.Analyzing) {
      const messages = [
        "Mapping legal geography...",
        "Identifying parties and roles...",
        "Extracting obligations ledger...",
        "Scanning for predatory rephrasing..."
      ];
      let i = 0;
      const interval = setInterval(() => {
        setLoadingMessage(messages[i % messages.length]);
        i++;
      }, 2500);
      return () => clearInterval(interval);
    }
  }, [step]);

  const handleUpload = async (base64: string, mimeType: string, preferences: UserPreferences) => {
    setStep(AppStep.Analyzing);
    setCurrentAuditTrail([]);
    addToAudit("Ingestion Started", `File type: ${mimeType}`);

    try {
      const classification = await classifyUpload(base64, mimeType);
      setActiveIntent(classification.intent);

      if (classification.intent === 'REVIEW') {
        addToAudit("Analysis Strategy", "Signer-First Review Triggered");
        const result = await analyzeContract(base64, mimeType, vault, preferences);
        setAnalysis(result);
        addToAudit("Scan Complete", `Score: ${result.signerScore}/100`);
        setStep(AppStep.Dashboard);
      } else {
        addToAudit("Drafting Strategy", "AI Drafing Tool Triggered");
        const result = await generateContractContent(base64, mimeType);
        setGeneratedContent(result);
        setStep(AppStep.Creator);
      }
    } catch (e) {
      console.error(e);
      alert("AI Scan timed out. Ensure your file is clear.");
      setStep(AppStep.Upload);
    }
  };

  const finalizeSigning = () => {
    if (!signature) {
      alert("Provide a signature to seal this document.");
      return;
    }

    addToAudit("Digital Consent", "Signature Applied Cryptographically");

    const newItem: ContractHistoryItem = {
      id: Date.now().toString(),
      name: analysis?.summary.slice(0, 30) || "Signed Agreement",
      date: new Date().toLocaleDateString(),
      type: analysis ? "Review & Seal" : "AI Draft & Seal",
      summary: analysis?.summary || generatedContent.slice(0, 100),
      analysis: analysis || undefined,
      content: generatedContent || undefined,
      auditTrail: [...currentAuditTrail, { event: "Vault Sealed", timestamp: new Date().toISOString(), details: "Archived for lifetime retrieval" }]
    };
    saveToVault(newItem);
    setStep(AppStep.Finalized);
  };

  const handleNavigate = (view: 'upload' | 'vault' | 'help' | 'pricing' | 'privacy' | 'terms') => {
    switch(view) {
      case 'upload': setStep(AppStep.Upload); break;
      case 'vault': setStep(AppStep.Vault); break;
      case 'privacy': setStep(AppStep.Privacy); break;
      case 'terms': setStep(AppStep.Terms); break;
      case 'pricing': setStep(AppStep.Pricing); break;
      case 'help': setStep(AppStep.Help); break;
    }
  };

  const renderContent = () => {
    switch (step) {
      case AppStep.Upload:
        return (
          <div className="max-w-4xl mx-auto px-4 py-16">
            <div className="text-center mb-16 animate-in fade-in slide-in-from-bottom-6 duration-700">
              <span className="inline-block px-5 py-2 bg-indigo-50 text-indigo-700 text-[10px] font-black uppercase tracking-[0.25em] rounded-full mb-6 border border-indigo-100">Universal Intake Active</span>
              <h1 className="text-6xl md:text-7xl font-black text-slate-900 mb-8 tracking-tighter leading-[0.9]">Legal Guard <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-600 to-emerald-600">Sync.</span></h1>
              <p className="text-xl text-slate-500 max-w-2xl mx-auto leading-relaxed">The only AI suite built for the signer. Identify risks, rephrase predatory terms, and seal agreements in one secure flow.</p>
            </div>
            <UploadArea onUpload={handleUpload} />
          </div>
        );

      case AppStep.Analyzing:
        return (
          <div className="flex flex-col items-center justify-center min-h-[70vh] animate-in fade-in">
            <div className="relative">
              <div className="w-40 h-40 border-8 border-indigo-50 border-t-indigo-600 rounded-full animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                <i className="fa-solid fa-user-shield text-indigo-600 text-4xl animate-pulse"></i>
              </div>
            </div>
            <h2 className="text-3xl font-black mt-12 text-slate-900 tracking-tight">{loadingMessage}</h2>
            <p className="text-slate-400 mt-4 font-bold uppercase text-xs tracking-widest">Processing Secure Stream...</p>
          </div>
        );

      case AppStep.Dashboard:
        return <Dashboard analysis={analysis!} onRestart={() => setStep(AppStep.Upload)} onConfirm={() => {
          addToAudit("Review Finished", "All terms and risks acknowledged by user");
          setStep(AppStep.Signing);
        }} />;

      case AppStep.Vault:
        return (
          <div className="max-w-5xl mx-auto px-4 py-12 animate-in fade-in duration-500">
            <div className="flex justify-between items-end mb-12">
              <div>
                <h2 className="text-5xl font-black text-slate-900 tracking-tight">Personal Vault</h2>
                <p className="text-slate-500 font-medium mt-2">Zero-knowledge storage of your historical protection records.</p>
              </div>
              <button onClick={() => setStep(AppStep.Upload)} className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black hover:bg-slate-800 transition">Analyze New</button>
            </div>
            {vault.length === 0 ? (
              <div className="bg-white rounded-[2.5rem] p-24 text-center border border-slate-100 shadow-sm ring-8 ring-slate-50">
                <i className="fa-solid fa-vault text-slate-200 text-5xl mb-8 block"></i>
                <h3 className="text-2xl font-black text-slate-900 mb-2">The Vault is Silent</h3>
                <p className="text-slate-400 font-bold">No documents signed or analyzed yet.</p>
              </div>
            ) : (
              <div className="grid gap-6">
                {vault.map(item => (
                  <div key={item.id} className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm flex flex-col group hover:border-indigo-200 transition-all">
                    <div className="flex items-center justify-between mb-4">
                       <div className="flex items-center gap-6">
                         <div className="w-12 h-12 bg-slate-50 rounded-xl flex items-center justify-center text-slate-400 group-hover:text-indigo-600 transition-colors">
                            <i className="fa-solid fa-file-shield text-xl"></i>
                         </div>
                         <div>
                           <h4 className="font-black text-lg text-slate-900">{item.name}</h4>
                           <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{item.date} • {item.type}</span>
                         </div>
                       </div>
                       <button onClick={() => {
                         if (item.analysis) { setAnalysis(item.analysis); setStep(AppStep.Dashboard); }
                       }} className="bg-slate-900 text-white px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-600 transition">View Details</button>
                    </div>
                    {/* Simplified Audit Display */}
                    <div className="bg-slate-50 p-3 rounded-xl border border-slate-100 flex items-center gap-4">
                       <i className="fa-solid fa-fingerprint text-emerald-500 opacity-50"></i>
                       <p className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">Seal Timestamp: {item.auditTrail[item.auditTrail.length - 1]?.timestamp}</p>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        );

      case AppStep.Signing:
        return (
          <div className="max-w-2xl mx-auto py-20 px-4 text-center">
             <div className="w-24 h-24 bg-indigo-50 rounded-3xl flex items-center justify-center mx-auto mb-8 transform rotate-12 shadow-2xl"><i className="fa-solid fa-file-contract text-indigo-600 text-4xl"></i></div>
             <h2 className="text-5xl font-black text-slate-900 mb-6 tracking-tight">Final Authorization</h2>
             <p className="text-slate-500 mb-12 text-lg leading-relaxed font-medium">Signing indicates you have reviewed the AI analysis and understand all detected high-risk clauses.</p>
             <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl border border-slate-100 mb-10">
                <SignaturePad onSign={(data) => setSignature(data)} onClear={() => setSignature(null)} />
             </div>
             <div className="flex gap-5">
                <button onClick={finalizeSigning} className="flex-[2] bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-2xl shadow-indigo-100 hover:bg-indigo-700 transition">Apply Digital Signature</button>
                <button onClick={() => setStep(AppStep.Dashboard)} className="flex-1 bg-white text-slate-400 border border-slate-200 font-black py-5 rounded-2xl">Cancel</button>
             </div>
          </div>
        );

      case AppStep.Finalized:
        return (
          <div className="max-w-2xl mx-auto py-20 px-4 text-center">
            <div className="w-32 h-32 bg-emerald-500 rounded-full flex items-center justify-center mx-auto mb-10 shadow-2xl ring-8 ring-emerald-50"><i className="fa-solid fa-shield-check text-white text-6xl"></i></div>
            <h2 className="text-5xl font-black text-slate-900 mb-6">Execution Complete.</h2>
            <p className="text-slate-500 text-xl mb-12 font-medium">Your agreement is cryptographically sealed and vault-archived.</p>
            <div className="flex flex-col gap-4">
              <button onClick={() => setStep(AppStep.Vault)} className="bg-slate-900 text-white font-black py-5 rounded-2xl transition shadow-2xl flex items-center justify-center gap-3"><i className="fa-solid fa-vault"></i>Enter Personal Vault</button>
              <button onClick={() => setStep(AppStep.Upload)} className="bg-white border-2 border-slate-200 text-slate-700 font-black py-5 rounded-2xl">Start New Analysis</button>
            </div>
          </div>
        );

      default:
        return <div className="text-center py-20">View not found.</div>;
    }
  };

  return (
    <Layout onNavigate={handleNavigate}>
      <div className="relative overflow-hidden min-h-screen">{renderContent()}</div>
    </Layout>
  );
};

