const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const classifyUpload = async (
  base64Data: string,
  mimeType: string
): Promise<ClassificationResult> => {
  const model = "gemini-3-flash-preview";
  const prompt = `
    Analyze this file carefully. 
    Determine the user's intent:
    1. REVIEW: Providing an existing contract to check for risks.
    2. CREATE: Providing notes/voice to draft a new contract.

    Return JSON:
    {
      "intent": "REVIEW" | "CREATE",
      "reasoning": "Brief explanation",
      "suggestedFileName": "Meaningful filename"
    }
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: prompt }
      ]
    },
    config: { responseMimeType: "application/json" }
  });

  return JSON.parse(response.text || '{"intent": "REVIEW"}');
};

export const generateContractContent = async (
  base64Data: string,
