export const analyzeContract = async (
  base64Data: string,
  mimeType: string,
  history: ContractHistoryItem[] = [],
  preferences: UserPreferences = { strictMode: false, focusAreas: [], languagePreference: 'English' }
): Promise<ContractAnalysis> => {
  const model = "gemini-3-pro-preview";

  const historyText = history.length > 0 
    ? `CONTEXT: User history includes: ${history.map(h => h.name).join(', ')}.`
    : '';

  const prompt = `
    Act as a consumer protection attorney. Analyze this document.
    ${historyText}

    REQUIRED JSON SCHEMA:
    {
      "summary": "3-sentence neutral plain-language summary",
      "signerScore": 85,
      "keywords": ["critical legal keywords found"],
      "parties": [{"name": "string", "role": "string"}],
      "obligations": [{"party": "string", "requirement": "string", "deadline": "optional"}],
      "keyTerms": [
        {"title": "string", "value": "string", "category": "Financial|Termination|Privacy|Liability|Duration|Parties|Obligations"}
      ],
      "redFlags": [
        {
          "id": "string",
          "issue": "Specific concern",
          "riskLevel": "High|Medium|Low",
          "suggestion": {
            "whyItMatters": "Reasoning",
            "strategy": "Negotiation move",
            "counterOffer": "Specific alternative clause",
            "rephrasedClause": "A neutral, signer-friendly rephrasing of the original clause",
            "renegotiationKeywords": ["Keywords"],
            "tacticalTips": ["Tips"]
          },
          "originalText": "The original predatory text"
        }
      ],
      "financials": {
        "amount": "string",
        "frequency": "string",
        "totalCommitment": "string",
        "hiddenFees": ["string"]
      },
      "industryComparison": [
        {"metric": "string", "assessment": "string", "isStandard": boolean}
      ],
      "verificationQuestion": "Confirmation question",
      "expectedResponse": "Expected answer",
      "conflictCheck": {
        "hasConflict": boolean,
        "conflictDetails": "string"
      },
      "fullText": "Full extracted plain text",
      "detectedLanguage": "string"
    }
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 8000 }
    }
  });

  try {
    return JSON.parse(response.text || '{}');
  } catch (e) {
    throw new Error("Analysis failed. Content might be too complex.");
  }
};

