import { GoogleGenAI, Type, Modality, GenerateContentResponse } from "@google/genai";
import { ContractAnalysis, ClassificationResult, ContractHistoryItem, ChatMessage, UserPreferences } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const classifyUpload = async (
  base64Data: string,
  mimeType: string
): Promise<ClassificationResult> => {
  const model = "gemini-3-flash-preview";
  const prompt = `
    Determine intent:
    1. REVIEW: Analyzing an existing contract for risks.
    2. CREATE: Drafting a new contract from notes or voice.
    Return JSON: { "intent": "REVIEW" | "CREATE", "reasoning": "string", "suggestedFileName": "string" }
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: prompt }
      ]
    },
    config: { responseMimeType: "application/json" }
  });

  return JSON.parse(response.text || '{"intent": "REVIEW"}');
};

export const analyzeContract = async (
  base64Data: string,
  mimeType: string,
  history: ContractHistoryItem[] = [],
  preferences: UserPreferences = { strictMode: false, focusAreas: [], languagePreference: 'English' }
): Promise<ContractAnalysis> => {
  const model = "gemini-3-pro-preview";

  const historyText = history.length > 0 
    ? `CONTEXT: User history includes: ${history.map(h => h.name).join(', ')}.`
    : '';

  const prompt = `
    Act as a protective legal bodyguard for the signer. Analyze this document/input.
    ${historyText}
    Preferences: ${JSON.stringify(preferences)}

    REQUIRED JSON SCHEMA:
    {
      "summary": "3-sentence neutral plain-language summary",
      "signerScore": 1-100,
      "keywords": ["List 5-8 critical legal keywords like 'Indemnity', 'Non-compete'"],
      "parties": [{"name": "string", "role": "string"}],
      "obligations": [{"party": "string", "requirement": "string", "deadline": "string"}],
      "keyTerms": [
        {"title": "string", "value": "string", "category": "Financial|Termination|Privacy|Liability|Duration|Parties|Obligations"}
      ],
      "redFlags": [
        {
          "id": "string",
          "issue": "Specific concern (e.g., Hidden Auto-Renewal)",
          "riskLevel": "High|Medium|Low",
          "suggestion": {
            "whyItMatters": "Reasoning",
            "strategy": "Negotiation strategy",
            "counterOffer": "Specific alternative clause text",
            "rephrasedClause": "A neutral, signer-friendly version of the original predatory clause",
            "renegotiationKeywords": ["Keywords"],
            "tacticalTips": ["Tips"]
          },
          "originalText": "The actual text from the document"
        }
      ],
      "financials": {
        "amount": "Total cost",
        "frequency": "Payment schedule",
        "totalCommitment": "Grand total value",
        "hiddenFees": ["Potential extra costs"]
      },
      "industryComparison": [{"metric": "string", "assessment": "string", "isStandard": boolean}],
      "verificationQuestion": "Security question for the user to confirm their understanding",
      "expectedResponse": "The correct answer to the question above",
      "conflictCheck": { "hasConflict": boolean, "conflictDetails": "string" },
      "fullText": "Full extracted plain text (OCR)",
      "detectedLanguage": "string"
    }
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 8000 }
    }
  });

  try {
    return JSON.parse(response.text || '{}');
  } catch (e) {
    throw new Error("Analysis engine failed to parse structure.");
  }
};

export const chatWithBodyguard = async (
  message: string,
  analysis: ContractAnalysis,
  history: ChatMessage[]
): Promise<string> => {
  const model = "gemini-3-flash-preview";
  const chat = ai.chats.create({
    model,
    config: {
      systemInstruction: `You are the SignWise Bodyguard. Protect the user. Current analysis: ${JSON.stringify(analysis)}`
    }
  });
  const response = await chat.sendMessage({ message });
  return response.text || "Error.";
};

export const generateVoiceSummary = async (text: string): Promise<string> => {
  const model = "gemini-2.5-flash-preview-tts";
  const response = await ai.models.generateContent({
    model,
    contents: [{ parts: [{ text: `Here is your contract bodyguard brief: ${text}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
      },
    },
  });
  return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || "";
};

export const generateNegotiationEmail = async (analysis: ContractAnalysis): Promise<string> => {
  const model = "gemini-3-flash-preview";
  const prompt = `Write a professional, collaborative negotiation email for the signer focusing on these red flags: ${JSON.stringify(analysis.redFlags)}. Request fairer terms for ${analysis.parties[0]?.name || 'the signer'}.`;
  const response = await ai.models.generateContent({ model, contents: prompt });
  return response.text || "";
};

export const compareWithStandards = async (analysis: ContractAnalysis): Promise<string> => {
  const model = "gemini-3-flash-preview";
  const prompt = `Compare these terms to industry standards: ${JSON.stringify(analysis)}. Identify predatory vs fair clauses in Markdown.`;
  const response = await ai.models.generateContent({ model, contents: prompt });
  return response.text || "";
};

export const refineContract = async (content: string, instruction: string): Promise<string> => {
  const model = "gemini-3-pro-preview";
  const prompt = `Refine this legal content: ${instruction}. Content: ${content}. Return only Markdown.`;
  const response = await ai.models.generateContent({ model, contents: prompt, config: { thinkingConfig: { thinkingBudget: 4000 } } });
  return response.text || content;
};

export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number = 24000, numChannels: number = 1): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

