import React, { useState } from 'react';

interface RedFlagProps {
  id: string;
  issue: string;
  riskLevel: 'High' | 'Medium' | 'Low';
  suggestion: {
    whyItMatters: string;
    strategy: string;
    counterOffer: string;
    rephrasedClause: string;
    renegotiationKeywords?: string[];
    tacticalTips?: string[];
  };
  originalText: string;
}

const RedFlagCard: React.FC<RedFlagProps> = ({ id, issue, riskLevel, suggestion, originalText }) => {
  const [feedback, setFeedback] = useState<'useful' | 'not-useful' | null>(null);
  const [showRephrased, setShowRephrased] = useState(false);

  const getRiskStyles = () => {
    switch (riskLevel) {
      case 'High': return 'bg-red-50 border-red-200 text-red-900';
      case 'Medium': return 'bg-amber-50 border-amber-200 text-amber-900';
      default: return 'bg-blue-50 border-blue-200 text-blue-900';
    }
  };

  const getBadgeStyles = () => {
    switch (riskLevel) {
      case 'High': return 'bg-red-600 text-white shadow-red-200';
      case 'Medium': return 'bg-amber-500 text-white shadow-amber-200';
      default: return 'bg-blue-600 text-white shadow-blue-200';
    }
  };

  const styles = getRiskStyles();

  return (
    <div className={`p-6 rounded-3xl border-l-[8px] mb-6 transition-all hover:shadow-xl bg-white border ${styles.split(' ')[1]} group`}>
      <div className="flex justify-between items-start mb-4">
        <div className="flex items-center gap-3">
          <div className={`w-10 h-10 rounded-xl flex items-center justify-center shadow-sm ${getBadgeStyles()}`}>
            {riskLevel === 'High' && <i className="fa-solid fa-triangle-exclamation animate-pulse"></i>}
            {riskLevel === 'Medium' && <i className="fa-solid fa-circle-info"></i>}
            {riskLevel === 'Low' && <i className="fa-solid fa-shield"></i>}
          </div>
          <div>
            <h4 className="font-black text-xl text-slate-900">{issue}</h4>
            <span className={`text-[9px] font-black uppercase tracking-widest px-2 py-0.5 rounded ${getBadgeStyles()}`}>{riskLevel} Risk</span>
          </div>
        </div>
        <div className="flex bg-slate-100 rounded-xl p-1 shadow-inner">
          <button 
            onClick={() => setFeedback('useful')}
            className={`p-2 rounded-lg transition ${feedback === 'useful' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
          >
            <i className="fa-solid fa-thumbs-up"></i>
          </button>
          <button 
            onClick={() => setFeedback('not-useful')}
