// Initializing the Google GenAI client using the environment's API key.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Classifies the uploaded content to determine if the user wants to review an existing contract or create a new one.
export const classifyUpload = async (
  base64Data: string,
  mimeType: string
): Promise<ClassificationResult> => {
  const model = "gemini-3-flash-preview";
  const prompt = `
    Analyze the uploaded document's intent. 
    1. REVIEW: The document is an existing contract the user wants to understand, scan for risks, or summarize.
    2. CREATE: The document is a brief, voice note, or list of terms for a NEW contract the user wants to draft.

    Return JSON:
    {
      "intent": "REVIEW" | "CREATE",
      "reasoning": "Brief explanation of why",
      "suggestedFileName": "A professional filename for this document"
    }
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: prompt }
      ]
    },
    config: { responseMimeType: "application/json" }
  });

  return JSON.parse(response.text || '{"intent": "REVIEW"}');
};

// Performs a deep analysis of a contract using the Gemini 3 Pro model for high-reasoning legal auditing.
export const analyzeContract = async (
  base64Data: string,
  mimeType: string,
  history: ContractHistoryItem[] = [],
  preferences: UserPreferences = { strictMode: false, focusAreas: [], languagePreference: 'English' }
): Promise<ContractAnalysis> => {
  const model = "gemini-3-pro-preview";

  const historyText = history.length > 0 
    ? `CONTEXT: The user has previously reviewed/signed these documents: ${history.map(h => h.name).join(', ')}. Check for potential conflicts with these.`
    : '';

  const prompt = `
    Act as a high-powered consumer protection attorney and "Signer's Bodyguard". 
    Perform a deep analysis of the provided document.
    ${historyText}

    USER PREFERENCES:
    - Strict Mode: ${preferences.strictMode} (If true, flag any clause that isn't perfectly neutral)
    - Focus Areas: ${preferences.focusAreas.join(', ')}
    - Output Language: ${preferences.languagePreference}

    Analyze for:
    1. Key Parties and their roles.
    2. Critical Obligations for the signer.
    3. Financial commitment (amounts, frequency, hidden fees).
    4. Red Flags (Liability caps, auto-renewals, non-competes, arbitration, data privacy).
    5. Plain-language summary.

    REQUIRED JSON SCHEMA:
    {
      "summary": "Concise 3-sentence summary of the core agreement.",
      "signerScore": 85,
      "keywords": ["List 5-8 critical keywords found"],
      "parties": [{"name": "string", "role": "string"}],
      "obligations": [{"party": "string", "requirement": "string", "deadline": "optional date/trigger"}],
      "keyTerms": [
        {"title": "string", "value": "string", "category": "Financial|Termination|Privacy|Liability|Duration|Parties|Obligations"}
      ],
      "redFlags": [
        {
          "id": "unique_id",
          "issue": "The core risk (e.g. Uncapped Liability)",
          "riskLevel": "High|Medium|Low",
          "suggestion": {
            "whyItMatters": "Explain the real-world harm to the user.",
            "strategy": "How to negotiate this point.",
            "counterOffer": "Specific fairer clause text the user can propose.",
            "rephrasedClause": "A neutral, 'signer-friendly' version of the original clause.",
            "renegotiationKeywords": ["Keywords to use in discussion"],
            "tacticalTips": ["Specific action steps"]
          },
          "originalText": "The exact text from the document being flagged"
        }
      ],
      "financials": {
        "amount": "Primary dollar amount",
        "frequency": "Payment frequency",
        "totalCommitment": "Calculated total commitment",
        "hiddenFees": ["List any potential extra costs"]
      },
      "industryComparison": [{"metric": "The term/fee", "assessment": "How it compares", "isStandard": boolean}],
      "verificationQuestion": "A question to test if the user understands a critical part of the contract.",
      "expectedResponse": "The correct short answer to the verification question.",
      "conflictCheck": { "hasConflict": boolean, "conflictDetails": "Explanation of any conflicts with history" },
      "fullText": "Full extracted plain text of the document (OCR result)",
      "detectedLanguage": "The language of the document"
    }
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 12000 }
    }
  });

  try {
    return JSON.parse(response.text || '{}');
  } catch (e) {
    throw new Error("Analysis failed. The document may be too complex or unclear.");
  }
};

