import React, { useRef, useState, useEffect } from 'react';
import { UserPreferences } from '../types';

interface UploadAreaProps {
  onUpload: (base64: string, mimeType: string, preferences: UserPreferences) => void;
}

const UploadArea: React.FC<UploadAreaProps> = ({ onUpload }) => {
  const [isDragging, setIsDragging] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [recordingType, setRecordingType] = useState<'audio' | 'video' | 'camera' | null>(null);
  const [preferences, setPreferences] = useState<UserPreferences>({
    strictMode: false,
    focusAreas: ['Liability', 'Financial'],
    languagePreference: 'English',
    secureLocalMode: true
  });
  const [showPrefs, setShowPrefs] = useState(false);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const streamRef = useRef<MediaStream | null>(null);

  const handleFile = (file: File) => {
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      const base64 = (e.target?.result as string).split(',')[1];
      if (file.type.startsWith('image/')) {
        setPreviewUrl(URL.createObjectURL(file));
      }
      onUpload(base64, file.type, preferences);
    };
    reader.readAsDataURL(file);
  };

  const startMedia = async (type: 'audio' | 'video' | 'camera') => {
    try {
      const constraints: MediaStreamConstraints = { 
        audio: type !== 'camera', 
        video: type === 'video' || type === 'camera' ? { facingMode: 'environment' } : false 
      };
      const stream = await navigator.mediaDevices.getUserMedia(constraints);
      streamRef.current = stream;
      setRecordingType(type);
      setIsRecording(true);

      if (type === 'camera' && videoRef.current) {
        videoRef.current.srcObject = stream;
      } else {
        chunksRef.current = [];
        const recorder = new MediaRecorder(stream);
        mediaRecorderRef.current = recorder;
        recorder.ondataavailable = (e) => {
          if (e.data.size > 0) chunksRef.current.push(e.data);
        };
        recorder.onstop = () => {
          const blob = new Blob(chunksRef.current, { type: recorder.mimeType });
          const reader = new FileReader();
          reader.onloadend = () => {
            const base64 = (reader.result as string).split(',')[1];
            onUpload(base64, recorder.mimeType, preferences);
          };
          reader.readAsDataURL(blob);
          stream.getTracks().forEach(track => track.stop());
        };
        recorder.start();
      }
    } catch (err) {
      alert("Device not accessible. Check permissions.");
      console.error(err);
    }
  };

  const capturePhoto = () => {
    const video = videoRef.current;
    if (!video) return;
    const canvas = document.createElement('canvas');
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    ctx?.drawImage(video, 0, 0);
    const dataUrl = canvas.toDataURL('image/jpeg');
    const base64 = dataUrl.split(',')[1];
    setPreviewUrl(dataUrl);
    stopMedia();
    onUpload(base64, 'image/jpeg', preferences);
  };

  const stopMedia = () => {
    if (recordingType === 'camera') {
      streamRef.current?.getTracks().forEach(track => track.stop());
    } else {
      mediaRecorderRef.current?.stop();
    }
    setIsRecording(false);
    setRecordingType(null);
  };

  const toggleFocusArea = (area: string) => {
    setPreferences(prev => ({
      ...prev,
      focusAreas: prev.focusAreas.includes(area) 
        ? prev.focusAreas.filter(a => a !== area)
        : [...prev.focusAreas, area]
    }));
  };

  return (
    <div className="space-y-8">
      {/* Settings Panel */}
      <div className="max-w-xl mx-auto">
        <button 
          onClick={() => setShowPrefs(!showPrefs)}
          className="flex items-center justify-between w-full bg-white px-8 py-5 rounded-[2rem] border border-slate-200 shadow-sm hover:border-indigo-300 transition-all group active:scale-95"
        >
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-600 transition-transform group-hover:rotate-12">
              <i className="fa-solid fa-sliders"></i>
            </div>
            <span className="text-xs font-black text-slate-800 uppercase tracking-widest">Intake Intelligence Hub</span>
          </div>
          <div className="flex gap-2">
            {preferences.secureLocalMode && <span className="text-[8px] bg-emerald-100 text-emerald-700 px-3 py-1 rounded-full font-black uppercase tracking-tighter"><i className="fa-solid fa-lock mr-1"></i>Secure Mode</span>}
            <i className={`fa-solid fa-chevron-down text-slate-300 transition-transform ${showPrefs ? 'rotate-180' : ''}`}></i>
          </div>
        </button>

        {showPrefs && (
          <div className="mt-6 bg-white p-10 rounded-[2.5rem] border border-slate-200 shadow-2xl animate-in fade-in slide-in-from-top-6">
            <div className="space-y-8">
              <div className="flex items-center justify-between p-6 bg-emerald-50 rounded-[1.5rem] border border-emerald-100">
                <div>
                  <h4 className="text-sm font-black text-emerald-900 uppercase tracking-tight mb-1">Secure Processing Mode</h4>
                  <p className="text-[10px] text-emerald-700 font-bold opacity-70 italic leading-relaxed">Prioritize data masking and localized analysis for sensitive docs.</p>
                </div>
                <input 
                  type="checkbox" 
                  checked={preferences.secureLocalMode}
                  onChange={(e) => setPreferences({...preferences, secureLocalMode: e.target.checked})}
                  className="w-6 h-6 rounded-lg text-emerald-600 focus:ring-emerald-500"
                />
              </div>

              <div>
                <div className="flex items-center justify-between mb-2">
                  <h4 className="text-xs font-black text-slate-900 uppercase tracking-widest">Risk Sensitivity</h4>
                  <input 
                    type="checkbox" 
                    checked={preferences.strictMode}
                    onChange={(e) => setPreferences({...preferences, strictMode: e.target.checked})}
                    className="w-6 h-6 rounded-lg text-indigo-600 focus:ring-indigo-500"
                  />
                </div>
                <p className="text-[10px] text-slate-400 font-bold leading-relaxed italic">"STRICT" flags all language favoring the sender, regardless of industry standard.</p>
              </div>

              <div>
                <h4 className="text-xs font-black text-slate-900 uppercase mb-4 tracking-widest">Critical Focus Domains</h4>
                <div className="flex flex-wrap gap-2">
                  {['Financial', 'Liability', 'Privacy', 'Termination', 'Intellectual Property'].map(area => (
                    <button
                      key={area}
                      onClick={() => toggleFocusArea(area)}
                      className={`px-5 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
                        preferences.focusAreas.includes(area) 
                          ? 'bg-slate-900 text-white shadow-xl scale-105' 
                          : 'bg-slate-50 text-slate-400 border border-slate-200 hover:border-slate-300'
                      }`}
                    >
                      {area}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <h4 className="text-xs font-black text-slate-900 uppercase mb-3 tracking-widest">Interface Language</h4>
                <select 
                  value={preferences.languagePreference}
                  onChange={(e) => setPreferences({...preferences, languagePreference: e.target.value})}
                  className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-6 py-4 text-xs font-black focus:ring-4 focus:ring-indigo-500/10 outline-none transition"
                >
                  <option>English</option>
                  <option>Spanish</option>
                  <option>French</option>
                  <option>German</option>
                  <option>Mandarin</option>
                </select>
              </div>
            </div>
          </div>
        )}
      </div>

      <div 
        className={`relative border-[4px] border-dashed rounded-[3.5rem] p-16 transition-all duration-500 cursor-pointer bg-white group shadow-inner ${
          isDragging ? 'border-indigo-500 bg-indigo-50/50 scale-[1.02]' : 'border-slate-100 hover:border-indigo-200'
        }`}
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={(e) => {
          e.preventDefault();
          setIsDragging(false);
          const file = e.dataTransfer.files[0];
          if (file) handleFile(file);
        }}
        onClick={() => !isRecording && fileInputRef.current?.click()}
      >
        <input 
          type="file" 
          className="hidden" 
          ref={fileInputRef} 
          onChange={(e) => e.target.files?.[0] && handleFile(e.target.files[0])}
          accept="*"
        />

        {isRecording ? (
          <div className="text-center py-10 animate-in zoom-in-95 duration-500">
