      "parties": [{"name": "string", "role": "string"}],
      "obligations": [{"party": "string", "requirement": "string", "deadline": "optional"}],
      "keyTerms": [
        {"title": "string", "value": "string", "category": "Financial|Termination|Privacy|Liability|Duration|Parties|Obligations"}
      ],
      "redFlags": [
        {
          "id": "id",
          "issue": "Brief risk concern title",
          "riskLevel": "High|Medium|Low",
          "suggestion": {
            "whyItMatters": "Explain the actual harm to the user in simple terms",
            "strategy": "How to negotiate this point",
            "counterOffer": "Specific fairer clause text to propose",
            "rephrasedClause": "A neutral, signer-friendly version of the original predatory text",
            "renegotiationKeywords": ["Words to use in discussion"],
            "tacticalTips": ["Tips for the user"]
          },
          "originalText": "The exact problematic text from the document"
        }
      ],
      "financials": {
        "amount": "string",
        "frequency": "string",
        "totalCommitment": "string",
        "hiddenFees": ["string"]
      },
      "industryComparison": [{"metric": "string", "assessment": "string", "isStandard": boolean}],
      "verificationQuestion": "A security question to test if the user understands a critical risk identified above",
      "expectedResponse": "The correct concise answer to the security question",
      "fullText": "Full extracted plain text (OCR results)",
      "detectedLanguage": "string"
    }
  `;

  const response = await ai.models.generateContent({
