import React, { useRef, useState, useEffect } from 'react';
import { UserPreferences } from '../types';

interface UploadAreaProps {
  onUpload: (base64: string, mimeType: string, preferences: UserPreferences) => void;
}

const UploadArea: React.FC<UploadAreaProps> = ({ onUpload }) => {
  const [isDragging, setIsDragging] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [recordingType, setRecordingType] = useState<'audio' | 'video' | 'camera' | null>(null);
  const [preferences, setPreferences] = useState<UserPreferences>({
    strictMode: false,
    focusAreas: ['Liability', 'Financial'],
    languagePreference: 'English',
    secureLocalMode: true
  });
  const [showPrefs, setShowPrefs] = useState(false);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const streamRef = useRef<MediaStream | null>(null);

  const handleFile = (file: File) => {
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      const base64 = (e.target?.result as string).split(',')[1];
      if (file.type.startsWith('image/')) {
        setPreviewUrl(URL.createObjectURL(file));
      }
      onUpload(base64, file.type, preferences);
    };
    reader.readAsDataURL(file);
  };

  const startMedia = async (type: 'audio' | 'video' | 'camera') => {
    try {
      const constraints: MediaStreamConstraints = { 
        audio: type !== 'camera', 
        video: type === 'video' || type === 'camera' ? { facingMode: 'environment' } : false 
      };
      const stream = await navigator.mediaDevices.getUserMedia(constraints);
      streamRef.current = stream;
      setRecordingType(type);
      setIsRecording(true);

      if (type === 'camera' && videoRef.current) {
        videoRef.current.srcObject = stream;
      } else {
        chunksRef.current = [];
        const recorder = new MediaRecorder(stream);
        mediaRecorderRef.current = recorder;
        recorder.ondataavailable = (e) => {
          if (e.data.size > 0) chunksRef.current.push(e.data);
        };
        recorder.onstop = () => {
          const blob = new Blob(chunksRef.current, { type: recorder.mimeType });
          const reader = new FileReader();
          reader.onloadend = () => {
            const base64 = (reader.result as string).split(',')[1];
            onUpload(base64, recorder.mimeType, preferences);
          };
          reader.readAsDataURL(blob);
          stream.getTracks().forEach(track => track.stop());
        };
        recorder.start();
      }
    } catch (err) {
      alert("Hardware access blocked. Please check your browser privacy permissions.");
      console.error(err);
    }
  };

  const capturePhoto = () => {
    const video = videoRef.current;
    if (!video) return;
    const canvas = document.createElement('canvas');
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    ctx?.drawImage(video, 0, 0);
    const dataUrl = canvas.toDataURL('image/jpeg');
    const base64 = dataUrl.split(',')[1];
    setPreviewUrl(dataUrl);
    stopMedia();
    onUpload(base64, 'image/jpeg', preferences);
  };

  const stopMedia = () => {
    if (recordingType === 'camera') {
      streamRef.current?.getTracks().forEach(track => track.stop());
    } else {
      mediaRecorderRef.current?.stop();
    }
    setIsRecording(false);
    setRecordingType(null);
  };

  const toggleFocusArea = (area: string) => {
    setPreferences(prev => ({
      ...prev,
      focusAreas: prev.focusAreas.includes(area) 
        ? prev.focusAreas.filter(a => a !== area)
        : [...prev.focusAreas, area]
    }));
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-1000">
      {/* Risk & Preference Center */}
      <div className="max-w-xl mx-auto">
        <button 
          onClick={() => setShowPrefs(!showPrefs)}
          className="flex items-center justify-between w-full bg-white px-8 py-6 rounded-[2rem] border border-slate-200 shadow-sm hover:border-indigo-400 transition-all group active:scale-95"
        >
          <div className="flex items-center gap-5">
            <div className="w-12 h-12 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 transition-transform group-hover:rotate-12">
              <i className="fa-solid fa-sliders text-xl"></i>
            </div>
            <div className="text-left">
              <span className="text-xs font-black text-slate-800 uppercase tracking-widest block leading-none mb-1">Guardian Engine</span>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">Customize Risk Thresholds</p>
            </div>
          </div>
          <div className="flex items-center gap-3">
            {preferences.secureLocalMode && <span className="text-[8px] bg-emerald-100 text-emerald-700 px-3 py-1 rounded-full font-black uppercase tracking-tighter hidden md:inline-flex items-center gap-1"><i className="fa-solid fa-lock text-[6px]"></i>Secure Mode</span>}
            <i className={`fa-solid fa-chevron-down text-slate-300 transition-transform ${showPrefs ? 'rotate-180' : ''}`}></i>
          </div>
        </button>

        {showPrefs && (
          <div className="mt-6 bg-white p-10 rounded-[3rem] border border-slate-200 shadow-[0_30px_60px_rgba(0,0,0,0.1)] animate-in fade-in slide-in-from-top-6 duration-500">
            <div className="space-y-8">
              <div className="flex items-center justify-between p-6 bg-emerald-50 rounded-[2rem] border border-emerald-100">
                <div>
                  <h4 className="text-sm font-black text-emerald-900 uppercase tracking-tight mb-1 flex items-center gap-2"><i className="fa-solid fa-fingerprint"></i> Secure Processing Mode</h4>
                  <p className="text-[10px] text-emerald-700 font-bold opacity-70 italic leading-relaxed">Prioritize PII masking and zero-knowledge localized analysis.</p>
                </div>
                <div className="relative inline-flex items-center cursor-pointer">
                  <input 
                    type="checkbox" 
                    checked={preferences.secureLocalMode}
                    onChange={(e) => setPreferences({...preferences, secureLocalMode: e.target.checked})}
                    className="sr-only peer"
                  />
                  <div className="w-12 h-7 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-slate-300 after:border after:rounded-full after:h-6 after:w-6 after:transition-all peer-checked:bg-emerald-500"></div>
                </div>
              </div>

              <div>
                <div className="flex items-center justify-between mb-3">
                  <h4 className="text-xs font-black text-slate-900 uppercase tracking-widest">Risk Sensitivity</h4>
                  <input 
                    type="checkbox" 
                    checked={preferences.strictMode}
                    onChange={(e) => setPreferences({...preferences, strictMode: e.target.checked})}
                    className="w-6 h-6 rounded-lg text-indigo-600 focus:ring-indigo-500 border-slate-300"
                  />
                </div>
                <p className="text-[10px] text-slate-400 font-bold leading-relaxed italic">"STRICT" flags all language favoring the sender, regardless of fairness.</p>
              </div>

              <div>
                <h4 className="text-xs font-black text-slate-900 uppercase mb-5 tracking-widest">Critical Guard Domains</h4>
                <div className="flex flex-wrap gap-2">
                  {['Financial', 'Liability', 'Privacy', 'Termination', 'Intellectual Property'].map(area => (
                    <button
                      key={area}
                      onClick={() => toggleFocusArea(area)}
                      className={`px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
                        preferences.focusAreas.includes(area) 
                          ? 'bg-slate-900 text-white shadow-xl scale-105' 
                          : 'bg-slate-50 text-slate-400 border border-slate-200 hover:border-slate-400'
                      }`}
                    >
                      {area}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Main Dropzone / Scanner */}
      <div 
        className={`relative border-[6px] border-dashed rounded-[4rem] p-16 transition-all duration-700 cursor-pointer bg-white group shadow-inner ${
          isDragging ? 'border-indigo-500 bg-indigo-50/50 scale-[1.01]' : 'border-slate-100 hover:border-indigo-300 hover:shadow-2xl'
        }`}
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={(e) => {
          e.preventDefault();
          setIsDragging(false);
          const file = e.dataTransfer.files[0];
          if (file) handleFile(file);
        }}
        onClick={() => !isRecording && fileInputRef.current?.click()}
      >
        <input 
          type="file" 
          className="hidden" 
          ref={fileInputRef} 
          onChange={(e) => e.target.files?.[0] && handleFile(e.target.files[0])}
          accept="*"
        />

        {isRecording ? (
          <div className="text-center py-10 animate-in zoom-in-95 duration-500">
            {recordingType === 'camera' ? (
              <div className="relative max-w-lg mx-auto mb-10 bg-slate-950 rounded-[3rem] overflow-hidden shadow-[0_50px_100px_rgba(0,0,0,0.6)] border-[10px] border-slate-900 aspect-[3/4] ring-20 ring-slate-50">
                <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover opacity-80" />

                {/* Real-time Scan Overlay */}
                <div className="absolute inset-0 pointer-events-none">
                  <div className="absolute top-1/2 left-0 right-0 h-[2px] bg-indigo-500 shadow-[0_0_25px_#6366f1] animate-scan-slow"></div>
                  <div className="absolute inset-12 border-2 border-white/30 rounded-3xl">
                    <div className="absolute top-0 left-0 w-16 h-16 border-t-[10px] border-l-[10px] border-indigo-600 rounded-tl-2xl"></div>
