                    <div className="absolute bottom-0 left-0 w-16 h-16 border-b-[10px] border-l-[10px] border-indigo-600 rounded-bl-2xl"></div>
                    <div className="absolute bottom-0 right-0 w-16 h-16 border-b-[10px] border-r-[10px] border-indigo-600 rounded-br-2xl"></div>
                  </div>
                  <div className="absolute bottom-32 left-1/2 -translate-x-1/2 text-white/60 text-[10px] font-black uppercase tracking-[0.6em] animate-pulse">
                    Capture Document
                  </div>
                </div>

                <div className="absolute bottom-12 inset-x-0 flex justify-center">
                  <button 
                    onClick={(e) => { e.stopPropagation(); capturePhoto(); }}
                    className="w-24 h-24 bg-white rounded-full border-[10px] border-slate-900 shadow-2xl flex items-center justify-center group active:scale-90 transition-all"
                  >
                    <div className="w-16 h-16 bg-indigo-600 rounded-full group-hover:bg-indigo-700 transition shadow-inner"></div>
                  </button>
                </div>
              </div>
            ) : (
              <div className="relative w-36 h-36 mx-auto mb-12">
                <div className="absolute inset-0 bg-red-500/20 rounded-full animate-ping"></div>
                <div className="relative w-full h-full bg-red-500 rounded-full flex items-center justify-center border-[8px] border-white shadow-2xl">
                  <i className={`fa-solid ${recordingType === 'video' ? 'fa-video' : 'fa-microphone'} text-white text-5xl`}></i>
                </div>
              </div>
            )}
            <h3 className="text-5xl font-black text-slate-900 mb-6 uppercase tracking-tighter leading-none">
              {recordingType === 'camera' ? 'Direct Vision Intake' : `Transcribing ${recordingType}...`}
            </h3>
            <button 
