              className="bg-slate-900 text-white px-16 py-7 rounded-[2rem] font-black hover:bg-red-600 transition shadow-[0_20px_60px_rgba(0,0,0,0.3)] active:scale-95 text-xs uppercase tracking-widest"
            >
              Cancel Feed
            </button>
          </div>
        ) : (
          <div className="text-center py-10">
            {previewUrl ? (
              <div className="mb-14 animate-in slide-in-from-bottom-10 duration-1000">
                <div className="relative w-48 h-64 mx-auto rounded-[2.5rem] border-[8px] border-white shadow-[0_40px_80px_rgba(0,0,0,0.2)] overflow-hidden group/preview ring-24 ring-indigo-50/50">
                  <img src={previewUrl} className="w-full h-full object-cover" alt="OCR Preview" />
                  <div className="absolute inset-0 bg-indigo-600/70 backdrop-blur-md flex items-center justify-center opacity-0 group-hover/preview:opacity-100 transition-all duration-300">
                    <span className="text-white text-[10px] font-black uppercase tracking-widest border-2 border-white px-4 py-2 rounded-xl">Retake</span>
                  </div>
                </div>
                <p className="mt-10 text-emerald-600 font-black text-xs uppercase tracking-[0.4em] flex items-center justify-center gap-3">
