// Classifies an uploaded file as either a contract to REVIEW or a prompt to CREATE a new one.
export const classifyUpload = async (
  base64Data: string,
  mimeType: string
): Promise<ClassificationResult> => {
  const model = "gemini-3-flash-preview";
  const prompt = `
    Analyze this document's intent. 
    1. REVIEW: An existing contract for risk assessment.
    2. CREATE: Drafting a new contract from a brief or voice note.

    Return JSON: { "intent": "REVIEW" | "CREATE", "reasoning": "string", "suggestedFileName": "string" }
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { data: base64Data, mimeType } },
        { text: prompt }
      ]
    },
    config: { responseMimeType: "application/json" }
  });

  return JSON.parse(response.text || '{"intent": "REVIEW"}');
};

