        "counterClauses": [{"original": "string", "suggested": "string", "reasoning": "string"}],
        "concessionStrategy": "What to give up to get what you want"
      },
      ${isComparison ? '"versionDiffs": [{ "clause": "string", "oldValue": "string", "newValue": "string", "changeType": "Addition|Deletion|Modification", "riskImpact": "Better|Worse|Neutral" }],' : ""}
      "verificationQuestion": "Understanding check",
      "expectedResponse": "Correct answer",
