              <h1 className="text-7xl md:text-8xl font-black text-slate-900 mb-8 tracking-tighter leading-none">Your Legal <span className="text-indigo-600">Shield.</span></h1>
              <p className="text-xl text-slate-500 max-w-2xl mx-auto leading-relaxed font-medium">Analyze batches, compare versions, and simulate negotiations before you ever pick up a pen.</p>
            </div>
            <UploadArea onUpload={handleUpload} />
          </div>
        );

      case AppStep.Analyzing:
        return (
          <div className="flex flex-col items-center justify-center min-h-[70vh]">
            <div className="relative w-64 h-64">
              <div className="absolute inset-0 border-8 border-indigo-100 rounded-full"></div>
              <div className="absolute inset-0 border-8 border-transparent border-t-indigo-600 rounded-full animate-spin"></div>
              <div className="absolute inset-8 bg-white rounded-full shadow-2xl flex items-center justify-center">
                <i className="fa-solid fa-user-shield text-indigo-600 text-5xl animate-pulse"></i>
              </div>
            </div>
            <h2 className="text-4xl font-black mt-16 text-slate-900 tracking-tight">{loadingMessage}</h2>
            <div className="mt-8 flex gap-2">
