        return <Dashboard 
          analysis={analysis!} 
          onRestart={() => setStep(AppStep.Upload)} 
          onDecline={() => setStep(AppStep.Vault)}
          onConfirm={() => setStep(AppStep.Signing)} 
          auditTrail={currentAuditTrail}
        />;

      case AppStep.Vault:
        return (
          <div className="max-w-6xl mx-auto px-4 py-12">
            <div className="flex justify-between items-end mb-12">
              <div>
                <h2 className="text-5xl font-black text-slate-900 tracking-tighter">Legal Vault</h2>
                <p className="text-slate-500 font-bold mt-2 uppercase text-[10px] tracking-widest">End-to-End Encrypted Storage</p>
              </div>
              <div className="flex gap-4">
                <button onClick={() => setStep(AppStep.Analytics)} className="bg-white border border-slate-200 text-slate-700 px-6 py-3 rounded-2xl font-black text-xs uppercase hover:bg-slate-50 transition">View Trends</button>
                <button onClick={() => setStep(AppStep.Upload)} className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-black text-xs uppercase hover:bg-indigo-700 transition shadow-xl">New Analysis</button>
              </div>
            </div>
            {vault.length === 0 ? (
              <div className="bg-white rounded-[3rem] p-32 text-center border-2 border-dashed border-slate-200">
                <i className="fa-solid fa-folder-open text-slate-200 text-8xl mb-8"></i>
                <h3 className="text-2xl font-black text-slate-400">Your vault is currently empty.</h3>
              </div>
            ) : (
              <div className="grid gap-4">
                {vault.map(item => (
                  <div key={item.id} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm flex items-center justify-between group hover:shadow-2xl transition-all cursor-pointer" onClick={() => { if(item.analysis) {setAnalysis(item.analysis); setStep(AppStep.Dashboard);}}}>
                    <div className="flex items-center gap-6">
                      <div className={`w-16 h-16 rounded-3xl flex items-center justify-center text-2xl ${item.status === 'Signed' ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
                        <i className={`fa-solid ${item.status === 'Signed' ? 'fa-signature' : 'fa-ban'}`}></i>
                      </div>
                      <div>
                        <h4 className="font-black text-xl text-slate-900">{item.name}</h4>
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{item.date} • {item.status}</p>
                      </div>
                    </div>
                    <i className="fa-solid fa-chevron-right text-slate-200 group-hover:text-indigo-600 transition"></i>
                  </div>
                ))}
              </div>
            )}
          </div>
        );

      case AppStep.Analytics:
        return (
          <div className="max-w-6xl mx-auto px-4 py-16">
            <h2 className="text-5xl font-black mb-12 tracking-tighter">Risk Analytics</h2>
            <div className="grid md:grid-cols-3 gap-8">
              <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm col-span-2">
                <h3 className="text-xl font-black mb-8 uppercase tracking-widest text-slate-400">Common Risk Categories</h3>
                <div className="space-y-6">
                  {['Liability Cap', 'Data Privacy', 'Arbitration Clauses', 'Auto-Renewal'].map((cat, i) => (
                    <div key={i} className="space-y-2">
                      <div className="flex justify-between text-xs font-black uppercase tracking-widest">
                        <span>{cat}</span>
                        <span>{Math.floor(Math.random() * 50 + 20)}% of Docs</span>
                      </div>
                      <div className="h-4 w-full bg-slate-100 rounded-full overflow-hidden">
                        <div className="h-full bg-indigo-600 rounded-full" style={{ width: `${Math.random() * 60 + 20}%` }}></div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
              <div className="bg-slate-900 text-white p-10 rounded-[3rem] shadow-2xl">
                <h3 className="text-xl font-black mb-6 uppercase tracking-widest text-indigo-400">Compliance Health</h3>
                <div className="text-7xl font-black mb-4">A-</div>
                <p className="text-slate-400 font-medium leading-relaxed">Your contracts are 82% aligned with your personal Playbook rules. Focus on tightening 'Liability' terms in future negotiations.</p>
              </div>
            </div>
          </div>
        );

      case AppStep.Obligations:
        return (
          <div className="max-w-6xl mx-auto px-4 py-16">
            <h2 className="text-5xl font-black mb-12 tracking-tighter">Active Obligations</h2>
            <div className="grid gap-6">
              {vault.flatMap(v => v.analysis?.obligations || []).map((ob, i) => (
                <div key={i} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 flex justify-between items-center group hover:border-indigo-200 transition">
                  <div>
                    <div className="flex items-center gap-3 mb-2">
                      <span className="text-[10px] font-black uppercase tracking-widest px-3 py-1 bg-slate-100 rounded-full">{ob.category}</span>
                      {ob.deadline && <span className="text-[10px] font-black text-red-600 uppercase tracking-widest flex items-center gap-1"><i className="fa-solid fa-clock"></i> {ob.deadline}</span>}
                    </div>
                    <p className="font-bold text-slate-800">{ob.requirement}</p>
                  </div>
                  <button className="w-12 h-12 rounded-2xl border-2 border-slate-100 flex items-center justify-center text-slate-200 hover:text-emerald-500 hover:border-emerald-500 transition">
                    <i className="fa-solid fa-check"></i>
                  </button>
                </div>
              ))}
            </div>
          </div>
        );

      default:
        return <div className="text-center py-20 font-black">View Not Implemented</div>;
    }
  };

  return (
    <Layout onNavigate={handleNavigate}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useRef, useState } from 'react';
import { UserPreferences } from '../types';

interface UploadAreaProps {
  onUpload: (files: { base64: string; mimeType: string }[], preferences: UserPreferences) => void;
}

const UploadArea: React.FC<UploadAreaProps> = ({ onUpload }) => {
  const [isDragging, setIsDragging] = useState(false);
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [preferences, setPreferences] = useState<UserPreferences>({
    strictMode: false,
    focusAreas: ['Liability', 'Financial', 'Privacy'],
    languagePreference: 'English',
    secureLocalMode: true,
    playbookRules: ['Always flag arbitration', 'Liability must be capped at 1x deal value']
  });
  const [showPrefs, setShowPrefs] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFiles = (files: FileList | File[]) => {
    const list = Array.from(files);
    setSelectedFiles(prev => [...prev, ...list].slice(0, 10));
  };

  const processUpload = async () => {
    if (selectedFiles.length === 0) return;

    const payloads = await Promise.all(selectedFiles.map(file => {
      return new Promise<{ base64: string; mimeType: string }>((resolve) => {
        const reader = new FileReader();
        reader.onload = (e) => {
          resolve({
            base64: (e.target?.result as string).split(',')[1],
            mimeType: file.type
          });
        };
        reader.readAsDataURL(file);
      });
    }));

    onUpload(payloads, preferences);
  };

  const removeFile = (index: number) => {
    setSelectedFiles(prev => prev.filter((_, i) => i !== index));
  };

  return (
    <div className="space-y-8">
      {/* Dynamic Preferences */}
      <div className="max-w-2xl mx-auto">
        <button 
          onClick={() => setShowPrefs(!showPrefs)}
          className="w-full bg-white p-6 rounded-[2.5rem] border border-slate-200 flex items-center justify-between hover:shadow-lg transition group"
        >
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 transition-transform group-hover:rotate-12">
              <i className="fa-solid fa-gear text-xl"></i>
            </div>
            <div className="text-left">
              <span className="text-xs font-black uppercase tracking-widest text-slate-800">Intelligence Playbook</span>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Configure Personal Legal Constraints</p>
            </div>
          </div>
          <i className={`fa-solid fa-chevron-down text-slate-300 transition-transform ${showPrefs ? 'rotate-180' : ''}`}></i>
        </button>

        {showPrefs && (
          <div className="mt-4 bg-white p-10 rounded-[3rem] border border-slate-200 shadow-2xl animate-in zoom-in-95">
             <div className="space-y-8">
               <div className="flex items-center justify-between p-6 bg-emerald-50 rounded-[2rem] border border-emerald-100">
                  <div>
                    <h4 className="text-sm font-black text-emerald-900 uppercase">Secure Processing Mode</h4>
                    <p className="text-[10px] text-emerald-700 font-bold opacity-70">Masks PII before AI transmission.</p>
                  </div>
                  <input type="checkbox" checked={preferences.secureLocalMode} onChange={e => setPreferences({...preferences, secureLocalMode: e.target.checked})} className="w-6 h-6 rounded-lg text-emerald-600 focus:ring-emerald-500" />
               </div>

               <div>
                 <h4 className="text-xs font-black text-slate-900 uppercase mb-4 tracking-widest">Personal Playbook Rules</h4>
                 <div className="space-y-2">
                   {preferences.playbookRules?.map((rule, i) => (
                     <div key={i} className="flex items-center gap-3 bg-slate-50 px-4 py-2 rounded-xl text-xs font-bold text-slate-600">
                       <i className="fa-solid fa-check text-emerald-500"></i> {rule}
                     </div>
                   ))}
                   <button className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mt-2 hover:underline">+ Add Custom Rule</button>
                 </div>
               </div>
             </div>
          </div>
        )}
      </div>

      <div 
        className={`relative border-[6px] border-dashed rounded-[4rem] p-16 transition-all duration-700 bg-white group shadow-inner cursor-pointer ${
          isDragging ? 'border-indigo-500 bg-indigo-50' : 'border-slate-100 hover:border-indigo-300'
        }`}
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={(e) => {
          e.preventDefault();
          setIsDragging(false);
          handleFiles(e.dataTransfer.files);
        }}
        onClick={() => fileInputRef.current?.click()}
      >
        <input 
          type="file" 
          multiple 
          className="hidden" 
          ref={fileInputRef} 
          onChange={(e) => e.target.files && handleFiles(e.target.files)}
        />

        {selectedFiles.length > 0 ? (
          <div className="space-y-8 text-center" onClick={e => e.stopPropagation()}>
            <h3 className="text-4xl font-black text-slate-900 tracking-tighter uppercase">Document Queue</h3>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              {selectedFiles.map((f, i) => (
                <div key={i} className="bg-slate-50 p-6 rounded-[2rem] border border-slate-200 relative group/file shadow-sm">
                  <i className="fa-solid fa-file-pdf text-4xl text-indigo-600 mb-4"></i>
                  <p className="text-[10px] font-black truncate text-slate-800 px-2">{f.name}</p>
                  <button 
                    onClick={() => removeFile(i)}
                    className="absolute -top-2 -right-2 w-8 h-8 bg-white border-2 border-slate-100 rounded-full text-red-500 flex items-center justify-center opacity-0 group-hover/file:opacity-100 transition shadow-lg"
                  >
                    <i className="fa-solid fa-xmark"></i>
                  </button>
                </div>
              ))}
              {selectedFiles.length < 10 && (
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="bg-white border-2 border-dashed border-slate-200 rounded-[2rem] flex items-center justify-center hover:bg-slate-50 transition p-10"
                >
                  <i className="fa-solid fa-plus text-2xl text-slate-300"></i>
                </button>
              )}
            </div>
            <div className="pt-8">
              <button 
                onClick={processUpload}
                className="bg-indigo-600 text-white px-16 py-6 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl hover:bg-indigo-700 transition active:scale-95"
              >
                Launch Intelligence Suite
              </button>
            </div>
          </div>
        ) : (
          <div className="text-center py-10">
            <div className="w-32 h-32 bg-indigo-600 rounded-[3rem] mx-auto flex items-center justify-center shadow-2xl mb-12 animate-bounce-slow">
              <i className="fa-solid fa-file-shield text-white text-6xl"></i>
            </div>
            <h3 className="text-6xl font-black text-slate-900 mb-6 tracking-tighter">Universal Intake.</h3>
            <p className="text-slate-500 mb-16 max-w-lg mx-auto font-medium text-xl leading-relaxed">Select up to 10 versions or separate documents for batch risk analysis.</p>
            <div className="flex flex-wrap justify-center gap-4">
              <div className="bg-white px-8 py-4 rounded-2xl border border-slate-200 flex items-center gap-3 text-xs font-black text-slate-400">
                <i className="fa-brands fa-google-drive text-blue-500"></i> Drive
              </div>
              <div className="bg-white px-8 py-4 rounded-2xl border border-slate-200 flex items-center gap-3 text-xs font-black text-slate-400">
                <i className="fa-brands fa-dropbox text-blue-400"></i> Dropbox
              </div>
              <div className="bg-white px-8 py-4 rounded-2xl border border-slate-200 flex items-center gap-3 text-xs font-black text-slate-400">
                <i className="fa-solid fa-envelope text-red-400"></i> Email Attachments
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default UploadArea;

import React, { useState, useRef, useEffect } from 'react';
import { ContractAnalysis, ChatMessage, AuditEntry } from '../types';
import RedFlagCard from './RedFlagCard';
import { 
  generateVoiceSummary, 
  decodeBase64, 
  decodeAudioData, 
  chatWithDocument
} from '../services/geminiService';

interface DashboardProps {
  analysis: ContractAnalysis;
  onConfirm: () => void;
  onRestart: () => void;
  onDecline: () => void;
  auditTrail: AuditEntry[];
}

const Dashboard: React.FC<DashboardProps> = ({ analysis, onConfirm, onRestart, onDecline, auditTrail }) => {
  const [activeTab, setActiveTab] = useState<'risk' | 'negotiate' | 'versions' | 'obligations'>('risk');
  const [isGeneratingVoice, setIsGeneratingVoice] = useState(false);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [chatInput, setChatInput] = useState('');
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [isChatLoading, setIsChatLoading] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (chatEndRef.current) chatEndRef.current.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory, isChatOpen]);

  const handleListen = async () => {
    setIsGeneratingVoice(true);
    try {
      const b64 = await generateVoiceSummary(analysis.summary);
      const ctx = new AudioContext();
      const b = await decodeAudioData(decodeBase64(b64), ctx);
      const s = ctx.createBufferSource();
      s.buffer = b; s.connect(ctx.destination); s.start();
    } catch (e) { alert("Audio sync failed."); } finally { setIsGeneratingVoice(false); }
  };

  const handleSendChat = async () => {
    if (!chatInput.trim() || isChatLoading) return;
    setChatHistory(prev => [...prev, { role: 'user', text: chatInput }]);
    setIsChatLoading(true);
    try {
      const r = await chatWithDocument(chatInput, analysis, chatHistory);
      setChatHistory(prev => [...prev, { role: 'model', text: r.text }]);
    } finally { setIsChatLoading(false); setChatInput(''); }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 space-y-8">
      {/* Risk Profile Header */}
      <div className="flex flex-col lg:flex-row gap-8 items-stretch">
        <div className="flex-1 bg-white p-12 rounded-[3.5rem] shadow-sm border border-slate-100 flex items-center gap-12">
          <div className="w-48 h-48 relative flex-shrink-0">
            <svg className="w-full h-full -rotate-90" viewBox="0 0 100 100">
              <circle cx="50" cy="50" r="45" fill="none" stroke="#f1f5f9" strokeWidth="10" />
              <circle cx="50" cy="50" r="45" fill="none" stroke={analysis.signerScore > 70 ? "#10b981" : "#f59e0b"} strokeWidth="10" strokeDasharray={`${analysis.signerScore * 2.82} 282`} strokeLinecap="round" />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center">
              <span className="text-5xl font-black text-slate-900">{analysis.signerScore}</span>
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Signer Score</span>
            </div>
          </div>
          <div>
            <div className="flex items-center gap-3 mb-4">
              <span className="px-3 py-1 bg-indigo-50 text-indigo-700 text-[10px] font-black uppercase tracking-widest rounded-full">Executive Brief</span>
              {analysis.metadata?.tamperRisk !== 'None' && <span className="px-3 py-1 bg-red-50 text-red-700 text-[10px] font-black uppercase tracking-widest rounded-full">Tamper Detected</span>}
            </div>
            <p className="text-2xl font-serif italic text-slate-700 leading-relaxed">"{analysis.summary}"</p>
          </div>
        </div>

        <div className="lg:w-96 bg-slate-900 text-white p-12 rounded-[3.5rem] flex flex-col justify-between shadow-2xl">
          <div className="flex items-center gap-3 mb-8">
            <i className="fa-solid fa-magnifying-glass-chart text-indigo-400 text-2xl"></i>
            <h3 className="text-xl font-black uppercase tracking-tighter">Sentinel View</h3>
          </div>
          <div className="space-y-4">
            <button onClick={handleListen} className="w-full bg-white/10 hover:bg-white/20 py-4 rounded-2xl font-black text-xs uppercase tracking-widest transition flex items-center justify-center gap-3">
              <i className={`fa-solid ${isGeneratingVoice ? 'fa-spinner fa-spin' : 'fa-volume-high'}`}></i>
              Voice Recap
            </button>
            <button onClick={onConfirm} className="w-full bg-indigo-600 hover:bg-indigo-700 py-6 rounded-2xl font-black text-xs uppercase tracking-widest transition shadow-xl active:scale-95">Proceed to Seal</button>
          </div>
        </div>
      </div>

      {/* Main Tabbed Interface */}
      <div className="bg-white rounded-[4rem] shadow-sm border border-slate-100 overflow-hidden">
        <nav className="flex border-b border-slate-100 bg-slate-50/50">
          {[
            { id: 'risk', label: 'Risk Audit', icon: 'fa-shield-halved' },
            { id: 'negotiate', label: 'Negotiation Hub', icon: 'fa-comments-dollar' },
            { id: 'versions', label: 'Version Control', icon: 'fa-code-compare' },
            { id: 'obligations', label: 'Obligations', icon: 'fa-calendar-check' }
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`px-10 py-6 text-xs font-black uppercase tracking-widest flex items-center gap-3 transition ${activeTab === tab.id ? 'bg-white text-indigo-600 border-b-4 border-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}
            >
              <i className={`fa-solid ${tab.icon}`}></i>
              {tab.label}
            </button>
          ))}
        </nav>

        <div className="p-12">
          {activeTab === 'risk' && (
            <div className="grid lg:grid-cols-2 gap-12">
              <div className="space-y-8">
                {analysis.redFlags.map((f, i) => <RedFlagCard key={i} {...f} id={i.toString()} />)}
              </div>
              <div className="bg-slate-50 rounded-[3rem] p-12 border border-slate-200">
                <h4 className="text-xl font-black mb-8 uppercase tracking-tighter text-slate-400">Risk Distribution</h4>
                <div className="relative h-96 w-full flex items-center justify-center">
                   {/* Heatmap Simulation */}
                   <div className="absolute inset-0 grid grid-cols-4 grid-rows-4 gap-4 p-8">
                     {Array.from({length: 16}).map((_, i) => (
                       <div key={i} className={`rounded-2xl transition-all duration-1000 ${i % 3 === 0 ? 'bg-red-500/20 shadow-[0_0_20px_red]' : 'bg-slate-200'}`}></div>
                     ))}
                   </div>
                   <div className="z-10 text-center font-black uppercase text-slate-400 text-[10px] tracking-widest">Scanning metadata patterns...</div>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'negotiate' && (
            <div className="space-y-12 animate-in fade-in duration-500">
              <div className="grid md:grid-cols-3 gap-8">
                <div className="bg-indigo-50 p-10 rounded-[3rem] border border-indigo-100 md:col-span-2">
                  <h4 className="text-2xl font-black text-indigo-900 mb-8 uppercase tracking-tighter">Leverage Points</h4>
                  <ul className="space-y-4">
                    {analysis.negotiation?.leveragePoints.map((p, i) => (
