export const analyzeBatch = async (
  files: { base64: string; mimeType: string }[],
  preferences: UserPreferences
): Promise<ContractAnalysis> => {
  const model = "gemini-3-pro-preview";

  const isComparison = files.length > 1;
  const parts = files.map((f, i) => ({ 
    inlineData: { data: f.base64, mimeType: f.mimeType },
    text: `Document ${i + 1} Source Content`
  }));

  const prompt = `
    Act as an elite Legal Bodyguard & Compliance Auditor. 
    Analyze the provided document(s) for signer protection and hidden risks.

    ${isComparison ? "The user provided multiple document versions. Map the evolution of clauses and flag regressive changes." : "Analyze the contract for traps, fraud indicators, and compliance."}

    USER PLAYBOOK RULES (STRICT ENFORCEMENT): ${preferences.playbookRules?.join('; ') || "None."}
    FOCUS AREAS: ${preferences.focusAreas.join(', ')}

    CHECKLIST FOR AI REASONING:
    1. FRAUD: Look for tampering indicators, inconsistent font/spacing, or suspicious metadata references in text.
    2. PLAYBOOK: Compare every clause against the user's custom rules.
    3. NEGOTIATION: Identify 3 leverage points where the signer has power (e.g. lack of reciprocity, market standards).
    4. OBLIGATIONS: Extract every date and financial commitment with specific deadlines.

    REQUIRED JSON SCHEMA:
    {
      "summary": "Plain language summary of core intent.",
      "signerScore": 0-100,
      "metadata": { 
        "isContract": true, 
        "confidence": 0-1,
        "tamperRisk": "None|Low|High",
        "anomalies": ["Any strange text shifts or missing standard clauses"]
      },
      "parties": [{"name": "string", "role": "string"}],
      "obligations": [{"id": "uuid", "party": "string", "requirement": "string", "deadline": "YYYY-MM-DD", "category": "string"}],
      "financials": { "amount": "string", "totalCommitment": "string", "hiddenFees": ["string"] },
      "redFlags": [{ "issue": "string", "riskLevel": "High|Medium|Low", "originalText": "string", "suggestion": { "counterOffer": "string", "rephrasedClause": "string", "whyItMatters": "string", "strategy": "string" } }],
      "playbookCompliance": [{"rule": "string", "isCompliant": boolean, "deviationDetail": "string", "suggestedCorrection": "string"}],
      "negotiation": {
        "leveragePoints": ["Specific power dynamics the user can exploit"],
        "counterClauses": [{"original": "string", "suggested": "string", "reasoning": "string"}],
        "concessionStrategy": "High-level plan for a better deal"
      },
      ${isComparison ? '"versionDiffs": [{ "clause": "string", "oldValue": "string", "newValue": "string", "changeType": "Addition|Deletion|Modification", "riskImpact": "Better|Worse|Neutral" }],' : ""}
      "verificationQuestion": "Security question about the most critical risk.",
      "expectedResponse": "Concise answer to verify user read it.",
      "fullText": "Full OCR/Text content"
    }
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [...parts as any, { text: prompt }]
    },
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 25000 }
    }
  });

  return JSON.parse(response.text || '{}');
};

