export function decodeBase64(base64: string): Uint8Array {
  const b = atob(base64);
  const u = new Uint8Array(b.length);
  for (let i = 0; i < b.length; i++) u[i] = b.charCodeAt(i);
  return u;
}

export async function decodeAudioData(data: Uint8Array, ctx: AudioContext) {
  const d = new Int16Array(data.buffer);
  const f = d.length;
  const b = ctx.createBuffer(1, f, 24000);
  const c = b.getChannelData(0);
  for (let i = 0; i < f; i++) c[i] = d[i] / 32768.0;
  return b;
}

import React, { useRef, useState } from 'react';
import { UserPreferences } from '../types';

interface UploadAreaProps {
  onUpload: (files: { base64: string; mimeType: string }[], preferences: UserPreferences) => void;
}

const UploadArea: React.FC<UploadAreaProps> = ({ onUpload }) => {
  const [isDragging, setIsDragging] = useState(false);
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [newRule, setNewRule] = useState('');
  const [preferences, setPreferences] = useState<UserPreferences>({
    strictMode: false,
    focusAreas: ['Liability', 'Financial', 'Privacy'],
    languagePreference: 'English',
    secureLocalMode: true,
    playbookRules: ['Liability must be capped at 1x deal value', 'Always flag mandatory arbitration']
  });
  const [showPrefs, setShowPrefs] = useState(false);
  const [showTemplates, setShowTemplates] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFiles = (files: FileList | File[]) => {
    const list = Array.from(files);
    setSelectedFiles(prev => [...prev, ...list].slice(0, 10));
  };

  const processUpload = async () => {
    if (selectedFiles.length === 0) return;
    const payloads = await Promise.all(selectedFiles.map(file => {
      return new Promise<{ base64: string; mimeType: string }>((resolve) => {
        const reader = new FileReader();
        reader.onload = (e) => resolve({ base64: (e.target?.result as string).split(',')[1], mimeType: file.type });
        reader.readAsDataURL(file);
      });
    }));
    onUpload(payloads as any, preferences);
  };

  const addRule = () => {
    if (!newRule.trim()) return;
    setPreferences(prev => ({ ...prev, playbookRules: [...(prev.playbookRules || []), newRule] }));
    setNewRule('');
  };

  const removeRule = (idx: number) => {
    setPreferences(prev => ({ ...prev, playbookRules: prev.playbookRules?.filter((_, i) => i !== idx) }));
  };

  const templates = [
    { name: 'Mutual NDA', icon: 'fa-handshake-simple' },
    { name: 'Independent Contractor Agreement', icon: 'fa-briefcase' },
    { name: 'SaaS Service Agreement', icon: 'fa-cloud' },
    { name: 'Software Licensing', icon: 'fa-code' }
  ];

  return (
    <div className="space-y-8">
      {/* Action Bar */}
      <div className="flex flex-col md:flex-row gap-4 max-w-4xl mx-auto">
        <button 
          onClick={() => setShowPrefs(!showPrefs)}
          className="flex-1 bg-white p-6 rounded-[2.5rem] border border-slate-200 flex items-center justify-between hover:shadow-xl transition group"
        >
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600">
              <i className="fa-solid fa-gavel"></i>
            </div>
            <div className="text-left">
              <span className="text-xs font-black uppercase tracking-widest text-slate-800">Playbook Editor</span>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">{preferences.playbookRules?.length || 0} Custom Rules Active</p>
            </div>
          </div>
          <i className={`fa-solid fa-chevron-down text-slate-300 transition-transform ${showPrefs ? 'rotate-180' : ''}`}></i>
        </button>

        <button 
          onClick={() => setShowTemplates(!showTemplates)}
          className="flex-1 bg-white p-6 rounded-[2.5rem] border border-slate-200 flex items-center justify-between hover:shadow-xl transition group"
        >
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-amber-50 rounded-2xl flex items-center justify-center text-amber-600">
              <i className="fa-solid fa-layer-group"></i>
            </div>
            <div className="text-left">
              <span className="text-xs font-black uppercase tracking-widest text-slate-800">Template Library</span>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Verified Legal Blueprints</p>
            </div>
          </div>
          <i className={`fa-solid fa-chevron-right text-slate-300 transition-transform ${showTemplates ? 'rotate-90' : ''}`}></i>
        </button>
      </div>

      {showPrefs && (
        <div className="max-w-2xl mx-auto bg-white p-10 rounded-[3rem] border border-slate-200 shadow-2xl animate-in zoom-in-95">
           <h4 className="text-xs font-black text-slate-900 uppercase mb-6 tracking-widest">Signer Playbook Constraints</h4>
           <div className="space-y-3 mb-8">
             {preferences.playbookRules?.map((rule, i) => (
               <div key={i} className="flex items-center justify-between bg-slate-50 px-5 py-3 rounded-2xl border border-slate-100 group">
                 <div className="flex items-center gap-3">
                   <i className="fa-solid fa-check text-emerald-500"></i>
                   <span className="text-xs font-bold text-slate-600">{rule}</span>
                 </div>
                 <button onClick={() => removeRule(i)} className="text-slate-300 hover:text-red-500 transition opacity-0 group-hover:opacity-100"><i className="fa-solid fa-trash"></i></button>
               </div>
             ))}
           </div>
           <div className="flex gap-3">
             <input 
              type="text" 
              value={newRule} 
              onChange={e => setNewRule(e.target.value)}
              placeholder="e.g. Jurisdiction must be Delaware..."
              className="flex-1 bg-slate-100 border-none rounded-2xl px-6 py-4 text-xs font-bold focus:ring-4 focus:ring-indigo-500/10"
             />
             <button onClick={addRule} className="bg-slate-900 text-white px-6 py-4 rounded-2xl text-[10px] font-black uppercase">Add Rule</button>
           </div>
        </div>
      )}

      {showTemplates && (
        <div className="max-w-2xl mx-auto grid grid-cols-2 gap-4 animate-in slide-in-from-top-4">
           {templates.map((t, i) => (
             <div key={i} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex items-center gap-4 cursor-pointer hover:border-indigo-400 hover:shadow-lg transition group">
                <div className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-400 group-hover:bg-indigo-50 group-hover:text-indigo-600 transition">
                  <i className={`fa-solid ${t.icon} text-xl`}></i>
                </div>
                <span className="text-xs font-black text-slate-700 uppercase tracking-tight">{t.name}</span>
             </div>
           ))}
        </div>
      )}

      <div 
        className={`relative max-w-4xl mx-auto border-[6px] border-dashed rounded-[4rem] p-16 transition-all duration-700 bg-white group shadow-inner cursor-pointer ${
          isDragging ? 'border-indigo-500 bg-indigo-50' : 'border-slate-100 hover:border-indigo-300'
        }`}
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={(e) => {
          e.preventDefault();
          setIsDragging(false);
          handleFiles(e.dataTransfer.files);
        }}
        onClick={() => fileInputRef.current?.click()}
      >
        <input type="file" multiple className="hidden" ref={fileInputRef} onChange={(e) => e.target.files && handleFiles(e.target.files)} />
        {selectedFiles.length > 0 ? (
          <div className="space-y-8 text-center" onClick={e => e.stopPropagation()}>
            <h3 className="text-4xl font-black text-slate-900 uppercase">Analysis Batch ({selectedFiles.length})</h3>
            <div className="flex flex-wrap justify-center gap-4">
              {selectedFiles.map((f, i) => (
                <div key={i} className="bg-slate-50 px-6 py-4 rounded-2xl border border-slate-200 flex items-center gap-3 relative group/f">
                  <i className="fa-solid fa-file-pdf text-indigo-500"></i>
                  <span className="text-[10px] font-black uppercase text-slate-600">{f.name}</span>
                  <button onClick={() => setSelectedFiles(prev => prev.filter((_, idx) => idx !== i))} className="text-red-300 hover:text-red-500"><i className="fa-solid fa-xmark"></i></button>
                </div>
              ))}
            </div>
            <button onClick={processUpload} className="bg-indigo-600 text-white px-16 py-6 rounded-[2rem] font-black text-xs uppercase tracking-[0.3em] shadow-2xl hover:bg-indigo-700 transition active:scale-95">Analyze Secured Batch</button>
          </div>
        ) : (
          <div className="text-center py-10">
            <div className="w-24 h-24 bg-indigo-600 rounded-[2.5rem] mx-auto flex items-center justify-center shadow-2xl mb-8 animate-bounce-slow">
              <i className="fa-solid fa-shield-halved text-white text-4xl"></i>
            </div>
            <h3 className="text-5xl font-black text-slate-900 mb-6 tracking-tighter">Universal Protective Intake.</h3>
            <p className="text-slate-500 mb-10 max-w-lg mx-auto font-medium text-lg leading-relaxed">Securely ingest PDFs, scans, or handwritten notes. Our AI will automatically detect versioning and contract type.</p>
            <div className="flex items-center justify-center gap-8 text-slate-300">
               <i className="fa-brands fa-google-drive text-3xl hover:text-blue-500 transition"></i>
               <i className="fa-brands fa-dropbox text-3xl hover:text-blue-400 transition"></i>
               <i className="fa-solid fa-camera text-3xl hover:text-amber-500 transition"></i>
               <i className="fa-solid fa-envelope text-3xl hover:text-red-400 transition"></i>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

