import React, { useState, useRef, useEffect } from 'react';
import { ContractAnalysis, ChatMessage, AuditEntry } from '../types';
import RedFlagCard from './RedFlagCard';
import { 
  generateVoiceSummary, 
  decodeBase64, 
  decodeAudioData, 
  chatWithDocument
} from '../services/geminiService';

interface DashboardProps {
  analysis: ContractAnalysis;
  onConfirm: () => void;
  onRestart: () => void;
  onDecline: () => void;
  auditTrail: AuditEntry[];
}

const Dashboard: React.FC<DashboardProps> = ({ analysis, onConfirm, onRestart, onDecline, auditTrail }) => {
  const [activeTab, setActiveTab] = useState<'risk' | 'negotiate' | 'versions' | 'obligations' | 'compliance'>('risk');
  const [isGeneratingVoice, setIsGeneratingVoice] = useState(false);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [chatInput, setChatInput] = useState('');
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [isChatLoading, setIsChatLoading] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (chatEndRef.current) chatEndRef.current.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory, isChatOpen]);

  const handleListen = async () => {
    setIsGeneratingVoice(true);
    try {
      const b64 = await generateVoiceSummary(analysis.summary);
      const ctx = new AudioContext();
      const b = await decodeAudioData(decodeBase64(b64), ctx);
      const s = ctx.createBufferSource();
      s.buffer = b; s.connect(ctx.destination); s.start();
    } catch (e) { alert("Audio briefing interrupted."); } finally { setIsGeneratingVoice(false); }
  };

  const handleSendChat = async () => {
    if (!chatInput.trim() || isChatLoading) return;
    setChatHistory(prev => [...prev, { role: 'user', text: chatInput }]);
    setIsChatLoading(true);
    try {
      const r = await chatWithDocument(chatInput, analysis, chatHistory);
      setChatHistory(prev => [...prev, { role: 'model', text: r.text }]);
    } finally { setIsChatLoading(false); setChatInput(''); }
  };

  const shareReport = () => {
    alert("Report link generated! Copying to clipboard for sharing with external advisors.");
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 space-y-8">
      {/* Risk Profile Header */}
      <div className="flex flex-col lg:flex-row gap-8 items-stretch">
        <div className="flex-1 bg-white p-12 rounded-[3.5rem] shadow-sm border border-slate-100 flex items-center gap-12 relative overflow-hidden">
          {analysis.metadata?.tamperRisk !== 'None' && (
            <div className="absolute top-0 right-0 bg-red-600 text-white px-6 py-2 rounded-bl-3xl flex items-center gap-2 animate-pulse">
              <i className="fa-solid fa-triangle-exclamation"></i>
              <span className="text-[10px] font-black uppercase tracking-widest">Fraud Alert: {analysis.metadata.tamperRisk} Risk</span>
            </div>
          )}
          <div className="w-48 h-48 relative flex-shrink-0">
            <svg className="w-full h-full -rotate-90" viewBox="0 0 100 100">
              <circle cx="50" cy="50" r="45" fill="none" stroke="#f1f5f9" strokeWidth="10" />
              <circle cx="50" cy="50" r="45" fill="none" stroke={analysis.signerScore > 70 ? "#10b981" : analysis.signerScore > 40 ? "#f59e0b" : "#ef4444"} strokeWidth="10" strokeDasharray={`${analysis.signerScore * 2.82} 282`} strokeLinecap="round" />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center">
              <span className="text-5xl font-black text-slate-900">{analysis.signerScore}</span>
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Signer Score</span>
            </div>
          </div>
          <div>
            <div className="flex items-center gap-3 mb-4">
              <span className="px-3 py-1 bg-indigo-50 text-indigo-700 text-[10px] font-black uppercase tracking-widest rounded-full">AI Executive Brief</span>
              <span className="text-[9px] font-bold text-slate-400">Scan Confidence: {Math.round((analysis.metadata?.confidence || 0.9) * 100)}%</span>
            </div>
            <p className="text-2xl font-serif italic text-slate-700 leading-relaxed">"{analysis.summary}"</p>
            {analysis.metadata?.anomalies && analysis.metadata.anomalies.length > 0 && (
              <div className="mt-4 flex gap-2">
                {analysis.metadata.anomalies.map((a, i) => (
                  <span key={i} className="text-[8px] bg-red-50 text-red-600 px-2 py-1 rounded-full font-black uppercase">{a}</span>
                ))}
              </div>
            )}
          </div>
        </div>

        <div className="lg:w-96 bg-slate-900 text-white p-12 rounded-[3.5rem] flex flex-col justify-between shadow-2xl">
          <div className="flex items-center justify-between mb-8">
            <div className="flex items-center gap-3">
              <i className="fa-solid fa-user-ninja text-indigo-400 text-2xl"></i>
              <h3 className="text-xl font-black uppercase tracking-tighter">Guardian</h3>
            </div>
            <button onClick={shareReport} className="text-slate-400 hover:text-white transition"><i className="fa-solid fa-share-nodes"></i></button>
          </div>
          <div className="space-y-4">
            <button onClick={handleListen} className="w-full bg-white/10 hover:bg-white/20 py-4 rounded-2xl font-black text-xs uppercase tracking-widest transition flex items-center justify-center gap-3">
              <i className={`fa-solid ${isGeneratingVoice ? 'fa-spinner fa-spin' : 'fa-volume-high'}`}></i>
              Voice Recap
            </button>
            <button onClick={onConfirm} className="w-full bg-indigo-600 hover:bg-indigo-700 py-6 rounded-2xl font-black text-xs uppercase tracking-widest transition shadow-xl active:scale-95">Proceed to Verify</button>
          </div>
        </div>
      </div>

      {/* Navigation */}
      <div className="bg-white rounded-[4rem] shadow-sm border border-slate-100 overflow-hidden">
        <nav className="flex border-b border-slate-100 bg-slate-50/50 overflow-x-auto whitespace-nowrap">
          {[
            { id: 'risk', label: 'Risk Audit', icon: 'fa-shield-halved' },
            { id: 'negotiate', label: 'Negotiation Simulator', icon: 'fa-comments-dollar' },
            { id: 'compliance', label: 'Playbook Alignment', icon: 'fa-gavel' },
            { id: 'versions', label: 'Version Diff', icon: 'fa-code-compare' },
            { id: 'obligations', label: 'Obligation Tracker', icon: 'fa-calendar-check' }
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`px-8 py-6 text-[10px] font-black uppercase tracking-widest flex items-center gap-3 transition ${activeTab === tab.id ? 'bg-white text-indigo-600 border-b-4 border-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}
            >
              <i className={`fa-solid ${tab.icon}`}></i>
              {tab.label}
            </button>
          ))}
        </nav>

        <div className="p-12">
          {activeTab === 'risk' && (
            <div className="grid lg:grid-cols-2 gap-12">
              <div className="space-y-8">
                {analysis.redFlags.map((f, i) => <RedFlagCard key={i} {...f} id={i.toString()} />)}
              </div>
              <div className="bg-slate-50 rounded-[3rem] p-12 border border-slate-200">
                <h4 className="text-xl font-black mb-8 uppercase tracking-tighter text-slate-400">Clause Intensity Heatmap</h4>
                <div className="relative h-96 w-full flex items-center justify-center bg-slate-900 rounded-3xl overflow-hidden p-8">
                   <div className="absolute inset-0 grid grid-cols-5 grid-rows-5 gap-2 opacity-40">
                     {Array.from({length: 25}).map((_, i) => (
                       <div key={i} className={`rounded-lg transition-all duration-2000 ${i % 4 === 0 ? 'bg-red-500 shadow-[0_0_15px_red]' : 'bg-slate-700'}`}></div>
                     ))}
                   </div>
                   <div className="z-10 text-center font-black uppercase text-indigo-400 text-[10px] tracking-[0.5em] animate-pulse">Scanning Structural Bias...</div>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'negotiate' && (
            <div className="space-y-12 animate-in fade-in">
              <div className="grid md:grid-cols-3 gap-8">
                <div className="bg-indigo-50 p-10 rounded-[3rem] border border-indigo-100 md:col-span-2">
                  <h4 className="text-2xl font-black text-indigo-900 mb-8 uppercase tracking-tighter flex items-center gap-4">
                    <i className="fa-solid fa-chess-knight"></i> Signer Leverage
                  </h4>
                  <ul className="grid md:grid-cols-2 gap-4">
                    {analysis.negotiation?.leveragePoints.map((p, i) => (
                      <li key={i} className="flex gap-4 items-center bg-white p-6 rounded-3xl shadow-sm border border-indigo-200">
                        <i className="fa-solid fa-circle-check text-indigo-600"></i>
                        <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{p}</p>
                      </li>
                    ))}
                  </ul>
                </div>
                <div className="bg-slate-900 text-white p-10 rounded-[3rem] shadow-2xl relative overflow-hidden">
                  <div className="absolute top-[-20%] right-[-20%] w-48 h-48 bg-indigo-600/20 blur-[60px] rounded-full"></div>
                  <h4 className="text-xl font-black mb-6 uppercase tracking-widest text-emerald-400">Concession Map</h4>
                  <p className="text-sm font-medium leading-relaxed opacity-80 italic">"{analysis.negotiation?.concessionStrategy}"</p>
                </div>
              </div>

              <div className="space-y-8">
                <h4 className="text-xl font-black uppercase tracking-widest text-slate-400">Simulator Proposals</h4>
                <div className="grid gap-6">
                  {analysis.negotiation?.counterClauses.map((c, i) => (
                    <div key={i} className="bg-white border border-slate-200 rounded-[3rem] p-10 shadow-sm flex flex-col md:flex-row gap-10 hover:border-indigo-400 transition">
                      <div className="flex-1 opacity-40">
                        <span className="text-[10px] font-black uppercase text-red-600 mb-2 block tracking-widest">Target Clause</span>
                        <p className="text-xs font-serif italic line-through">"{c.original}"</p>
                      </div>
                      <div className="flex-[2]">
                        <span className="text-[10px] font-black uppercase text-emerald-600 mb-2 block tracking-widest">Signer-Fair Proposal</span>
                        <p className="text-base font-serif font-bold text-slate-900 mb-6 leading-relaxed">"{c.suggested}"</p>
                        <div className="bg-slate-50 p-6 rounded-2xl border border-slate-100 flex items-start gap-4">
                           <i className="fa-solid fa-lightbulb text-indigo-500 mt-1"></i>
                           <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-relaxed">Reasoning: {c.reasoning}</p>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}

          {activeTab === 'compliance' && (
            <div className="space-y-8 animate-in zoom-in-95">
               <h4 className="text-2xl font-black text-slate-900 tracking-tighter uppercase mb-8">Playbook Compliance Audit</h4>
               <div className="grid gap-4">
                 {analysis.playbookCompliance?.map((rule, i) => (
                   <div key={i} className={`p-8 rounded-[2.5rem] border-2 flex items-center justify-between transition-all ${rule.isCompliant ? 'bg-emerald-50 border-emerald-100' : 'bg-red-50 border-red-100 shadow-lg'}`}>
                     <div className="flex-1">
                       <div className="flex items-center gap-3 mb-2">
                         <i className={`fa-solid ${rule.isCompliant ? 'fa-check-circle text-emerald-600' : 'fa-times-circle text-red-600'} text-xl`}></i>
                         <span className="text-xs font-black uppercase text-slate-900 tracking-widest">{rule.rule}</span>
                       </div>
                       {!rule.isCompliant && (
                         <div className="ml-8 space-y-4">
                           <p className="text-xs text-red-700 font-medium">Deviation: {rule.deviationDetail}</p>
                           <div className="bg-white p-4 rounded-xl border border-red-200">
                             <span className="text-[8px] font-black uppercase text-red-500 block mb-1">Aligned Correction</span>
                             <p className="text-xs font-serif italic text-slate-800">{rule.suggestedCorrection}</p>
                           </div>
                         </div>
                       )}
                     </div>
                     <span className={`px-4 py-1.5 rounded-full text-[8px] font-black uppercase tracking-widest ${rule.isCompliant ? 'bg-emerald-200 text-emerald-800' : 'bg-red-600 text-white animate-pulse'}`}>
                       {rule.isCompliant ? 'Compliant' : 'Deviation'}
                     </span>
                   </div>
                 ))}
               </div>
            </div>
          )}

          {activeTab === 'versions' && (
            <div className="space-y-8 animate-in slide-in-from-right-10">
              {analysis.versionDiffs ? (
                <div className="grid gap-8">
                  {analysis.versionDiffs.map((d, i) => (
                    <div key={i} className="bg-slate-50 p-10 rounded-[3rem] border border-slate-200 shadow-inner">
                      <div className="flex justify-between items-center mb-8">
                        <h5 className="text-xs font-black uppercase tracking-widest text-slate-900">{d.clause}</h5>
                        <div className="flex gap-2">
                          <span className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest bg-white border ${d.riskImpact === 'Better' ? 'text-emerald-600 border-emerald-100' : d.riskImpact === 'Worse' ? 'text-red-600 border-red-100' : 'text-slate-400 border-slate-100'}`}>
                            {d.riskImpact} Impact
                          </span>
                        </div>
                      </div>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        {d.oldValue && (
                          <div className="bg-white p-6 rounded-2xl border border-slate-100 opacity-50 relative">
                             <span className="absolute -top-3 left-4 bg-slate-200 px-2 py-0.5 rounded text-[8px] font-black uppercase">Previous</span>
                             <p className="text-xs text-slate-600 line-through italic leading-relaxed">"{d.oldValue}"</p>
                          </div>
                        )}
                        <div className="bg-white p-6 rounded-2xl border-2 border-indigo-500 shadow-2xl relative">
                           <span className="absolute -top-3 left-4 bg-indigo-600 text-white px-2 py-0.5 rounded text-[8px] font-black uppercase tracking-widest animate-pulse">Updated</span>
                           <p className="text-xs text-slate-900 font-bold leading-relaxed">"{d.newValue || d.clause}"</p>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="text-center py-20 bg-slate-100 rounded-[3rem] border-2 border-dashed border-slate-200">
                  <i className="fa-solid fa-code-merge text-7xl text-slate-200 mb-8"></i>
                  <h3 className="text-2xl font-black text-slate-400">Multiple files required for Comparison analysis.</h3>
                </div>
              )}
            </div>
          )}

          {activeTab === 'obligations' && (
            <div className="space-y-8 animate-in slide-in-from-bottom-6">
               <h4 className="text-2xl font-black text-slate-900 tracking-tighter uppercase mb-8">Critical Reminders & Commitments</h4>
               <div className="grid md:grid-cols-2 gap-8">
                 {analysis.obligations.map((ob, i) => (
                   <div key={i} className="bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-sm flex items-start justify-between group hover:border-indigo-400 transition">
                     <div className="flex-1">
                       <span className="text-[10px] font-black uppercase tracking-[0.3em] text-indigo-500 mb-4 inline-block">{ob.category}</span>
                       <h5 className="text-base font-bold text-slate-800 mb-6 leading-tight">{ob.requirement}</h5>
                       <div className="flex items-center gap-6">
                         {ob.deadline && (
                           <div className="flex items-center gap-2 text-red-600 font-black text-[10px] uppercase tracking-widest bg-red-50 px-4 py-1.5 rounded-full">
                             <i className="fa-solid fa-bell animate-swing"></i>
                             Expiry: {ob.deadline}
                           </div>
                         )}
                         <button className="text-[10px] font-black text-slate-400 uppercase tracking-widest hover:text-indigo-600 transition flex items-center gap-2">
                           <i className="fa-solid fa-calendar-plus"></i> Add to iCal
                         </button>
                       </div>
                     </div>
                     <button className="w-12 h-12 rounded-2xl border border-slate-100 flex items-center justify-center text-slate-200 group-hover:text-emerald-500 transition shadow-inner">
                       <i className="fa-solid fa-circle-check text-2xl"></i>
                     </button>
                   </div>
                 ))}
               </div>
            </div>
          )}
        </div>
      </div>

      {/* Floating Chat Companion (RAG cited responses) */}
      <div className={`fixed bottom-8 right-8 z-[100] transition-all duration-500 ${isChatOpen ? 'w-[450px]' : 'w-20 h-20'}`}>
        {isChatOpen ? (
          <div className="bg-white rounded-[4rem] shadow-[0_50px_100px_rgba(0,0,0,0.5)] border border-slate-200 h-[750px] flex flex-col overflow-hidden animate-in zoom-in-95">
            <div className="bg-slate-900 p-10 text-white flex justify-between items-center relative overflow-hidden">
               <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-600/20 blur-[60px] rounded-full"></div>
               <div className="flex items-center gap-4 relative z-10">
                 <div className="w-16 h-16 bg-indigo-600 rounded-3xl flex items-center justify-center shadow-xl">
                   <i className="fa-solid fa-robot text-3xl"></i>
                 </div>
                 <div>
                   <h4 className="font-black text-sm uppercase tracking-tighter">Sentinel Chat</h4>
                   <p className="text-[9px] font-black uppercase text-emerald-400 animate-pulse tracking-widest">Document Sync Live</p>
                 </div>
               </div>
               <button onClick={() => setIsChatOpen(false)} className="text-slate-500 hover:text-white transition relative z-10"><i className="fa-solid fa-circle-chevron-down text-4xl"></i></button>
            </div>
            <div className="flex-1 overflow-y-auto p-10 space-y-10 bg-slate-50/30">
               {chatHistory.length === 0 && (
                 <div className="h-full flex flex-col items-center justify-center text-center px-12 opacity-30">
                   <i className="fa-solid fa-book-open-reader text-8xl mb-10"></i>
                   <p className="text-xs font-black uppercase tracking-[0.5em]">Ask anything about your agreement.</p>
                 </div>
               )}
               {chatHistory.map((m, i) => (
                 <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                   <div className={`max-w-[85%] px-10 py-6 rounded-[3rem] text-sm leading-relaxed shadow-xl ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-br-none' : 'bg-white text-slate-800 border border-slate-100 rounded-bl-none font-medium'}`}>
                     {m.text}
                   </div>
                 </div>
               ))}
               {isChatLoading && <div className="text-[10px] font-black text-slate-300 animate-pulse tracking-[0.4em] uppercase text-center">Referencing Legal Corpus...</div>}
               <div ref={chatEndRef}></div>
            </div>
            <div className="p-10 bg-white border-t border-slate-100">
               <div className="relative">
                 <input 
                  type="text" 
                  value={chatInput} 
                  onChange={e => setChatInput(e.target.value)} 
                  onKeyPress={e => e.key === 'Enter' && handleSendChat()} 
                  placeholder="Query your document..." 
                  className="w-full bg-slate-100 border-none rounded-full py-6 pl-10 pr-20 text-sm font-black tracking-tight focus:ring-8 focus:ring-indigo-500/10 outline-none transition shadow-inner"
                 />
                 <button onClick={handleSendChat} className="absolute right-4 top-4 w-12 h-12 bg-indigo-600 text-white rounded-full flex items-center justify-center shadow-xl active:scale-90 transition"><i className="fa-solid fa-paper-plane text-xs"></i></button>
               </div>
            </div>
          </div>
        ) : (
          <button onClick={() => setIsChatOpen(true)} className="w-24 h-24 bg-slate-900 text-white rounded-[3rem] flex items-center justify-center shadow-2xl hover:scale-110 hover:shadow-indigo-500/50 transition-all duration-300 group border-[6px] border-white">
            <i className="fa-solid fa-user-shield text-4xl group-hover:rotate-12 transition"></i>
            <div className="absolute -top-1 -right-1 w-8 h-8 bg-indigo-600 border-4 border-white rounded-full flex items-center justify-center text-[10px] font-black animate-ping"></div>
          </button>
        )}
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import UploadArea from './components/UploadArea';
import Dashboard from './components/Dashboard';
import ContractCreator from './components/ContractCreator';
import SignaturePad from './components/SignaturePad';
import { analyzeBatch, classifyUpload, generateContractContent } from './services/geminiService';
import { AppStep, ContractAnalysis, ContractHistoryItem, UserPreferences, AuditEntry, VerificationMethod } from './types';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.Upload);
  const [analysis, setAnalysis] = useState<ContractAnalysis | null>(null);
  const [generatedContent, setGeneratedContent] = useState<string>('');
  const [loadingMessage, setLoadingMessage] = useState('Sentinel Shield Activating...');
  const [vault, setVault] = useState<ContractHistoryItem[]>([]);
  const [signature, setSignature] = useState<string | null>(null);
  const [currentAuditTrail, setCurrentAuditTrail] = useState<AuditEntry[]>([]);
  const [verificationMethod, setVerificationMethod] = useState<VerificationMethod>('Standard');
  const [currentPreferences, setCurrentPreferences] = useState<UserPreferences>({
    strictMode: false,
    focusAreas: ['Liability', 'Financial', 'Privacy'],
    languagePreference: 'English',
    playbookRules: []
  });

  useEffect(() => {
    const savedVault = localStorage.getItem('signwise_vault_v3');
    if (savedVault) setVault(JSON.parse(savedVault));
  }, []);

  const addToAudit = (event: string, details: string) => {
    setCurrentAuditTrail(prev => [...prev, { event, timestamp: new Date().toISOString(), details }]);
  };

  const handleUpload = async (files: { base64: string; mimeType: string }[], preferences: UserPreferences) => {
    setStep(AppStep.Analyzing);
    setCurrentPreferences(preferences);
    addToAudit("Batch Intake", `${files.length} files. Mode: ${preferences.secureLocalMode ? 'Secure' : 'Standard'}`);

    try {
      if (files.length === 1) {
        const classification = await classifyUpload(files[0].base64, files[0].mimeType);
        if (classification.intent === 'CREATE') {
          const content = await generateContractContent(files[0].base64, files[0].mimeType);
          setGeneratedContent(content);
          setStep(AppStep.Creator);
          return;
        }
      }
      const result = await analyzeBatch(files, preferences);
      setAnalysis(result);
      addToAudit("Analysis Ready", `Score: ${result.signerScore}. Detections: ${result.redFlags.length}`);
      setStep(AppStep.Dashboard);
    } catch (e) {
      alert("AI Sentinel encountered a structural document error.");
      setStep(AppStep.Upload);
    }
  };

  const finalizeDocument = (status: 'Signed' | 'Declined') => {
    const newItem: ContractHistoryItem = {
      id: Math.random().toString(36).substr(2, 9),
      name: `Contract_${new Date().toLocaleDateString()}`,
      date: new Date().toLocaleDateString(),
      type: analysis?.metadata?.isContract ? 'Formal Agreement' : 'Document Analysis',
      status,
      summary: analysis?.summary || "No summary available.",
      analysis: analysis || undefined,
      auditTrail: [...currentAuditTrail, { event: status, timestamp: new Date().toISOString(), details: `Final decision recorded. Method: ${verificationMethod}` }],
      signatureData: signature || undefined
    };
    const updated = [newItem, ...vault];
    setVault(updated);
    localStorage.setItem('signwise_vault_v3', JSON.stringify(updated));
    setStep(AppStep.Vault);
  };

  const renderContent = () => {
    switch (step) {
      case AppStep.Upload:
        return (
          <div className="max-w-6xl mx-auto px-4 py-20">
            <div className="text-center mb-20 animate-in fade-in slide-in-from-bottom-10">
              <span className="inline-block px-6 py-2 bg-indigo-50 text-indigo-700 text-[10px] font-black uppercase tracking-[0.3em] rounded-full mb-10 border border-indigo-100 shadow-sm">Protective Intel v3.5</span>
              <h1 className="text-7xl md:text-9xl font-black text-slate-900 mb-10 tracking-tighter leading-none">Your Legal <span className="text-indigo-600">Shield.</span></h1>
