import React, { useRef, useState } from 'react';
import { UserPreferences } from '../types';

interface UploadAreaProps {
  onUpload: (files: { base64: string; mimeType: string }[], preferences: UserPreferences) => void;
}

const UploadArea: React.FC<UploadAreaProps> = ({ onUpload }) => {
  const [isDragging, setIsDragging] = useState(false);
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [newRule, setNewRule] = useState('');
  const [preferences, setPreferences] = useState<UserPreferences>({
    strictMode: false,
    focusAreas: ['Liability', 'Financial', 'Privacy'],
    languagePreference: 'English',
    secureLocalMode: true,
    playbookRules: ['Liability must be capped at 1x deal value', 'Always flag mandatory arbitration']
  });
  const [showPrefs, setShowPrefs] = useState(false);
  const [showTemplates, setShowTemplates] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFiles = (files: FileList | File[]) => {
    const list = Array.from(files);
    setSelectedFiles(prev => [...prev, ...list].slice(0, 10));
  };

  const processUpload = async () => {
    if (selectedFiles.length === 0) return;
    const payloads = await Promise.all(selectedFiles.map(file => {
      return new Promise<{ base64: string; mimeType: string }>((resolve) => {
        const reader = new FileReader();
        reader.onload = (e) => resolve({ base64: (e.target?.result as string).split(',')[1], mimeType: file.type });
        reader.readAsDataURL(file);
      });
    }));
    onUpload(payloads as any, preferences);
  };

  const addRule = () => {
    if (!newRule.trim()) return;
    setPreferences(prev => ({ ...prev, playbookRules: [...(prev.playbookRules || []), newRule] }));
    setNewRule('');
  };

  const removeRule = (idx: number) => {
    setPreferences(prev => ({ ...prev, playbookRules: prev.playbookRules?.filter((_, i) => i !== idx) }));
  };

  const templates = [
    { name: 'Mutual NDA', icon: 'fa-handshake-simple' },
    { name: 'Freelance Agreement', icon: 'fa-briefcase' },
    { name: 'Rental Lease', icon: 'fa-house-user' },
    { name: 'SaaS Terms', icon: 'fa-cloud' }
  ];

  const handleCloudConnect = (provider: string) => {
    alert(`Connecting to ${provider}... OAuth simulation initiated.`);
  };

  return (
    <div className="space-y-8 max-w-5xl mx-auto">
      {/* Dynamic Action Bar */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <button 
          onClick={() => setShowPrefs(!showPrefs)}
          className="bg-white p-8 rounded-[3rem] border border-slate-200 flex items-center justify-between hover:shadow-xl transition group text-left"
        >
          <div className="flex items-center gap-5">
            <div className="w-12 h-12 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600 transition-transform group-hover:rotate-12">
              <i className="fa-solid fa-gavel"></i>
            </div>
            <div>
              <span className="text-xs font-black uppercase tracking-widest text-slate-800">Playbook Engine</span>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">{preferences.playbookRules?.length || 0} Custom Constraints Active</p>
            </div>
          </div>
          <i className={`fa-solid fa-chevron-down text-slate-300 transition-transform ${showPrefs ? 'rotate-180' : ''}`}></i>
        </button>

        <button 
          onClick={() => setShowTemplates(!showTemplates)}
          className="bg-white p-8 rounded-[3rem] border border-slate-200 flex items-center justify-between hover:shadow-xl transition group text-left"
        >
          <div className="flex items-center gap-5">
            <div className="w-12 h-12 bg-amber-50 rounded-2xl flex items-center justify-center text-amber-600 transition-transform group-hover:rotate-12">
              <i className="fa-solid fa-layer-group"></i>
            </div>
            <div>
              <span className="text-xs font-black uppercase tracking-widest text-slate-800">Template Vault</span>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Pre-Vetted Legal Blueprints</p>
            </div>
          </div>
          <i className={`fa-solid fa-chevron-right text-slate-300 transition-transform ${showTemplates ? 'rotate-90' : ''}`}></i>
        </button>
      </div>

      {showPrefs && (
        <div className="bg-white p-10 rounded-[3rem] border border-slate-200 shadow-2xl animate-in zoom-in-95">
           <h4 className="text-xs font-black text-slate-900 uppercase mb-6 tracking-widest">Signer Constraints</h4>
           <div className="space-y-3 mb-8">
             {preferences.playbookRules?.map((rule, i) => (
               <div key={i} className="flex items-center justify-between bg-slate-50 px-5 py-3 rounded-2xl border border-slate-100 group">
                 <div className="flex items-center gap-3">
                   <i className="fa-solid fa-check text-emerald-500"></i>
                   <span className="text-xs font-bold text-slate-600">{rule}</span>
                 </div>
                 <button onClick={() => removeRule(i)} className="text-slate-300 hover:text-red-500 transition opacity-0 group-hover:opacity-100"><i className="fa-solid fa-trash"></i></button>
               </div>
             ))}
           </div>
           <div className="flex gap-3">
             <input 
              type="text" 
              value={newRule} 
              onChange={e => setNewRule(e.target.value)}
              placeholder="e.g. Always flag 24 month terms..."
              className="flex-1 bg-slate-100 border-none rounded-2xl px-6 py-4 text-xs font-bold focus:ring-4 focus:ring-indigo-500/10"
             />
             <button onClick={addRule} className="bg-slate-900 text-white px-8 py-4 rounded-2xl text-[10px] font-black uppercase">Add</button>
           </div>
        </div>
      )}

      {showTemplates && (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 animate-in slide-in-from-top-4">
           {templates.map((t, i) => (
             <div key={i} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm flex flex-col items-center gap-4 cursor-pointer hover:border-indigo-400 hover:shadow-2xl transition group">
                <div className="w-16 h-16 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-300 group-hover:bg-indigo-50 group-hover:text-indigo-600 transition shadow-inner">
                  <i className={`fa-solid ${t.icon} text-3xl`}></i>
                </div>
                <span className="text-[10px] font-black text-slate-800 uppercase tracking-tight text-center">{t.name}</span>
             </div>
           ))}
        </div>
      )}

      {/* Cloud Integration Buttons */}
      <div className="flex justify-center gap-4">
        <button onClick={() => handleCloudConnect('Google Drive')} className="bg-white px-6 py-3 rounded-2xl border border-slate-200 text-xs font-black text-slate-500 hover:border-blue-400 transition flex items-center gap-3">
          <i className="fa-brands fa-google-drive text-blue-500 text-lg"></i> Drive
        </button>
        <button onClick={() => handleCloudConnect('Dropbox')} className="bg-white px-6 py-3 rounded-2xl border border-slate-200 text-xs font-black text-slate-500 hover:border-blue-400 transition flex items-center gap-3">
          <i className="fa-brands fa-dropbox text-blue-600 text-lg"></i> Dropbox
        </button>
        <button onClick={() => handleCloudConnect('OneDrive')} className="bg-white px-6 py-3 rounded-2xl border border-slate-200 text-xs font-black text-slate-500 hover:border-blue-400 transition flex items-center gap-3">
          <i className="fa-solid fa-cloud text-sky-500 text-lg"></i> OneDrive
        </button>
      </div>

      <div 
        className={`relative border-[6px] border-dashed rounded-[4rem] p-16 transition-all duration-700 bg-white group shadow-inner cursor-pointer ${
          isDragging ? 'border-indigo-500 bg-indigo-50' : 'border-slate-100 hover:border-indigo-300'
        }`}
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={(e) => {
          e.preventDefault();
          setIsDragging(false);
          handleFiles(e.dataTransfer.files);
        }}
        onClick={() => fileInputRef.current?.click()}
      >
        <input type="file" multiple className="hidden" ref={fileInputRef} onChange={(e) => e.target.files && handleFiles(e.target.files)} />
        {selectedFiles.length > 0 ? (
          <div className="space-y-8 text-center" onClick={e => e.stopPropagation()}>
            <h3 className="text-5xl font-black text-slate-900 uppercase tracking-tighter">Analysis Batch ({selectedFiles.length})</h3>
            <div className="flex flex-wrap justify-center gap-4">
              {selectedFiles.map((f, i) => (
                <div key={i} className="bg-slate-50 px-6 py-4 rounded-2xl border border-slate-200 flex items-center gap-3 relative group/f shadow-sm">
                  <i className="fa-solid fa-file-pdf text-indigo-500"></i>
                  <span className="text-[10px] font-black uppercase text-slate-600 truncate max-w-[120px]">{f.name}</span>
                  <button onClick={() => setSelectedFiles(prev => prev.filter((_, idx) => idx !== i))} className="text-red-300 hover:text-red-500 transition"><i className="fa-solid fa-circle-xmark"></i></button>
                </div>
              ))}
              {selectedFiles.length < 10 && (
                <button onClick={() => fileInputRef.current?.click()} className="bg-white border-2 border-dashed border-slate-100 rounded-2xl px-6 py-4 text-slate-300 hover:text-indigo-400 transition">
                  <i className="fa-solid fa-plus-circle"></i>
                </button>
              )}
            </div>
            <button onClick={processUpload} className="bg-indigo-600 text-white px-20 py-8 rounded-[2.5rem] font-black text-xs uppercase tracking-[0.4em] shadow-[0_30px_60px_rgba(79,70,229,0.3)] hover:bg-indigo-700 transition active:scale-95">Analyze Protective Batch</button>
          </div>
        ) : (
          <div className="text-center py-10">
            <div className="w-24 h-24 bg-indigo-600 rounded-[2.5rem] mx-auto flex items-center justify-center shadow-2xl mb-12 animate-bounce-slow">
              <i className="fa-solid fa-shield-halved text-white text-4xl"></i>
            </div>
            <h3 className="text-6xl font-black text-slate-900 mb-6 tracking-tighter leading-none">Universal <span className="text-indigo-600">Secure</span> Intake.</h3>
            <p className="text-slate-500 mb-16 max-w-lg mx-auto font-medium text-xl leading-relaxed">Securely ingest PDFs, scans, or handwritten notes. Multi-file uploads auto-detect version history.</p>
            <div className="flex items-center justify-center gap-10 text-slate-300">
               <div className="flex flex-col items-center gap-2 group cursor-default">
                  <i className="fa-brands fa-google-drive text-4xl group-hover:text-blue-500 transition-all"></i>
                  <span className="text-[8px] font-black uppercase">Drive</span>
               </div>
               <div className="flex flex-col items-center gap-2 group cursor-default">
                  <i className="fa-brands fa-dropbox text-4xl group-hover:text-blue-400 transition-all"></i>
                  <span className="text-[8px] font-black uppercase">Dropbox</span>
               </div>
               <div className="flex flex-col items-center gap-2 group cursor-default">
                  <i className="fa-solid fa-camera text-4xl group-hover:text-amber-500 transition-all"></i>
                  <span className="text-[8px] font-black uppercase">Mobile Scan</span>
               </div>
               <div className="flex flex-col items-center gap-2 group cursor-default">
                  <i className="fa-solid fa-envelope text-4xl group-hover:text-red-400 transition-all"></i>
                  <span className="text-[8px] font-black uppercase">Email Link</span>
               </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default UploadArea;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import UploadArea from './components/UploadArea';
import Dashboard from './components/Dashboard';
import ContractCreator from './components/ContractCreator';
import SignaturePad from './components/SignaturePad';
import { analyzeBatch, classifyUpload, generateContractContent } from './services/geminiService';
import { AppStep, ContractAnalysis, ContractHistoryItem, UserPreferences, AuditEntry, VerificationMethod } from './types';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.Upload);
  const [analysis, setAnalysis] = useState<ContractAnalysis | null>(null);
  const [generatedContent, setGeneratedContent] = useState<string>('');
  const [loadingMessage, setLoadingMessage] = useState('Sentinel Shield Activating...');
  const [vault, setVault] = useState<ContractHistoryItem[]>([]);
  const [signature, setSignature] = useState<string | null>(null);
  const [currentAuditTrail, setCurrentAuditTrail] = useState<AuditEntry[]>([]);
  const [verificationMethod, setVerificationMethod] = useState<VerificationMethod>('Standard');
  const [currentPreferences, setCurrentPreferences] = useState<UserPreferences>({
    strictMode: false,
    focusAreas: ['Liability', 'Financial', 'Privacy'],
    languagePreference: 'English',
    playbookRules: []
  });

  useEffect(() => {
    const savedVault = localStorage.getItem('signwise_vault_v4');
    if (savedVault) setVault(JSON.parse(savedVault));
  }, []);

  const addToAudit = (event: string, details: string) => {
    setCurrentAuditTrail(prev => [...prev, { event, timestamp: new Date().toISOString(), details }]);
  };

  const handleUpload = async (files: { base64: string; mimeType: string }[], preferences: UserPreferences) => {
    setStep(AppStep.Analyzing);
    setCurrentPreferences(preferences);
    addToAudit("Batch Intake", `${files.length} documents securely processed.`);

    try {
      if (files.length === 1) {
        const classification = await classifyUpload(files[0].base64, files[0].mimeType);
        if (classification.intent === 'CREATE') {
          setLoadingMessage("Architecting Protective Draft...");
          const content = await generateContractContent(files[0].base64, files[0].mimeType);
          setGeneratedContent(content);
          setStep(AppStep.Creator);
          return;
        }
      }
      setLoadingMessage("Auditing Forensics & Playbook...");
      const result = await analyzeBatch(files, preferences);
      setAnalysis(result);
      addToAudit("Audit Complete", `Safety Score: ${result.signerScore}.`);
      setStep(AppStep.Dashboard);
    } catch (e) {
      alert("Structural failure in analysis. Ensure files are legible.");
      setStep(AppStep.Upload);
    }
  };

  const finalizeDocument = (status: 'Signed' | 'Declined') => {
    const newItem: ContractHistoryItem = {
      id: Math.random().toString(36).substr(2, 9),
      name: `Signed_Audit_${new Date().toLocaleDateString().replace(/\//g, '_')}`,
      date: new Date().toLocaleDateString(),
      type: 'Protective Audit',
      status,
      summary: analysis?.summary || "Direct drafting session.",
      analysis: analysis || undefined,
      auditTrail: [...currentAuditTrail, { event: status, timestamp: new Date().toISOString(), details: `Identity Verified via ${verificationMethod}` }],
      signatureData: signature || undefined
    };
    const updated = [newItem, ...vault];
    setVault(updated);
    localStorage.setItem('signwise_vault_v4', JSON.stringify(updated));
    setStep(AppStep.Vault);
  };

  const renderContent = () => {
    switch (step) {
      case AppStep.Upload:
        return (
          <div className="max-w-7xl mx-auto px-4 py-20">
            <div className="text-center mb-24 animate-in fade-in slide-in-from-bottom-12 duration-1000">
              <span className="inline-block px-6 py-2 bg-indigo-50 text-indigo-700 text-[10px] font-black uppercase tracking-[0.4em] rounded-full mb-12 border border-indigo-100 shadow-sm">v4.0 Enterprise Suite</span>
              <h1 className="text-7xl md:text-9xl font-black text-slate-900 mb-12 tracking-tighter leading-[0.85]">Your Legal <span className="text-indigo-600">Guardian.</span></h1>
              <p className="text-2xl text-slate-500 max-w-4xl mx-auto leading-relaxed font-medium">Batch audit, detect forensic anomalies, and simulate negotiations with the first signer-first AI intelligence hub.</p>
            </div>
            <UploadArea onUpload={handleUpload} />
          </div>
        );

      case AppStep.Analyzing:
        return (
          <div className="flex flex-col items-center justify-center min-h-[70vh] animate-in zoom-in-95 duration-700">
            <div className="relative w-80 h-80">
               <div className="absolute inset-0 border-x-[12px] border-indigo-600 rounded-full animate-spin"></div>
               <div className="absolute inset-0 border-y-[12px] border-slate-100 rounded-full"></div>
               <div className="absolute inset-12 bg-white rounded-full shadow-2xl flex items-center justify-center">
                  <i className="fa-solid fa-user-shield text-indigo-600 text-7xl animate-pulse"></i>
               </div>
            </div>
            <h2 className="text-4xl font-black mt-20 text-slate-900 tracking-[0.2em] uppercase">{loadingMessage}</h2>
            <p className="text-slate-400 font-bold mt-4 uppercase text-[10px] tracking-[0.5em]">AES-256 Vaulting Protocol Engaged</p>
          </div>
        );

      case AppStep.Dashboard:
        return <Dashboard 
          analysis={analysis!} 
          onRestart={() => setStep(AppStep.Upload)} 
          onDecline={() => finalizeDocument('Declined')}
          onConfirm={() => setStep(AppStep.Verification)} 
          auditTrail={currentAuditTrail}
        />;

      case AppStep.Verification:
        return (
          <div className="max-w-4xl mx-auto px-4 py-24 animate-in zoom-in-95">
             <div className="bg-white p-20 rounded-[4rem] shadow-2xl border border-slate-100 text-center relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-2 bg-indigo-600"></div>
                <i className="fa-solid fa-fingerprint text-indigo-600 text-8xl mb-12"></i>
                <h2 className="text-5xl font-black text-slate-900 mb-8 tracking-tighter">Identity Assurance</h2>
                <p className="text-slate-500 mb-16 max-w-lg mx-auto font-medium text-lg leading-relaxed">Required enhanced verification for this legally binding audit trail.</p>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-16">
                   {(['Standard', 'Biometric', 'Behavioral'] as VerificationMethod[]).map(method => (
                     <button 
                       key={method}
                       onClick={() => setVerificationMethod(method)}
                       className={`p-10 rounded-[3rem] border-[3px] transition-all duration-300 flex flex-col items-center gap-6 ${verificationMethod === method ? 'border-indigo-600 bg-indigo-50 shadow-2xl scale-105' : 'border-slate-50 hover:border-slate-200'}`}
                     >
                       <div className={`w-16 h-16 rounded-3xl flex items-center justify-center text-3xl ${verificationMethod === method ? 'bg-indigo-600 text-white' : 'bg-slate-50 text-slate-300'}`}>
                         <i className={`fa-solid ${method === 'Standard' ? 'fa-id-card' : method === 'Biometric' ? 'fa-eye' : 'fa-brain'}`}></i>
                       </div>
                       <span className={`text-xs font-black uppercase tracking-widest ${verificationMethod === method ? 'text-indigo-900' : 'text-slate-400'}`}>{method}</span>
                     </button>
                   ))}
                </div>
                <button 
                  onClick={() => setStep(AppStep.Signing)}
                  className="bg-slate-900 text-white px-20 py-8 rounded-[2.5rem] font-black text-xs uppercase tracking-[0.4em] hover:bg-indigo-600 transition shadow-2xl active:scale-95"
                >
                  Verify & Proceed
                </button>
             </div>
          </div>
        );

      case AppStep.Signing:
        return (
          <div className="max-w-4xl mx-auto px-4 py-24">
             <div className="bg-white p-20 rounded-[4rem] shadow-2xl border border-slate-100">
                <h2 className="text-5xl font-black text-slate-900 mb-12 tracking-tighter uppercase text-center leading-none">Apply Protected <span className="text-indigo-600">Seal</span></h2>
                <SignaturePad onSign={setSignature} onClear={() => setSignature(null)} />
                <button 
                  disabled={!signature}
                  onClick={() => finalizeDocument('Signed')}
                  className={`w-full py-8 rounded-[2.5rem] font-black text-xs uppercase tracking-[0.4em] mt-12 transition shadow-2xl ${signature ? 'bg-indigo-600 text-white hover:bg-indigo-700' : 'bg-slate-100 text-slate-300 cursor-not-allowed'}`}
                >
                  Confirm Audited Signature
                </button>
             </div>
          </div>
        );

      case AppStep.Vault:
        return (
          <div className="max-w-7xl mx-auto px-4 py-20">
             <div className="flex justify-between items-end mb-20">
                <div>
                  <h2 className="text-8xl font-black text-slate-900 tracking-tighter">Vault.</h2>
                  <p className="text-slate-400 font-bold uppercase text-xs tracking-[0.5em] mt-6 flex items-center gap-3">
                    <i className="fa-solid fa-shield-check text-emerald-500"></i> Encrypted Signer-Only Access
                  </p>
                </div>
                <div className="flex gap-4">
                  <button onClick={() => setStep(AppStep.Analytics)} className="bg-white border border-slate-200 text-slate-700 px-8 py-4 rounded-[2rem] font-black text-xs uppercase tracking-widest hover:bg-slate-50 transition">Analytics</button>
                  <button onClick={() => setStep(AppStep.Upload)} className="bg-indigo-600 text-white px-10 py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl hover:bg-indigo-700 transition">New Audit</button>
                </div>
             </div>

             <div className="grid gap-6">
               {vault.map(item => (
                 <div key={item.id} className="bg-white p-12 rounded-[4rem] border border-slate-100 shadow-sm flex items-center justify-between group hover:shadow-[0_40px_80px_rgba(0,0,0,0.1)] transition-all cursor-pointer" onClick={() => { if(item.analysis) { setAnalysis(item.analysis); setStep(AppStep.Dashboard); } }}>
                    <div className="flex items-center gap-12">
                       <div className={`w-24 h-24 rounded-[3rem] flex items-center justify-center text-4xl ${item.status === 'Signed' ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
                          <i className={`fa-solid ${item.status === 'Signed' ? 'fa-signature' : 'fa-ban'}`}></i>
                       </div>
                       <div>
                          <h4 className="text-3xl font-black text-slate-900 tracking-tighter mb-2">{item.name}</h4>
                          <div className="flex gap-6">
                            <span className="text-xs font-black text-slate-400 uppercase tracking-widest">{item.date}</span>
                            <span className={`text-xs font-black uppercase tracking-widest ${item.status === 'Signed' ? 'text-emerald-500' : 'text-red-500'}`}>{item.status}</span>
                            {item.analysis?.metadata?.tamperRisk === 'High' && <span className="text-xs font-black text-red-600 animate-pulse uppercase"><i className="fa-solid fa-triangle-exclamation mr-2"></i>Anomaly Alert</span>}
                          </div>
                       </div>
                    </div>
                    <div className="flex gap-4 opacity-0 group-hover:opacity-100 transition duration-500 translate-x-10 group-hover:translate-x-0">
                       <button className="w-14 h-14 bg-slate-50 text-slate-400 rounded-3xl hover:bg-indigo-600 hover:text-white transition shadow-sm"><i className="fa-solid fa-download"></i></button>
                       <button className="w-14 h-14 bg-slate-50 text-slate-400 rounded-3xl hover:bg-indigo-600 hover:text-white transition shadow-sm"><i className="fa-solid fa-comment-dots"></i></button>
                    </div>
                 </div>
               ))}
               {vault.length === 0 && (
                 <div className="bg-slate-50 border-4 border-dashed border-slate-100 rounded-[5rem] p-32 text-center">
                    <i className="fa-solid fa-box-archive text-8xl text-slate-200 mb-10"></i>
                    <h3 className="text-3xl font-black text-slate-300 uppercase tracking-widest">Vault Empty</h3>
                 </div>
               )}
             </div>
          </div>
        );

      case AppStep.Analytics:
        return (
          <div className="max-w-7xl mx-auto px-4 py-24 animate-in slide-in-from-bottom-12">
            <h2 className="text-8xl font-black mb-16 tracking-tighter">Insights.</h2>
            <div className="grid md:grid-cols-3 gap-10">
               <div className="bg-white p-12 rounded-[4rem] shadow-sm border border-slate-100 md:col-span-2">
                  <h4 className="text-lg font-black uppercase tracking-widest text-slate-400 mb-12">Risk Trends Over Time</h4>
                  <div className="h-80 w-full flex items-end gap-6 p-8 bg-slate-50 rounded-[3rem] shadow-inner relative overflow-hidden">
                    <div className="absolute inset-0 grid grid-cols-12 gap-1 opacity-5">
                      {Array.from({length: 144}).map((_, i) => <div key={i} className="bg-indigo-900"></div>)}
                    </div>
                    {[40, 65, 30, 85, 45, 95, 20].map((h, i) => (
                      <div key={i} className="flex-1 bg-indigo-600 rounded-t-2xl relative group" style={{ height: `${h}%` }}>
                        <div className="absolute -top-10 left-1/2 -translate-x-1/2 opacity-0 group-hover:opacity-100 bg-slate-900 text-white text-[10px] px-3 py-1 rounded font-black transition">Score: {h}</div>
                      </div>
                    ))}
                  </div>
                  <div className="flex justify-between mt-8 px-4 text-[10px] font-black uppercase text-slate-400 tracking-[0.3em]">
                    <span>Jan</span><span>Mar</span><span>May</span><span>Jul</span><span>Sep</span><span>Nov</span>
                  </div>
               </div>
               <div className="bg-slate-900 text-white p-12 rounded-[4rem] shadow-2xl flex flex-col justify-between">
                  <div>
                    <h4 className="text-sm font-black text-emerald-400 uppercase tracking-widest mb-10">Top Hazards Found</h4>
                    <div className="space-y-8">
                       {[
                         { label: 'Indemnity Traps', count: 12 },
                         { label: 'Auto-Renewal', count: 8 },
                         { label: 'Arbitration', count: 15 }
                       ].map((item, i) => (
                         <div key={i} className="flex justify-between items-center border-b border-white/10 pb-4">
                           <span className="text-xs font-bold">{item.label}</span>
                           <span className="text-xl font-black">{item.count}</span>
                         </div>
                       ))}
                    </div>
                  </div>
                  <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-relaxed">Playbook Rule Alignment: 92% Compliance</p>
               </div>
            </div>
          </div>
        );

      case AppStep.Obligations:
        return (
          <div className="max-w-7xl mx-auto px-4 py-24 animate-in slide-in-from-bottom-12">
            <h2 className="text-8xl font-black mb-16 tracking-tighter text-red-600">Pending.</h2>
            <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
               {vault.flatMap(v => v.analysis?.obligations || []).map((ob, i) => (
                 <div key={i} className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-xl flex flex-col justify-between group hover:border-red-500 transition-all">
                    <div>
                      <div className="flex justify-between items-start mb-6">
                        <span className="text-[10px] font-black uppercase text-red-500 tracking-widest bg-red-50 px-4 py-1 rounded-full">{ob.category}</span>
                        <i className="fa-solid fa-clock-rotate-left text-slate-200 group-hover:text-red-300 transition"></i>
                      </div>
                      <h4 className="text-xl font-black text-slate-900 mb-4">{ob.requirement}</h4>
                    </div>
                    <div className="pt-8 border-t border-slate-50 mt-8 flex justify-between items-center">
                       <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Due: {ob.deadline || 'TBD'}</span>
                       <button className="text-[10px] font-black text-indigo-600 uppercase tracking-widest hover:underline">Mark Meta</button>
                    </div>
                 </div>
               ))}
               {vault.flatMap(v => v.analysis?.obligations || []).length === 0 && (
                 <div className="col-span-full py-32 text-center text-slate-300 font-black uppercase tracking-[0.5em] opacity-30">
                    No active obligations found.
                 </div>
               )}
            </div>
          </div>
        );

      case AppStep.Creator:
        return <ContractCreator initialContent={generatedContent} onConfirm={(c) => { setGeneratedContent(c); setStep(AppStep.Verification); }} onRestart={() => setStep(AppStep.Upload)} />;

      default:
        return <div className="text-center py-20 font-black">Feature Buffered...</div>;
    }
  };

  return (
    <Layout onNavigate={(v: any) => {
      const stepKey = v === 'analytics' ? 'Analytics' : v === 'vault' ? 'Vault' : v === 'upload' ? 'Upload' : 'Upload';
      setStep(AppStep[stepKey as keyof typeof AppStep] || AppStep.Upload);
    }}>
      {renderContent()}
    </Layout>
  );
};

export default App;

export interface AuditEntry {
  event: string;
  timestamp: string;
  details: string;
}

export interface Obligation {
  id: string;
  party: string;
  requirement: string;
  deadline?: string;
  status: 'Pending' | 'Met' | 'Overdue';
  category: string;
}

export interface VersionDiff {
  clause: string;
  oldValue?: string;
  newValue?: string;
  changeType: 'Addition' | 'Deletion' | 'Modification';
  riskImpact: 'Better' | 'Worse' | 'Neutral';
}

export interface NegotiationStrategy {
  leveragePoints: string[];
  counterClauses: { original: string; suggested: string; reasoning: string }[];
  concessionStrategy: string;
}

export interface PlaybookCompliance {
  rule: string;
  isCompliant: boolean;
  deviationDetail?: string;
  suggestedCorrection?: string;
}

export interface Comment {
  id: string;
  author: string;
  text: string;
  timestamp: string;
  clauseId?: string;
}

export interface ContractAnalysis {
  summary: string;
  signerScore: number;
  keywords: string[];
  parties: { name: string; role: string }[];
  obligations: Obligation[];
  keyTerms: {
    title: string;
    value: string;
    category: 'Financial' | 'Termination' | 'Privacy' | 'Liability' | 'Duration' | 'Parties' | 'Obligations';
  }[];
  redFlags: {
    id: string;
    issue: string;
    riskLevel: 'High' | 'Medium' | 'Low';
    suggestion: {
      whyItMatters: string;
      strategy: string;
      counterOffer: string;
      rephrasedClause: string;
      renegotiationKeywords: string[];
      tacticalTips: string[];
    };
    originalText: string;
  }[];
  financials: {
    amount: string;
    frequency: string;
    totalCommitment: string;
    hiddenFees: string[];
  };
  industryComparison: { metric: string; assessment: string; isStandard: boolean }[];
  verificationQuestion: string;
  expectedResponse: string;
  negotiation?: NegotiationStrategy;
  versionDiffs?: VersionDiff[];
  playbookCompliance?: PlaybookCompliance[];
  fullText?: string;
  detectedLanguage?: string;
  comments?: Comment[];
  metadata?: {
    isContract: boolean;
    confidence: number;
    tamperRisk: 'None' | 'Low' | 'High';
    anomalies: string[];
    expiryDates: { date: string; type: string }[];
  };
}

export interface UserPreferences {
  strictMode: boolean;
  focusAreas: string[];
  languagePreference: string;
  secureLocalMode?: boolean;
  playbookRules?: string[]; // Custom rules like "Always flag no-compete"
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  citations?: string[];
}

export interface ClassificationResult {
  intent: 'REVIEW' | 'CREATE' | 'COMPARE';
  reasoning: string;
  suggestedFileName?: string;
}

export interface ContractHistoryItem {
  id: string;
  name: string;
  date: string;
  type: string;
  status: 'Signed' | 'Declined' | 'Draft' | 'Archived';
  summary: string;
  analysis?: ContractAnalysis;
  content?: string;
  auditTrail: AuditEntry[];
  signatureData?: string;
}

export enum AppStep {
  Upload,
  Analyzing,
  Dashboard,
  Creator,
  Signing,
  Verification,
  Finalized,
  Vault,
  Privacy,
  Terms,
  Pricing,
  Help,
  Analytics,
  Obligations,
  Collaboration,
  Auth
}

export type VerificationMethod = 'Biometric' | 'Behavioral' | 'Standard';

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import UploadArea from './components/UploadArea';
import Dashboard from './components/Dashboard';
import ContractCreator from './components/ContractCreator';
import SignaturePad from './components/SignaturePad';
import { analyzeBatch, classifyUpload, generateContractContent } from './services/geminiService';
import { AppStep, ContractAnalysis, ContractHistoryItem, UserPreferences, AuditEntry, VerificationMethod } from './types';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.Upload);
  const [analysis, setAnalysis] = useState<ContractAnalysis | null>(null);
  const [generatedContent, setGeneratedContent] = useState<string>('');
  const [loadingMessage, setLoadingMessage] = useState('Sentinel Shield Activating...');
  const [vault, setVault] = useState<ContractHistoryItem[]>([]);
  const [signature, setSignature] = useState<string | null>(null);
  const [currentAuditTrail, setCurrentAuditTrail] = useState<AuditEntry[]>([]);
  const [verificationMethod, setVerificationMethod] = useState<VerificationMethod>('Standard');
  const [currentPreferences, setCurrentPreferences] = useState<UserPreferences>({
    strictMode: false,
    focusAreas: ['Liability', 'Financial', 'Privacy'],
    languagePreference: 'English',
    playbookRules: []
  });

  useEffect(() => {
    const savedVault = localStorage.getItem('signwise_vault_v4');
    if (savedVault) setVault(JSON.parse(savedVault));
  }, []);

  const addToAudit = (event: string, details: string) => {
    setCurrentAuditTrail(prev => [...prev, { event, timestamp: new Date().toISOString(), details }]);
  };

  const handleUpload = async (files: { base64: string; mimeType: string }[], preferences: UserPreferences) => {
    setStep(AppStep.Analyzing);
    setCurrentPreferences(preferences);
    addToAudit("Batch Intake", `${files.length} documents securely processed.`);

    try {
      if (files.length === 1) {
        const classification = await classifyUpload(files[0].base64, files[0].mimeType);
        if (classification.intent === 'CREATE') {
          setLoadingMessage("Architecting Protective Draft...");
          const content = await generateContractContent(files[0].base64, files[0].mimeType);
          setGeneratedContent(content);
          setStep(AppStep.Creator);
          return;
        }
      }
      setLoadingMessage("Auditing Forensics & Playbook...");
      const result = await analyzeBatch(files, preferences);
      setAnalysis(result);
      addToAudit("Audit Complete", `Safety Score: ${result.signerScore}.`);
      setStep(AppStep.Dashboard);
    } catch (e) {
      alert("Structural failure in analysis. Ensure files are legible.");
      setStep(AppStep.Upload);
    }
  };

  const finalizeDocument = (status: 'Signed' | 'Declined') => {
    const newItem: ContractHistoryItem = {
      id: Math.random().toString(36).substr(2, 9),
      name: `Signed_Audit_${new Date().toLocaleDateString().replace(/\//g, '_')}`,
      date: new Date().toLocaleDateString(),
      type: 'Protective Audit',
      status,
      summary: analysis?.summary || "Direct drafting session.",
      analysis: analysis || undefined,
      auditTrail: [...currentAuditTrail, { event: status, timestamp: new Date().toISOString(), details: `Identity Verified via ${verificationMethod}` }],
      signatureData: signature || undefined
    };
    const updated = [newItem, ...vault];
    setVault(updated);
    localStorage.setItem('signwise_vault_v4', JSON.stringify(updated));
    setStep(AppStep.Vault);
  };

  const handleNavigate = (v: string) => {
    const routeMap: Record<string, AppStep> = {
      upload: AppStep.Upload,
      vault: AppStep.Vault,
      analytics: AppStep.Analytics,
      pricing: AppStep.Pricing,
      help: AppStep.Help,
      privacy: AppStep.Privacy,
      terms: AppStep.Terms,
      auth: AppStep.Auth
    };
    setStep(routeMap[v] || AppStep.Upload);
    window.scrollTo(0, 0);
  };

  const renderContent = () => {
    switch (step) {
      case AppStep.Upload:
        return (
          <div className="max-w-7xl mx-auto px-4 py-20">
            <div className="text-center mb-24 animate-in fade-in slide-in-from-bottom-12 duration-1000">
              <span className="inline-block px-6 py-2 bg-indigo-50 text-indigo-700 text-[10px] font-black uppercase tracking-[0.4em] rounded-full mb-12 border border-indigo-100 shadow-sm">v4.0 Enterprise Suite</span>
              <h1 className="text-7xl md:text-9xl font-black text-slate-900 mb-12 tracking-tighter leading-[0.85]">Your Legal <span className="text-indigo-600">Guardian.</span></h1>
              <p className="text-2xl text-slate-500 max-w-4xl mx-auto leading-relaxed font-medium">Batch audit, detect forensic anomalies, and simulate negotiations with the first signer-first AI intelligence hub.</p>
            </div>
            <UploadArea onUpload={handleUpload} />
          </div>
        );

      case AppStep.Analyzing:
        return (
          <div className="flex flex-col items-center justify-center min-h-[70vh] animate-in zoom-in-95 duration-700">
            <div className="relative w-80 h-80">
               <div className="absolute inset-0 border-x-[12px] border-indigo-600 rounded-full animate-spin"></div>
               <div className="absolute inset-0 border-y-[12px] border-slate-100 rounded-full"></div>
               <div className="absolute inset-12 bg-white rounded-full shadow-2xl flex items-center justify-center">
                  <i className="fa-solid fa-user-shield text-indigo-600 text-7xl animate-pulse"></i>
               </div>
            </div>
            <h2 className="text-4xl font-black mt-20 text-slate-900 tracking-[0.2em] uppercase">{loadingMessage}</h2>
            <p className="text-slate-400 font-bold mt-4 uppercase text-[10px] tracking-[0.5em]">AES-256 Vaulting Protocol Engaged</p>
          </div>
        );

      case AppStep.Dashboard:
        return <Dashboard 
          analysis={analysis!} 
          onRestart={() => setStep(AppStep.Upload)} 
          onDecline={() => finalizeDocument('Declined')}
          onConfirm={() => setStep(AppStep.Verification)} 
          auditTrail={currentAuditTrail}
        />;

      case AppStep.Verification:
        return (
          <div className="max-w-4xl mx-auto px-4 py-24 animate-in zoom-in-95">
             <div className="bg-white p-20 rounded-[4rem] shadow-2xl border border-slate-100 text-center relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-2 bg-indigo-600"></div>
                <i className="fa-solid fa-fingerprint text-indigo-600 text-8xl mb-12"></i>
                <h2 className="text-5xl font-black text-slate-900 mb-8 tracking-tighter">Identity Assurance</h2>
                <p className="text-slate-500 mb-16 max-w-lg mx-auto font-medium text-lg leading-relaxed">Required enhanced verification for this legally binding audit trail.</p>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-16">
                   {(['Standard', 'Biometric', 'Behavioral'] as VerificationMethod[]).map(method => (
                     <button 
                       key={method}
                       onClick={() => setVerificationMethod(method)}
                       className={`p-10 rounded-[3rem] border-[3px] transition-all duration-300 flex flex-col items-center gap-6 ${verificationMethod === method ? 'border-indigo-600 bg-indigo-50 shadow-2xl scale-105' : 'border-slate-50 hover:border-slate-200'}`}
                     >
                       <div className={`w-16 h-16 rounded-3xl flex items-center justify-center text-3xl ${verificationMethod === method ? 'bg-indigo-600 text-white' : 'bg-slate-50 text-slate-300'}`}>
                         <i className={`fa-solid ${method === 'Standard' ? 'fa-id-card' : method === 'Biometric' ? 'fa-eye' : 'fa-brain'}`}></i>
                       </div>
                       <span className={`text-xs font-black uppercase tracking-widest ${verificationMethod === method ? 'text-indigo-900' : 'text-slate-400'}`}>{method}</span>
                     </button>
                   ))}
                </div>
                <button 
                  onClick={() => setStep(AppStep.Signing)}
                  className="bg-slate-900 text-white px-20 py-8 rounded-[2.5rem] font-black text-xs uppercase tracking-[0.4em] hover:bg-indigo-600 transition shadow-2xl active:scale-95"
                >
                  Verify & Proceed
                </button>
             </div>
          </div>
        );

      case AppStep.Signing:
        return (
          <div className="max-w-4xl mx-auto px-4 py-24">
             <div className="bg-white p-20 rounded-[4rem] shadow-2xl border border-slate-100">
                <h2 className="text-5xl font-black text-slate-900 mb-12 tracking-tighter uppercase text-center leading-none">Apply Protected <span className="text-indigo-600">Seal</span></h2>
                <SignaturePad onSign={setSignature} onClear={() => setSignature(null)} />
                <button 
                  disabled={!signature}
                  onClick={() => finalizeDocument('Signed')}
                  className={`w-full py-8 rounded-[2.5rem] font-black text-xs uppercase tracking-[0.4em] mt-12 transition shadow-2xl ${signature ? 'bg-indigo-600 text-white hover:bg-indigo-700' : 'bg-slate-100 text-slate-300 cursor-not-allowed'}`}
                >
                  Confirm Audited Signature
                </button>
             </div>
          </div>
        );

      case AppStep.Vault:
        return (
          <div className="max-w-7xl mx-auto px-4 py-20">
             <div className="flex justify-between items-end mb-20">
                <div>
                  <h2 className="text-8xl font-black text-slate-900 tracking-tighter">Vault.</h2>
                  <p className="text-slate-400 font-bold uppercase text-xs tracking-[0.5em] mt-6 flex items-center gap-3">
                    <i className="fa-solid fa-shield-check text-emerald-500"></i> Encrypted Signer-Only Access
                  </p>
                </div>
                <div className="flex gap-4">
                  <button onClick={() => setStep(AppStep.Analytics)} className="bg-white border border-slate-200 text-slate-700 px-8 py-4 rounded-[2rem] font-black text-xs uppercase tracking-widest hover:bg-slate-50 transition">Analytics</button>
                  <button onClick={() => setStep(AppStep.Upload)} className="bg-indigo-600 text-white px-10 py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl hover:bg-indigo-700 transition">New Audit</button>
                </div>
             </div>

             <div className="grid gap-6">
               {vault.map(item => (
                 <div key={item.id} className="bg-white p-12 rounded-[4rem] border border-slate-100 shadow-sm flex items-center justify-between group hover:shadow-[0_40px_80px_rgba(0,0,0,0.1)] transition-all cursor-pointer" onClick={() => { if(item.analysis) { setAnalysis(item.analysis); setStep(AppStep.Dashboard); } }}>
                    <div className="flex items-center gap-12">
                       <div className={`w-24 h-24 rounded-[3rem] flex items-center justify-center text-4xl ${item.status === 'Signed' ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
                          <i className={`fa-solid ${item.status === 'Signed' ? 'fa-signature' : 'fa-ban'}`}></i>
                       </div>
                       <div>
                          <h4 className="text-3xl font-black text-slate-900 tracking-tighter mb-2">{item.name}</h4>
                          <div className="flex gap-6">
                            <span className="text-xs font-black text-slate-400 uppercase tracking-widest">{item.date}</span>
                            <span className={`text-xs font-black uppercase tracking-widest ${item.status === 'Signed' ? 'text-emerald-500' : 'text-red-500'}`}>{item.status}</span>
                          </div>
                       </div>
                    </div>
                    <div className="flex gap-4 opacity-0 group-hover:opacity-100 transition duration-500">
                       <button className="w-14 h-14 bg-slate-50 text-slate-400 rounded-3xl hover:bg-indigo-600 hover:text-white transition shadow-sm"><i className="fa-solid fa-download"></i></button>
                       <button className="w-14 h-14 bg-slate-50 text-slate-400 rounded-3xl hover:bg-indigo-600 hover:text-white transition shadow-sm"><i className="fa-solid fa-comment-dots"></i></button>
                    </div>
                 </div>
               ))}
               {vault.length === 0 && (
                 <div className="bg-slate-50 border-4 border-dashed border-slate-100 rounded-[5rem] p-32 text-center">
                    <i className="fa-solid fa-box-archive text-8xl text-slate-200 mb-10"></i>
                    <h3 className="text-3xl font-black text-slate-300 uppercase tracking-widest">Vault Empty</h3>
                 </div>
               )}
             </div>
          </div>
        );

      case AppStep.Analytics:
        return (
          <div className="max-w-7xl mx-auto px-4 py-24 animate-in slide-in-from-bottom-12">
            <h2 className="text-8xl font-black mb-16 tracking-tighter">Insights.</h2>
            <div className="grid md:grid-cols-3 gap-10">
               <div className="bg-white p-12 rounded-[4rem] shadow-sm border border-slate-100 md:col-span-2">
                  <h4 className="text-lg font-black uppercase tracking-widest text-slate-400 mb-12">Risk Trends Over Time</h4>
                  <div className="h-80 w-full flex items-end gap-6 p-8 bg-slate-50 rounded-[3rem] shadow-inner relative overflow-hidden">
                    <div className="absolute inset-0 grid grid-cols-12 gap-1 opacity-5">
                      {Array.from({length: 144}).map((_, i) => <div key={i} className="bg-indigo-900"></div>)}
                    </div>
                    {[40, 65, 30, 85, 45, 95, 20].map((h, i) => (
                      <div key={i} className="flex-1 bg-indigo-600 rounded-t-2xl relative group" style={{ height: `${h}%` }}>
                        <div className="absolute -top-10 left-1/2 -translate-x-1/2 opacity-0 group-hover:opacity-100 bg-slate-900 text-white text-[10px] px-3 py-1 rounded font-black transition">Score: {h}</div>
                      </div>
                    ))}
                  </div>
               </div>
               <div className="bg-slate-900 text-white p-12 rounded-[4rem] shadow-2xl flex flex-col justify-between">
                  <div>
                    <h4 className="text-sm font-black text-emerald-400 uppercase tracking-widest mb-10">Top Hazards Found</h4>
                    <div className="space-y-8">
                       {[{ label: 'Indemnity Traps', count: 12 }, { label: 'Auto-Renewal', count: 8 }, { label: 'Arbitration', count: 15 }].map((item, i) => (
                         <div key={i} className="flex justify-between items-center border-b border-white/10 pb-4">
                           <span className="text-xs font-bold">{item.label}</span>
                           <span className="text-xl font-black">{item.count}</span>
                         </div>
                       ))}
                    </div>
                  </div>
               </div>
            </div>
          </div>
        );

      case AppStep.Pricing:
        return (
          <div className="max-w-7xl mx-auto px-4 py-24">
            <div className="text-center mb-16">
              <h2 className="text-6xl font-black text-slate-900 mb-6 tracking-tighter">Pick Your Shield.</h2>
              <p className="text-xl text-slate-500 font-medium">Protect your signatures with AI-driven intelligence.</p>
            </div>
            <div className="grid md:grid-cols-3 gap-8">
              {[
                { name: 'Guardian', price: '$0', features: ['3 Scans / Mo', 'Basic Risk Audit', 'Standard E-Sign'], color: 'bg-white text-slate-900' },
                { name: 'Sentinel Pro', price: '$29', features: ['Unlimited Scans', 'Negotiation Simulator', 'Batch Processing', 'Advanced Forensics'], color: 'bg-indigo-600 text-white', featured: true },
                { name: 'Enterprise', price: 'Custom', features: ['White-Labeling', 'API Access', 'Playbook Integration', 'Bulk Vaulting'], color: 'bg-slate-900 text-white' }
              ].map((plan, i) => (
                <div key={i} className={`${plan.color} p-12 rounded-[4rem] border border-slate-200 shadow-xl flex flex-col ${plan.featured ? 'scale-105' : ''}`}>
                  <h3 className="text-2xl font-black mb-2 uppercase tracking-tighter">{plan.name}</h3>
                  <div className="text-5xl font-black mb-8">{plan.price}<span className="text-sm font-normal opacity-50">/mo</span></div>
                  <ul className="space-y-4 mb-12 flex-grow">
                    {plan.features.map((f, j) => (
                      <li key={j} className="flex items-center gap-3 text-sm font-medium">
                        <i className="fa-solid fa-check-circle opacity-50"></i> {f}
                      </li>
                    ))}
                  </ul>
                  <button className={`w-full py-5 rounded-2xl font-black uppercase text-xs tracking-widest ${plan.featured ? 'bg-white text-indigo-600' : 'bg-slate-900 text-white'}`}>Select Plan</button>
                </div>
              ))}
            </div>
          </div>
        );

      case AppStep.Privacy:
      case AppStep.Terms:
        const isPrivacy = step === AppStep.Privacy;
        return (
          <div className="max-w-4xl mx-auto px-4 py-24">
            <h2 className="text-5xl font-black mb-12 tracking-tighter text-slate-900">{isPrivacy ? 'Privacy Policy' : 'Terms of Service'}</h2>
            <div className="prose prose-slate prose-xl font-medium text-slate-600 space-y-8">
              <p>Last updated: June 2024</p>
              <section>
                <h3 className="text-2xl font-black text-slate-900 mb-4 uppercase tracking-widest">1. Introduction</h3>
                <p>Welcome to SignWise AI. We take your security and rights as a signer extremely seriously. This document outlines how we operate and handle your data.</p>
              </section>
              <section>
                <h3 className="text-2xl font-black text-slate-900 mb-4 uppercase tracking-widest">2. Data Security</h3>
                <p>All document processing is performed using AES-256 encryption. We utilize transient memory sessions that purge your full document text immediately after analysis unless you explicitly save it to your Vault.</p>
              </section>
              <section>
                <h3 className="text-2xl font-black text-slate-900 mb-4 uppercase tracking-widest">3. AI Disclaimers</h3>
                <p>SignWise AI provides intelligence assistance and risk detection. It is NOT a substitute for professional legal advice. Users are responsible for their final signature decisions.</p>
              </section>
            </div>
            <button onClick={() => setStep(AppStep.Upload)} className="mt-16 bg-slate-900 text-white px-10 py-5 rounded-2xl font-black uppercase text-xs tracking-widest">Return to Scans</button>
          </div>
        );

      case AppStep.Help:
        return (
          <div className="max-w-5xl mx-auto px-4 py-24">
            <div className="grid md:grid-cols-2 gap-16">
              <div>
                <h2 className="text-5xl font-black mb-8 tracking-tighter">Support.</h2>
                <div className="space-y-6">
                  {[
                    { q: "Is my document stored?", a: "Documents are only stored if you explicitly save them to your encrypted Vault." },
                    { q: "Can I use it for business?", a: "Yes, our Sentinel Pro and Enterprise plans are designed for high-volume corporate auditing." },
                    { q: "Is the analysis legally binding?", a: "No, the analysis is for information purposes to help you negotiate better terms." }
                  ].map((faq, i) => (
                    <details key={i} className="bg-white border border-slate-100 rounded-3xl p-6 group cursor-pointer shadow-sm">
                      <summary className="font-black text-slate-900 uppercase tracking-widest text-xs list-none flex justify-between items-center">
                        {faq.q}
                        <i className="fa-solid fa-chevron-down text-slate-300 group-open:rotate-180 transition-transform"></i>
                      </summary>
                      <p className="mt-4 text-slate-600 text-sm font-medium leading-relaxed">{faq.a}</p>
                    </details>
                  ))}
                </div>
              </div>
              <div className="bg-slate-900 rounded-[4rem] p-12 text-white">
                <h3 className="text-2xl font-black mb-8 uppercase tracking-widest text-indigo-400">API Documentation</h3>
                <pre className="bg-slate-800 p-6 rounded-3xl overflow-x-auto text-xs font-mono text-emerald-400 shadow-inner">
{`POST /v1/analyze
{
  "files": [base64],
  "playbook": ["strictly_delaware"]
}

// Response:
{
  "signerScore": 84,
  "redFlags": [...]
}`}
                </pre>
                <p className="mt-8 text-slate-400 text-sm">Need a higher rate limit? <span className="text-indigo-400 cursor-pointer underline">Contact Enterprise Sales</span></p>
              </div>
            </div>
          </div>
        );

      case AppStep.Auth:
        return (
          <div className="max-w-xl mx-auto px-4 py-32 animate-in zoom-in-95">
            <div className="bg-white p-16 rounded-[4rem] shadow-2xl border border-slate-100 text-center relative overflow-hidden">
               <div className="absolute top-0 left-0 w-full h-2 bg-indigo-600"></div>
               <div className="w-24 h-24 bg-indigo-50 rounded-[2.5rem] flex items-center justify-center mx-auto mb-10 text-indigo-600">
                  <i className="fa-solid fa-user-lock text-4xl"></i>
               </div>
               <h2 className="text-5xl font-black text-slate-900 mb-4 tracking-tighter uppercase">Access Vault</h2>
               <p className="text-slate-500 mb-12 font-medium">Verify your identity to view your protected signatures.</p>
               <div className="space-y-4 text-left">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-4">Authorized Email</label>
                    <input type="email" placeholder="agent@sentinel.ai" className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-6 py-4 text-sm font-bold focus:ring-4 focus:ring-indigo-500/10 outline-none" />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-4">Vault Key</label>
                    <input type="password" placeholder="••••••••" className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-6 py-4 text-sm font-bold focus:ring-4 focus:ring-indigo-500/10 outline-none" />
                  </div>
               </div>
               <button onClick={() => setStep(AppStep.Vault)} className="w-full bg-slate-900 text-white py-6 rounded-2xl font-black uppercase text-xs tracking-[0.3em] mt-10 hover:bg-indigo-600 transition shadow-xl">Decrypt Access</button>
               <div className="mt-8 flex justify-between text-[10px] font-black uppercase tracking-widest text-slate-400">
                  <span className="cursor-pointer hover:text-indigo-600 transition">Request Key</span>
                  <span className="cursor-pointer hover:text-indigo-600 transition">Contact Admin</span>
               </div>
            </div>
          </div>
        );

      default:
        return <div className="text-center py-20 font-black">Feature Buffered...</div>;
    }
  };

  return (
    <Layout onNavigate={handleNavigate}>
      {renderContent()}
    </Layout>
  );
};

export default App;

export interface AuditEntry {
  event: string;
  timestamp: string;
  details: string;
}

export interface Obligation {
  id: string;
  party: string;
  requirement: string;
  deadline?: string;
  status: 'Pending' | 'Met' | 'Overdue';
  category: string;
}

export interface VersionDiff {
  clause: string;
  oldValue?: string;
  newValue?: string;
  changeType: 'Addition' | 'Deletion' | 'Modification';
  riskImpact: 'Better' | 'Worse' | 'Neutral';
}

export interface NegotiationStrategy {
  leveragePoints: string[];
  counterClauses: { original: string; suggested: string; reasoning: string }[];
  concessionStrategy: string;
}

