import { GoogleGenAI, Type, Modality, GenerateContentResponse } from "@google/genai";
import { ContractAnalysis, ClassificationResult, ContractHistoryItem, ChatMessage, UserPreferences } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeBatch = async (
  files: { base64: string; mimeType: string }[],
  preferences: UserPreferences
): Promise<ContractAnalysis> => {
  const model = "gemini-3-pro-preview";

  const isComparison = files.length > 1;

  // Each Part in the array must contain exactly one field: text, inlineData, functionCall, etc.
  // We cannot have both inlineData and text in the same part object.
  const parts: any[] = [];
  files.forEach((f, i) => {
    parts.push({ text: `--- Start of Document ${i + 1} ---` });
    parts.push({ inlineData: { data: f.base64, mimeType: f.mimeType } });
    parts.push({ text: `--- End of Document ${i + 1} ---` });
  });

  const prompt = `
    Act as an elite Legal Guardian and Forensics Auditor. 
    Analyze the provided content for protection of the Signer.

    ${isComparison ? "The user provided multiple versions. Flag deletions or additions that weaken the signer's position." : "Analyze the contract for traps, fraud indicators, and compliance."}

    PLAYBOOK RULES: ${preferences.playbookRules?.join('; ') || "Protect signer interests above all."}
    FOCUS: ${preferences.focusAreas.join(', ')}

    CHECKLIST:
    1. FRAUD: Identify metadata anomalies or inconsistencies in text structure.
    2. NEGOTIATION: Extract 3 leverage points where the signer can push back.
    3. REMINDERS: Extract all key dates (renewal, termination, payment) for a calendar.
    4. PLAYBOOK: Verify compliance with the provided rules.

    REQUIRED JSON SCHEMA:
    {
      "summary": "Brief executive summary.",
      "signerScore": 0-100,
      "metadata": { 
        "isContract": true, 
        "confidence": 0-1,
        "tamperRisk": "None|Low|High",
        "anomalies": ["strings describing font shifts, metadata weirdness, etc."],
        "expiryDates": [{"date": "YYYY-MM-DD", "type": "Renewal|Termination|Payment"}]
      },
      "parties": [{"name": "string", "role": "string"}],
      "obligations": [{"id": "uuid", "party": "string", "requirement": "string", "deadline": "YYYY-MM-DD", "category": "string"}],
      "financials": { "amount": "string", "totalCommitment": "string", "hiddenFees": ["string"] },
      "redFlags": [{ "id": "uuid", "issue": "string", "riskLevel": "High|Medium|Low", "originalText": "string", "suggestion": { "counterOffer": "string", "rephrasedClause": "string", "whyItMatters": "string", "strategy": "string" } }],
      "playbookCompliance": [{"rule": "string", "isCompliant": boolean, "deviationDetail": "string", "suggestedCorrection": "string"}],
      "negotiation": {
        "leveragePoints": ["Detailed dynamic advantages"],
        "counterClauses": [{"original": "string", "suggested": "string", "reasoning": "string"}],
        "concessionStrategy": "What to trade off"
      },
      ${isComparison ? '"versionDiffs": [{ "clause": "string", "oldValue": "string", "newValue": "string", "changeType": "Addition|Deletion|Modification", "riskImpact": "Better|Worse|Neutral" }],' : ""}
      "verificationQuestion": "Security challenge question.",
      "expectedResponse": "Challenge answer.",
      "fullText": "Full extracted plain text"
    }
  `;

  parts.push({ text: prompt });

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: parts
    },
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 32768 }
    }
  });

  return JSON.parse(response.text || '{}');
};

export const chatWithDocument = async (
  query: string,
  analysis: ContractAnalysis,
  history: ChatMessage[]
): Promise<{ text: string; citations: string[] }> => {
  const model = "gemini-3-flash-preview";
  const chat = ai.chats.create({
    model,
    config: {
      systemInstruction: `You are the SignWise Bodyguard. Context: ${analysis.summary}. Full Text: ${analysis.fullText?.slice(0, 10000)}.
      Reference specific clauses when answering. Be firm and protective of the user.`
    }
  });

  const response = await chat.sendMessage({ message: query });
  return { 
    text: response.text || "Guardian unavailable.",
    citations: [] 
  };
};

export const classifyUpload = async (base64Data: string, mimeType: string): Promise<ClassificationResult> => {
  const model = "gemini-3-flash-preview";
  const response = await ai.models.generateContent({
    model,
    contents: { 
      parts: [
        { inlineData: { data: base64Data, mimeType } }, 
        { text: "Classify this document intake. Intent: REVIEW, CREATE, or COMPARE. Return JSON with 'intent' and 'reasoning' fields." }
      ] 
    },
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text || '{"intent": "REVIEW"}');
};

export const generateContractContent = async (base64: string, mimeType: string) => {
  const model = "gemini-3-pro-preview";
  const r = await ai.models.generateContent({
    model,
    contents: { 
      parts: [
        { inlineData: { data: base64, mimeType } }, 
        { text: "Draft a pro-signer contract based on the provided input. Focus on maximizing signer protections and clarity." }
      ] 
    },
    config: { thinkingConfig: { thinkingBudget: 32768 } }
  });
  return r.text || "";
};

export const refineContract = async (content: string, instruction: string) => {
  const model = "gemini-3-pro-preview";
  const r = await ai.models.generateContent({
    model,
    contents: {
      parts: [{ text: `Original Content:\n${content}\n\nRefinement Instruction: ${instruction}` }]
    },
    config: { thinkingConfig: { thinkingBudget: 32768 } }
  });
  return r.text || content;
};

export const generateVoiceSummary = async (text: string): Promise<string> => {
  const model = "gemini-2.5-flash-preview-tts";
  const response = await ai.models.generateContent({
    model,
    contents: { parts: [{ text: `Protective Brief: ${text}` }] },
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
    },
  });
  return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || "";
};

export function decodeBase64(base64: string): Uint8Array {
  const b = atob(base64);
  const u = new Uint8Array(b.length);
  for (let i = 0; i < b.length; i++) u[i] = b.charCodeAt(i);
  return u;
}

export async function decodeAudioData(data: Uint8Array, ctx: AudioContext) {
  const d = new Int16Array(data.buffer);
  const b = ctx.createBuffer(1, d.length, 24000);
  const c = b.getChannelData(0);
  for (let i = 0; i < d.length; i++) c[i] = d[i] / 32768.0;
  return b;
}

