          <button onClick={() => setIsChatOpen(true)} className="w-16 h-16 md:w-20 md:h-20 bg-slate-900 text-white rounded-2xl md:rounded-[2.5rem] flex items-center justify-center shadow-2xl hover:scale-105 hover:shadow-indigo-500/50 transition-all duration-300 group border-[4px] md:border-[6px] border-white">
