            <h4 className="font-black text-base md:text-xl text-slate-900 leading-tight truncate">{issue}</h4>
            <span className={`text-[7px] md:text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded ${getBadgeStyles()}`}>{riskLevel} Risk</span>
          </div>
        </div>
        <div className="flex bg-slate-100 rounded-lg p-1 shadow-inner shrink-0 self-end sm:self-start">
          <button 
