      <div className="mb-6">
        <p className="text-[8px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 flex items-center gap-2">
          <i className="fa-solid fa-quote-left text-slate-300"></i> Discovered Clause
        </p>
        <div className="bg-slate-50 p-3 md:p-4 rounded-xl md:rounded-2xl border border-slate-200 font-serif text-xs md:text-sm italic text-slate-600 leading-relaxed break-words">
          "{originalText}"
        </div>
      </div>

      <div className="bg-slate-900 rounded-2xl md:rounded-[2rem] overflow-hidden border border-slate-800 shadow-xl">
        <div className="bg-indigo-600 px-4 md:px-5 py-2 flex items-center justify-between">
          <span className="text-white text-[8px] md:text-[9px] font-black uppercase tracking-widest flex items-center gap-2">
            <i className="fa-solid fa-shield-halved text-[10px]"></i> Guardian Recommendation
          </span>
        </div>

        <div className="p-4 md:p-6 space-y-4 md:space-y-6">
          <div>
            <h5 className="text-indigo-400 text-[8px] md:text-[9px] font-black uppercase mb-1">Impact Analysis</h5>
            <p className="text-slate-300 text-[10px] md:text-xs leading-relaxed break-words">{suggestion.whyItMatters}</p>
          </div>

          <div className="flex gap-2">
             <button 
               onClick={() => setShowRephrased(!showRephrased)}
               className="flex-1 bg-amber-600/10 text-amber-500 border border-amber-900/50 px-3 md:px-4 py-2 rounded-lg md:rounded-xl text-[8px] md:text-[9px] font-black uppercase tracking-wider hover:bg-amber-600/20 transition flex items-center justify-center gap-2"
             >
               <i className="fa-solid fa-wand-magic-sparkles text-[10px]"></i>
