export const analyzeBatch = async (
  files: { base64: string; mimeType: string }[],
  preferences: UserPreferences
): Promise<ContractAnalysis> => {
  const model = "gemini-3-pro-preview";

  const isComparison = files.length > 1;
  const parts: any[] = [];

  files.forEach((f, i) => {
    parts.push({ text: `--- Start of Document ${i + 1} ---` });
    parts.push({ inlineData: { data: f.base64, mimeType: f.mimeType } });
    parts.push({ text: `--- End of Document ${i + 1} ---` });
  });

  const prompt = `
    Act as a "Red Team" Legal Strategist and Forensic Auditor. Your mission is to protect the SIGNER at all costs.

    SYSTEM DIRECTIVES:
    1. ASYMMETRY SCAN: Identify every instance where the counterparty has a right that the signer lacks (e.g., right to terminate, right to audit).
    2. BEHAVIORAL ANALYSIS: Identify "Dark Patterns" in the legalese designed to confuse or hide liability.
    3. WORST CASE MODELING: If this contract goes to litigation, where does the signer lose?
    4. SILENT OMISSIONS: What critical protections (Indemnity, Force Majeure, Limitation of Liability) are MISSING for the signer?

    ANALYSIS FRAMEWORK:
    - Focus on ${preferences.focusAreas.join(', ')}.
    - Use the Playbook: ${preferences.playbookRules?.join('; ') || "Prioritize signer leverage and asset protection."}

    REQUIRED JSON OUTPUT SCHEMA:
    {
      "summary": "High-level strategic overview.",
      "signerScore": 0-100,
      "worstCaseScenario": "Detailed description of the most dangerous outcome for the signer.",
      "silentOmissions": ["List of missing protective clauses."],
      "metadata": { 
        "isContract": true, 
        "tamperRisk": "None|Low|High",
        "anomalies": ["Metadata or structural inconsistencies"],
        "expiryDates": [{"date": "YYYY-MM-DD", "type": "Renewal|Termination"}]
      },
      "parties": [{"name": "string", "role": "string"}],
      "obligations": [{"id": "uuid", "party": "string", "requirement": "string", "deadline": "YYYY-MM-DD", "category": "string"}],
      "redFlags": [{
        "id": "uuid",
        "issue": "Specific risk found",
        "riskLevel": "High|Medium|Low",
        "originalText": "The exact wording found",
        "suggestion": {
          "whyItMatters": "Deep explanation of the legal/practical danger.",
          "strategy": "The overarching negotiation goal.",
          "counterOffer": "Specific wording to propose instead.",
          "rephrasedClause": "A 'fair' middle-ground alternative.",
          "tacticalTips": ["Specific verbal cues for negotiation"],
          "psychologicalInsight": "Why did the counterparty include this specific wording?"
        }
      }],
      "negotiation": {
        "leveragePoints": ["Strategic advantages for the signer"],
        "counterClauses": [{"original": "string", "suggested": "string", "reasoning": "string"}],
        "concessionStrategy": "What to give up to get the big wins"
      },
      "fullText": "Clean extracted text"
    }
  `;

  parts.push({ text: prompt });

  const response = await ai.models.generateContent({
    model,
    contents: { parts: parts },
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 32768 }
    }
  });

  return JSON.parse(response.text || '{}');
};

export const chatWithDocument = async (
  query: string,
  analysis: ContractAnalysis,
  history: ChatMessage[]
): Promise<{ text: string; citations: string[] }> => {
  const model = "gemini-3-flash-preview";
  const chat = ai.chats.create({
    model,
    config: {
      systemInstruction: `
        You are the SignWise Sentinel. You have superhuman legal reasoning and pattern recognition.
        Context: ${analysis.summary}
        Worst Case Scenario: ${analysis.worstCaseScenario}
        Silent Omissions: ${analysis.silentOmissions.join(', ')}

        RULES:
        1. Never provide generic legal advice; be hyper-specific to this document.
        2. Use a tone that is protective, skeptical, and strategic.
        3. If asked about a risk, explain not just what it says, but how it could be used against the user in court.
      `
    }
  });

  const response = await chat.sendMessage({ message: query });
  return { text: response.text || "Sentinel unavailable.", citations: [] };
};

export const classifyUpload = async (base64Data: string, mimeType: string): Promise<ClassificationResult> => {
  const model = "gemini-3-flash-preview";
  const response = await ai.models.generateContent({
    model,
    contents: { 
      parts: [
        { inlineData: { data: base64Data, mimeType } }, 
        { text: "Classify this document. Is it a REVIEW, CREATE (template), or COMPARE (history) request? Return JSON." }
      ] 
    },
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text || '{"intent": "REVIEW"}');
};

export const generateContractContent = async (base64: string, mimeType: string) => {
  const model = "gemini-3-pro-preview";
  const r = await ai.models.generateContent({
    model,
    contents: { 
      parts: [
        { inlineData: { data: base64, mimeType } }, 
        { text: "Architect a 'Signer-First' contract. Every clause must be optimized for the user's protection, assuming high-conflict enforcement." }
      ] 
    },
    config: { thinkingConfig: { thinkingBudget: 32768 } }
  });
