export const analyzeBatch = async (
  files: { base64: string; mimeType: string }[],
  preferences: UserPreferences
): Promise<ContractAnalysis> => {
  const model = "gemini-3-pro-preview";

  const isComparison = files.length > 1;
  const parts: any[] = [];

  files.forEach((f, i) => {
    parts.push({ text: `--- Start of Document ${i + 1} ---` });
    parts.push({ inlineData: { data: f.base64, mimeType: f.mimeType } });
    parts.push({ text: `--- End of Document ${i + 1} ---` });
  });

  const prompt = `
    Act as a "Tier-1" Legal Strategist and Forensic Auditor specializing in asymmetric signer protection.

    INTELLECTUAL FRAMEWORKS:
    1. GROUNDED RESEARCH: Use Google Search to verify any specific statutes, case laws (e.g., Delaware corporate law updates, California AB5), or regulatory frameworks (GDPR, CCPA) mentioned. Provide a "Regulatory Pulse" section.
    2. ASYMMETRY SCAN: Map rights of Party A vs Party B. Flag "One-Way" clauses (e.g., "Counterparty can terminate at will, Signer is locked in").
    3. LIABILITY FORECASTING: Quantify the financial risk. Estimate "Worst-Case Financial Exposure".
    4. JURISDICTION AUDIT: Assess the governing law and venue. Is the chosen venue a "hometown advantage" for the counterparty?
    5. DARK PATTERN DETECTION: Identify clauses hidden in definitions or exhibits that strip rights found in the main body.

    ANALYSIS FOCUS: ${preferences.focusAreas.join(', ')}
    USER PLAYBOOK: ${preferences.playbookRules?.join('; ') || "Maximize signer autonomy and minimize liability."}

    REQUIRED JSON OUTPUT:
    {
      "summary": "Strategic brief for the signer.",
      "signerScore": 0-100,
      "worstCaseScenario": "Specific narrative of the most damaging legal/financial outcome.",
      "silentOmissions": ["Protections that are standard but MISSING here."],
      "jurisdictionAudit": {
        "governingLaw": "Jurisdiction name",
        "venue": "Specific court location",
        "favorabilityScore": 0-100,
        "warning": "Why this venue is or isn't a trap."
      },
      "liabilityModel": {
        "estimatedExposure": "$ Amount or 'Infinite'",
        "capStatus": "Capped|Uncapped|Ambiguous",
        "hiddenCosts": ["Fees, indemnities, or overhead costs"]
      },
      "regulatoryPulse": [{
        "statute": "Name of law",
        "relevance": "How it affects this doc",
        "recentChanges": "Grounded news/updates on this law",
        "citationUrl": "Source link from Google Search"
      }],
      "redFlags": [{
        "id": "uuid",
        "issue": "Found risk",
        "riskLevel": "High|Medium|Low",
        "originalText": "The clause",
        "suggestion": {
          "whyItMatters": "Reasoning based on case law or common precedent.",
          "strategy": "Negotiation stance",
          "counterOffer": "Specific pro-signer language",
          "rephrasedClause": "Fair middle ground",
          "tacticalTips": ["Phrases to use in the meeting"],
          "psychologicalInsight": "The likely motive of the drafter"
        }
      }],
      "negotiation": {
        "leveragePoints": ["Advantageous facts or clauses"],
        "counterClauses": [{"original": "string", "suggested": "string", "reasoning": "string"}],
        "concessionStrategy": "Low-stakes items to trade away"
      }
    }
  `;

  parts.push({ text: prompt });

  const response = await ai.models.generateContent({
    model,
    contents: { parts: parts },
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 32768 },
      tools: [{ googleSearch: {} }] // Granting real-world knowledge
    }
  });

  return JSON.parse(response.text || '{}');
};

export const chatWithDocument = async (
  query: string,
  analysis: ContractAnalysis,
  history: ChatMessage[]
): Promise<{ text: string; citations: string[] }> => {
  const model = "gemini-3-pro-preview"; // Using Pro for better reasoning in chat
  const chat = ai.chats.create({
    model,
    config: {
      systemInstruction: `
        You are the SignWise Sentinel. You are a high-level strategist, not just a reviewer.
        Summary: ${analysis.summary}
        Exposure Model: ${analysis.liabilityModel?.estimatedExposure}
        Jurisdiction: ${analysis.jurisdictionAudit?.governingLaw}

        BEHAVIORS:
        1. CHALLENGE ASSUMPTIONS: If a user asks 'Is this okay?', explain WHY it might not be.
        2. PREDICT OUTCOMES: Walk the user through a scenario where a clause is enforced.
        3. REAL-WORLD DATA: Use Google Search to find specific legal precedents or current news if asked about a law.
      `,
      tools: [{ googleSearch: {} }]
    }
  });

  const response = await chat.sendMessage({ message: query });

  // Extract search citations if available
  const citations: string[] = [];
  if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
    response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
      if (chunk.web?.uri) citations.push(chunk.web.uri);
    });
  }

  return { text: response.text || "Sentinel currently processing deep logic...", citations };
};

