export const analyzeBatch = async (
  rawFiles: { base64: string; mimeType: string }[],
  preferences: UserPreferences
): Promise<ContractAnalysis> => {
  const model = "gemini-3-pro-preview";
  const files = filterFiles(rawFiles);

  if (files.length === 0) {
    throw new Error("No supported document types found (PDF, Images, or Text required). ZIP files are not supported.");
  }

  const parts: any[] = [];
  files.forEach((f, i) => {
    parts.push({ text: `--- Start of Document ${i + 1} ---` });
    parts.push({ inlineData: { data: f.base64, mimeType: f.mimeType } });
    parts.push({ text: `--- End of Document ${i + 1} ---` });
  });

  const prompt = `
    Act as a "Tier-1" Forensic Legal Architect. Your goal is to provide deep strategic insight and protective reasoning for the SIGNER.

    ADVANCED ANALYTIC PROTOCOLS:
    1. GROUNDED RESEARCH: Use Google Search to find current state-specific legal nuances (e.g., non-compete ban updates in CA/NY, specific indemnity statutes).
    2. ASYMMETRY MAPPING: Compare rights of Party A (Counterparty) vs Party B (User). Explicitly list what they can do that the user cannot.
    3. CONFLICT SIMULATION: Simulate 3 high-stakes scenarios (e.g., breach of payment, project delay, data leak) and show exactly how this contract performs for the user.
    4. LIQUIDATED DAMAGES & CAPS: Model the maximum dollar exposure.
    5. PSYCHOLOGICAL PROFILING: Identify why specific word choices were used to potentially disadvantage the signer.

    REQUIRED JSON OUTPUT:
    {
      "summary": "High-level strategic briefing.",
      "signerScore": 0-100,
      "worstCaseScenario": "Narrative of the most dangerous outcome.",
      "silentOmissions": ["Protective clauses that should be here but aren't."],
      "asymmetricClauses": [{
        "category": "Termination|Audit|Liability",
        "counterpartyRight": "What they can do",
        "signerRight": "What the user can do (or can't)",
        "imbalanceLevel": "Severe|Moderate|Fair"
      }],
      "conflictSimulations": [{
        "trigger": "A project delay occurs...",
        "outcome": "User is liable for $X...",
        "protectiveAction": "Request a 'cure period' of 15 days."
      }],
      "jurisdictionAudit": {
        "governingLaw": "Jurisdiction",
        "venue": "Court location",
        "favorabilityScore": 0-100,
        "warning": "Specific trap warning for this state."
      },
      "liabilityModel": {
        "estimatedExposure": "Dollar estimate",
        "capStatus": "Capped|Uncapped|Ambiguous",
        "hiddenCosts": ["Late fees, legal cost shifting, etc."]
      },
      "regulatoryPulse": [{
        "statute": "Law name",
        "relevance": "Context",
        "recentChanges": "Grounded search updates",
        "citationUrl": "Link to source"
      }],
      "redFlags": [{
        "id": "uuid",
        "issue": "Risk detail",
        "riskLevel": "High|Medium|Low",
        "originalText": "The text",
        "suggestion": {
          "whyItMatters": "Deep legal reasoning.",
          "strategy": "Negotiation move",
          "counterOffer": "Protective text",
          "rephrasedClause": "Balanced text",
          "tacticalTips": ["Verbal negotiation cues"],
          "psychologicalInsight": "Drafter motive"
        }
      }],
      "negotiation": {
        "leveragePoints": ["Advantage points"],
        "counterClauses": [{"original": "text", "suggested": "text", "reasoning": "logic"}],
        "concessionStrategy": "What to trade"
      }
    }
  `;

  parts.push({ text: prompt });

  const response = await ai.models.generateContent({
    model,
    contents: { parts: parts },
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 32768 },
      tools: [{ googleSearch: {} }]
    }
  });

  return JSON.parse(response.text || '{}');
};

export const chatWithDocument = async (
  query: string,
  analysis: ContractAnalysis,
  history: ChatMessage[]
): Promise<{ text: string; citations: string[] }> => {
  const model = "gemini-3-pro-preview";
  const chat = ai.chats.create({
    model,
    config: {
      systemInstruction: `
        You are the SignWise Sentinel. Use extreme legal reasoning and strategic thinking.
        Current Analysis: ${analysis.summary}
        Liability Exposure: ${analysis.liabilityModel?.estimatedExposure}
        Worst Case: ${analysis.worstCaseScenario}

        Focus on predicting outcomes and recommending specific negotiation phrases.
        Always look for the hidden catch in any clause mentioned.
      `,
      tools: [{ googleSearch: {} }]
    }
  });

  const response = await chat.sendMessage({ message: query });
  const citations: string[] = [];
  if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
    response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
      if (chunk.web?.uri) citations.push(chunk.web.uri);
    });
  }

  return { text: response.text || "Reasoning engine paused.", citations };
};

export const classifyUpload = async (base64Data: string, mimeType: string): Promise<ClassificationResult> => {
  if (!SUPPORTED_MIME_TYPES.includes(mimeType)) {
    return { intent: 'REVIEW', reasoning: 'Unsupported file type fallback.' };
  }
  const model = "gemini-3-flash-preview";
  const response = await ai.models.generateContent({
    model,
    contents: { 
      parts: [
        { inlineData: { data: base64Data, mimeType } }, 
        { text: "Predict user intent: REVIEW, CREATE, or COMPARE. Return JSON." }
      ] 
    },
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text || '{"intent": "REVIEW"}');
};

