        </button>
        <button onClick={() => handleCloudConnect('OneDrive')} className="flex-1 sm:flex-none bg-white px-4 md:px-6 py-2.5 md:py-3 rounded-xl md:rounded-2xl border border-slate-200 text-[9px] md:text-xs font-black text-slate-500 hover:border-blue-400 transition flex items-center justify-center gap-2">
