            </div>
            <h3 className="text-3xl md:text-6xl font-black text-slate-900 mb-4 md:mb-6 tracking-tighter leading-none text-balance">Universal <span className="text-indigo-600">Secure</span> Intake.</h3>
            <p className="text-sm md:text-xl text-slate-500 mb-10 md:mb-16 max-w-lg mx-auto font-medium leading-relaxed px-4">Securely ingest PDFs, scans, or handwritten notes. ZIP files are not supported. Supported: PDF, JPG, PNG, WEBP, TXT.</p>
            <div className="flex flex-wrap items-center justify-center gap-6 md:gap-10 text-slate-300 px-4">
               <div className="flex flex-col items-center gap-1.5 md:gap-2 group cursor-default">
                  <i className="fa-brands fa-google-drive text-2xl md:text-4xl group-hover:text-blue-500 transition-all"></i>
                  <span className="text-[7px] md:text-[8px] font-black uppercase tracking-tighter">Drive</span>
               </div>
               <div className="flex flex-col items-center gap-1.5 md:gap-2 group cursor-default">
                  <i className="fa-brands fa-dropbox text-2xl md:text-4xl group-hover:text-blue-400 transition-all"></i>
                  <span className="text-[7px] md:text-[8px] font-black uppercase tracking-tighter">Dropbox</span>
               </div>
               <div className="flex flex-col items-center gap-1.5 md:gap-2 group cursor-default">
                  <i className="fa-solid fa-camera text-2xl md:text-4xl group-hover:text-amber-500 transition-all"></i>
                  <span className="text-[7px] md:text-[8px] font-black uppercase tracking-tighter">Scan</span>
               </div>
               <div className="flex flex-col items-center gap-1.5 md:gap-2 group cursor-default">
                  <i className="fa-solid fa-envelope text-2xl md:text-4xl group-hover:text-red-400 transition-all"></i>
