import React, { useState, useRef, useEffect } from 'react';
import { ContractAnalysis, ChatMessage, AuditEntry, Comment } from '../types';
import RedFlagCard from './RedFlagCard';
import { 
  generateVoiceSummary, 
  decodeBase64, 
  decodeAudioData, 
  chatWithDocument
} from '../services/geminiService';

interface DashboardProps {
  analysis: ContractAnalysis;
  onConfirm: () => void;
  onRestart: () => void;
  onDecline: () => void;
  auditTrail: AuditEntry[];
}

const Dashboard: React.FC<DashboardProps> = ({ analysis, onConfirm, onRestart, onDecline, auditTrail }) => {
  const [activeTab, setActiveTab] = useState<'risk' | 'negotiate' | 'versions' | 'obligations' | 'compliance' | 'collab' | 'intel'>('risk');
  const [isGeneratingVoice, setIsGeneratingVoice] = useState(false);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [chatInput, setChatInput] = useState('');
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [isChatLoading, setIsChatLoading] = useState(false);
  const [comments, setComments] = useState<Comment[]>(analysis.comments || []);
  const [newComment, setNewComment] = useState('');
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (chatEndRef.current) chatEndRef.current.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory, isChatOpen]);

  const handleListen = async () => {
    setIsGeneratingVoice(true);
    try {
      const b64 = await generateVoiceSummary(analysis.summary);
      const ctx = new AudioContext();
      const b = await decodeAudioData(decodeBase64(b64), ctx);
      const s = ctx.createBufferSource();
      s.buffer = b; s.connect(ctx.destination); s.start();
    } catch (e) { alert("Audio interrupted."); } finally { setIsGeneratingVoice(false); }
  };

  const handleSendChat = async () => {
    if (!chatInput.trim() || isChatLoading) return;
    const userMsg = chatInput;
    setChatHistory(prev => [...prev, { role: 'user', text: userMsg }]);
    setChatInput('');
    setIsChatLoading(true);
    try {
      const r = await chatWithDocument(userMsg, analysis, chatHistory);
      setChatHistory(prev => [...prev, { role: 'model', text: r.text, citations: r.citations }]);
    } finally { setIsChatLoading(false); }
  };

  const addComment = () => {
    if (!newComment.trim()) return;
    const comment: Comment = {
      id: Math.random().toString(),
      author: 'You',
      text: newComment,
      timestamp: new Date().toLocaleTimeString()
    };
    setComments([comment, ...comments]);
    setNewComment('');
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-4 md:py-8 space-y-4 md:space-y-8 animate-in fade-in duration-500">
      {/* Critical Intelligence Banner */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        {/* Worst Case */}
        <div className="bg-slate-900 text-white p-6 rounded-2xl border-l-8 border-red-600 shadow-2xl">
          <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-red-500 mb-2">Exposure Forecast</h4>
          <p className="text-xs opacity-90 leading-relaxed italic">"{analysis.worstCaseScenario}"</p>
        </div>

        {/* Jurisdiction Intelligence */}
        <div className="bg-indigo-600 text-white p-6 rounded-2xl shadow-xl relative overflow-hidden group">
          <div className="absolute top-[-10%] right-[-10%] w-32 h-32 bg-white/10 blur-[40px] rounded-full group-hover:scale-125 transition-transform"></div>
          <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Jurisdiction Audit</h4>
          <div className="flex justify-between items-end">
            <div>
              <p className="text-xl font-black">{analysis.jurisdictionAudit?.governingLaw || 'Unknown'}</p>
              <p className="text-[10px] font-bold opacity-80">{analysis.jurisdictionAudit?.venue}</p>
            </div>
            <div className="text-right">
              <span className="text-3xl font-black">{analysis.jurisdictionAudit?.favorabilityScore}%</span>
              <p className="text-[8px] font-black uppercase tracking-widest opacity-60">Favorability</p>
            </div>
          </div>
        </div>

        {/* Financial Exposure */}
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col justify-between">
          <div>
            <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 mb-2">Liability Model</h4>
            <p className="text-2xl font-black text-slate-900">{analysis.liabilityModel?.estimatedExposure || 'TBD'}</p>
            <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-full ${analysis.liabilityModel?.capStatus === 'Uncapped' ? 'bg-red-100 text-red-600' : 'bg-emerald-100 text-emerald-600'}`}>
              {analysis.liabilityModel?.capStatus}
            </span>
          </div>
          <div className="mt-4 flex -space-x-2">
            {analysis.liabilityModel?.hiddenCosts.map((_, i) => (
