export const generateVoiceSummary = async (text: string): Promise<string> => {
  const model = "gemini-2.5-flash-preview-tts";
  const response = await ai.models.generateContent({
    model,
    contents: { parts: [{ text: `Brief: ${text}` }] },
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
    },
  });
  return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || "";
};

export function decodeBase64(base64: string): Uint8Array {
  const b = atob(base64);
  const u = new Uint8Array(b.length);
  for (let i = 0; i < b.length; i++) u[i] = b.charCodeAt(i);
  return u;
}

export async function decodeAudioData(data: Uint8Array, ctx: AudioContext) {
  const d = new Int16Array(data.buffer);
  const b = ctx.createBuffer(1, d.length, 24000);
  const c = b.getChannelData(0);
  for (let i = 0; i < d.length; i++) c[i] = d[i] / 32768.0;
  return b;
}

import React, { useState, useRef, useEffect } from 'react';
import { ContractAnalysis, ChatMessage, AuditEntry, Comment } from '../types';
import RedFlagCard from './RedFlagCard';
import { 
  generateVoiceSummary, 
  decodeBase64, 
  decodeAudioData, 
  chatWithDocument
} from '../services/geminiService';

interface DashboardProps {
  analysis: ContractAnalysis;
  onConfirm: () => void;
  onRestart: () => void;
  onDecline: () => void;
  auditTrail: AuditEntry[];
}

const Dashboard: React.FC<DashboardProps> = ({ analysis, onConfirm, onRestart, onDecline, auditTrail }) => {
  const [activeTab, setActiveTab] = useState<'risk' | 'negotiate' | 'versions' | 'obligations' | 'compliance' | 'collab' | 'intel'>('risk');
  const [isGeneratingVoice, setIsGeneratingVoice] = useState(false);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [chatInput, setChatInput] = useState('');
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [isChatLoading, setIsChatLoading] = useState(false);
  const [comments, setComments] = useState<Comment[]>(analysis.comments || []);
  const [newComment, setNewComment] = useState('');
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (chatEndRef.current) chatEndRef.current.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory, isChatOpen]);

  const handleListen = async () => {
    setIsGeneratingVoice(true);
    try {
      const b64 = await generateVoiceSummary(analysis.summary);
      const ctx = new AudioContext();
      const b = await decodeAudioData(decodeBase64(b64), ctx);
      const s = ctx.createBufferSource();
      s.buffer = b; s.connect(ctx.destination); s.start();
    } catch (e) { alert("Audio interrupted."); } finally { setIsGeneratingVoice(false); }
  };

  const handleSendChat = async () => {
    if (!chatInput.trim() || isChatLoading) return;
    const userMsg = chatInput;
    setChatHistory(prev => [...prev, { role: 'user', text: userMsg }]);
    setChatInput('');
    setIsChatLoading(true);
    try {
      const r = await chatWithDocument(userMsg, analysis, chatHistory);
      setChatHistory(prev => [...prev, { role: 'model', text: r.text, citations: r.citations }]);
    } finally { setIsChatLoading(false); }
  };

  const addComment = () => {
