export const SUPPORTED_MIME_TYPES = [
  "application/pdf",
  "image/png",
  "image/jpeg",
  "image/webp",
  "image/heic",
  "image/heif",
  "text/plain",
  "text/javascript",
  "text/python",
  "text/x-python",
  "text/typescript",
  "text/html",
  "text/css",
  "text/md",
  "text/csv",
  "text/xml",
  "text/rtf"
];

const filterFiles = (files: { base64: string; mimeType: string }[]) => {
  return files.filter(f => SUPPORTED_MIME_TYPES.includes(f.mimeType));
};

export const analyzeBatch = async (
  rawFiles: { base64: string; mimeType: string }[],
  preferences: UserPreferences
): Promise<ContractAnalysis> => {
  const model = "gemini-3-pro-preview";
  const files = filterFiles(rawFiles);

  if (files.length === 0) {
    throw new Error("No supported document types found. ZIP files are extracted client-side. Please ensure the ZIP contains PDFs, Images, or Text files.");
  }

  const parts: any[] = [];
  files.forEach((f, i) => {
    parts.push({ text: `--- Start of Document ${i + 1} ---` });
    parts.push({ inlineData: { data: f.base64, mimeType: f.mimeType } });
    parts.push({ text: `--- End of Document ${i + 1} ---` });
  });

  const prompt = `
    Act as a "Tier-1" Forensic Legal Architect. Provide high-autonomy strategic protection for the SIGNER.

    INTELLECTUAL FRAMEWORKS:
    1. GROUNDED RESEARCH: Use Google Search for current statutes (e.g., Delaware/NY corporate law, state privacy acts).
    2. ASYMMETRY SCAN: Map rights Party A vs Party B. Flag "One-Way" clauses.
    3. DATA SHIELD: Analyze data ownership, AI training rights, and sharing protocols.
    4. FORCE MAJEURE STRESS TEST: Evaluate performance triggers in crises.
    5. RECIPROCITY GAPS: Identify where the counterparty is protected but the signer is NOT. Use these as negotiation chips.
    6. CONFLICT SIMULATIONS: Predict outcomes for: Non-payment, Performance failure, and Security breach.

    REQUIRED JSON OUTPUT:
    {
      "summary": "Brief",
      "signerScore": 0-100,
      "worstCaseScenario": "Narrative",
      "silentOmissions": ["Clauses missing"],
      "dataShield": {
        "dataOwnership": "Signer|Counterparty|Joint",
        "aiTrainingRights": true|false,
        "thirdPartySharing": "Detail",
        "securityStandard": "Detail"
      },
      "forceMajeure": {
        "isIncluded": true|false,
        "coversPandemics": true|false,
        "signerExitRights": "Summary"
      },
      "reciprocityGaps": [{
        "issue": "Liability",
        "counterpartyProtection": "Description",
        "missingSignerProtection": "Description",
        "negotiationChip": "Suggested demand"
      }],
      "asymmetricClauses": [{"category": "string", "counterpartyRight": "string", "signerRight": "string", "imbalanceLevel": "Severe|Moderate|Fair"}],
      "conflictSimulations": [{"trigger": "string", "outcome": "string", "protectiveAction": "string"}],
      "jurisdictionAudit": {"governingLaw": "string", "venue": "string", "favorabilityScore": 0-100, "warning": "string"},
      "liabilityModel": {"estimatedExposure": "string", "capStatus": "Capped|Uncapped", "hiddenCosts": ["string"]},
      "regulatoryPulse": [{"statute": "string", "relevance": "string", "recentChanges": "string", "citationUrl": "string"}],
      "redFlags": [{"id": "uuid", "issue": "string", "riskLevel": "High|Medium|Low", "originalText": "string", "suggestion": {"whyItMatters": "string", "strategy": "string", "counterOffer": "string", "rephrasedClause": "string", "tacticalTips": ["string"], "psychologicalInsight": "string"}}],
      "negotiation": {"leveragePoints": ["string"], "counterClauses": [{"original": "string", "suggested": "string", "reasoning": "string"}], "concessionStrategy": "string"},
      "industryComparison": [{"metric": "string", "assessment": "string", "isStandard": true|false}]
    }
  `;

  parts.push({ text: prompt });

  const response = await ai.models.generateContent({
    model,
    contents: { parts: parts },
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 32768 },
      tools: [{ googleSearch: {} }]
    }
  });

  return JSON.parse(response.text || '{}');
};

export const chatWithDocument = async (
  query: string,
  analysis: ContractAnalysis,
  history: ChatMessage[]
): Promise<{ text: string; citations: string[] }> => {
  const model = "gemini-3-pro-preview";
  const chat = ai.chats.create({
    model,
    config: {
      systemInstruction: `
        You are the SignWise Sentinel. Use extreme strategic reasoning.
        Context: ${analysis.summary}
        Exposure: ${analysis.liabilityModel?.estimatedExposure}
        Gaps: ${(analysis.reciprocityGaps?.map(g => g.issue) ?? []).join(', ')}
      `,
      tools: [{ googleSearch: {} }]
    }
  });

  const response = await chat.sendMessage({ message: query });
  const citations: string[] = [];
  if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
    response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
      if (chunk.web?.uri) citations.push(chunk.web.uri);
    });
  }

  return { text: response.text || "Reasoning...", citations };
};

export const classifyUpload = async (base64Data: string, mimeType: string): Promise<ClassificationResult> => {
  if (!SUPPORTED_MIME_TYPES.includes(mimeType)) {
    return { intent: 'REVIEW', reasoning: 'Fallback' };
  }
  const model = "gemini-3-flash-preview";
  const response = await ai.models.generateContent({
    model,
    contents: { 
      parts: [
        { inlineData: { data: base64Data, mimeType } }, 
        { text: "Predict intent: REVIEW, CREATE, or COMPARE. Return JSON." }
      ] 
    },
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text || '{"intent": "REVIEW"}');
};

