export function decodeBase64(base64: string): Uint8Array {
  const b = atob(base64);
  const u = new Uint8Array(b.length);
  for (let i = 0; i < b.length; i++) u[i] = b.charCodeAt(i);
  return u;
}

export async function decodeAudioData(data: Uint8Array, ctx: AudioContext) {
  const d = new Int16Array(data.buffer);
  const b = ctx.createBuffer(1, d.length, 24000);
  const c = b.getChannelData(0);
  for (let i = 0; i < d.length; i++) c[i] = d[i] / 32768.0;
  return b;
}

