export const SUPPORTED_MIME_TYPES = [
  "application/pdf",
  "image/png",
  "image/jpeg",
  "image/webp",
  "image/heic",
  "image/heif",
  "text/plain",
  "text/html",
  "text/css",
  "text/md",
  "text/csv",
  "text/xml",
  "text/rtf"
];

const filterFiles = (files: { base64: string; mimeType: string }[]) => {
  return files.filter(f => SUPPORTED_MIME_TYPES.includes(f.mimeType));
};

export const analyzeBatch = async (
  rawFiles: { base64: string; mimeType: string }[],
  preferences: UserPreferences
): Promise<ContractAnalysis> => {
  const model = "gemini-3-pro-preview";
  const files = filterFiles(rawFiles);

  if (files.length === 0) {
    throw new Error("No supported documents found. Please ensure the ZIP contains PDFs, Images, or Text files.");
  }

  const parts: any[] = [];
  files.forEach((f, i) => {
    parts.push({ text: `--- Start of Document ${i + 1} ---` });
    parts.push({ inlineData: { data: f.base64, mimeType: f.mimeType } });
    parts.push({ text: `--- End of Document ${i + 1} ---` });
  });

  const isProject = files.length > 1;

  const prompt = `
    Act as a "Tier-1" Forensic Legal Architect (Contract Guardian AI). Provide high-autonomy strategic protection for the SIGNER.
    ${isProject ? "This is a PROJECT-WIDE audit of multiple related documents. Perform a forensic deep-dive for cross-document collisions." : "Analyze this document for predatory terms and signer-first protection."}

    MISSION: Empower the signer to spot hidden traps, quantify asymmetry, and arm them with negotiation leverage.

    INTELLECTUAL FRAMEWORKS:
    1. GROUNDED RESEARCH: Use Google Search for current statutes and enforceability norms.
    2. ASYMMETRY SCAN (Titan Logic): Map rights Party A vs Party B. Flag "One-Way" clauses.
