      "obligations": [{"party": "string", "requirement": "string", "deadline": "string", "category": "string"}]
    }
  `;

  parts.push({ text: prompt });

  const response = await ai.models.generateContent({
    model,
    contents: { parts: parts },
    config: {
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 32768 },
      tools: [{ googleSearch: {} }]
    }
  });

  return JSON.parse(response.text || '{}');
};

export const chatWithDocument = async (
  query: string,
  analysis: ContractAnalysis,
  history: ChatMessage[]
): Promise<{ text: string; citations: string[] }> => {
  const model = "gemini-3-pro-preview";
  const chat = ai.chats.create({
    model,
    config: {
      systemInstruction: `
        You are the Contract Guardian Sentinel. Act as a Forensic Legal Bodyguard.
        Always prioritize the signer's interests.
        Context: ${analysis.summary}
        Global Score: ${analysis.signerScore}
        Exposure: ${analysis.liabilityModel?.estimatedExposure}
        Gaps: ${(analysis.reciprocityGaps?.map(g => g.issue) ?? []).join(', ')}
        ${analysis.projectAudit ? `Project Level Overview: ${analysis.projectAudit.executiveSummary}` : ""}
      `,
      tools: [{ googleSearch: {} }]
    }
  });

  const response = await chat.sendMessage({ message: query });
  const citations: string[] = [];
  if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
    response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
      if (chunk.web?.uri) citations.push(chunk.web.uri);
    });
  }

  return { text: response.text || "Guardian reasoning...", citations };
};

export const classifyUpload = async (base64Data: string, mimeType: string): Promise<ClassificationResult> => {
  if (!SUPPORTED_MIME_TYPES.includes(mimeType)) {
    return { intent: 'REVIEW', reasoning: 'Fallback' };
  }
  const model = "gemini-3-flash-preview";
  const response = await ai.models.generateContent({
    model,
    contents: { 
      parts: [
        { inlineData: { data: base64Data, mimeType } }, 
        { text: "Predict intent: REVIEW, CREATE, or COMPARE. Return JSON {intent: '...', reasoning: '...'}" }
      ] 
    },
    config: { responseMimeType: "application/json" }
  });
  return JSON.parse(response.text || '{"intent": "REVIEW"}');
};

