                <div className="flex-grow overflow-y-auto p-6 md:p-8 space-y-6 scrollbar-hide">
                   {chatHistory.length === 0 && (
                     <div className="text-center py-10 opacity-40">
                        <i className="fa-solid fa-user-shield text-4xl mb-4 text-slate-200"></i>
                        <p className="text-[10px] font-black uppercase tracking-widest leading-relaxed">I am your Forensic Bodyguard.<br/>How can I protect you today?</p>
                     </div>
                   )}
                   {chatHistory.map((msg, i) => (
                     <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[85%] p-4 md:p-5 rounded-2xl md:rounded-[1.5rem] ${msg.role === 'user' ? 'bg-indigo-600 text-white rounded-br-none' : 'bg-slate-50 text-slate-800 rounded-bl-none border border-slate-100'}`}>
                           <p className="text-[11px] md:text-xs font-medium leading-relaxed">{msg.text}</p>
                        </div>
                     </div>
                   ))}
                   {isChatLoading && (
                     <div className="flex justify-start">
                        <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 flex gap-1">
                           <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></div>
                           <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                           <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                        </div>
                     </div>
                   )}
                   <div ref={chatEndRef} />
                </div>

                <div className="p-6 md:p-8 border-t border-slate-100 bg-slate-50/50">
                   <div className="flex gap-2">
                      <input 
                        type="text" 
                        value={chatInput}
                        onChange={e => setChatInput(e.target.value)}
                        onKeyPress={e => e.key === 'Enter' && handleSendChat()}
                        placeholder="e.g. Total liability if I walk away?"
                        className="flex-1 bg-white border border-slate-200 rounded-xl md:rounded-2xl px-4 md:px-5 py-3 md:py-4 text-[11px] md:text-xs font-bold outline-none focus:ring-4 focus:ring-indigo-500/10 transition shadow-inner"
                      />
                      <button 
                        onClick={handleSendChat}
                        disabled={isChatLoading}
                        className="bg-slate-900 text-white w-12 h-12 md:w-14 md:h-14 rounded-xl md:rounded-2xl flex items-center justify-center hover:bg-indigo-600 transition disabled:opacity-50"
                      >
                         <i className="fa-solid fa-bolt text-sm"></i>
                      </button>
                   </div>
                </div>
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

