        }],
        "asymmetricClauses": [{"category": "string", "counterpartyRight": "string", "signerRight": "string", "imbalanceLevel": "Severe|Moderate|Fair"}],
        "conflictSimulations": [{"trigger": "string", "outcome": "string", "protectiveAction": "string"}],
