/**
 * Helper to execute API calls with exponential backoff retries for 429 and 5xx errors.
 */
async function withRetry<T>(fn: () => Promise<T>, maxRetries = 3, baseDelay = 2000): Promise<T> {
  let lastError: any;
  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (error: any) {
      lastError = error;
      const errorMessage = error?.message || "";
      const isRateLimit = errorMessage.includes("429") || errorMessage.includes("quota") || errorMessage.includes("RESOURCE_EXHAUSTED");
      const isServerError = errorMessage.includes("500") || errorMessage.includes("503") || errorMessage.includes("504");

      if (isRateLimit || isServerError) {
        const delay = baseDelay * Math.pow(2, i) + Math.random() * 1000;
        console.warn(`Guardian retry attempt ${i + 1}/${maxRetries} in ${Math.round(delay)}ms due to: ${errorMessage}`);
        await new Promise(resolve => setTimeout(resolve, delay));
        continue;
      }
      throw error;
    }
  }
  throw lastError;
}

const filterFiles = (files: { base64: string; mimeType: string }[]) => {
  return files.filter(f => SUPPORTED_MIME_TYPES.includes(f.mimeType));
};

export const analyzeBatch = async (
