        "redFlags": [{"id": "uuid", "issue": "string", "riskLevel": "High|Medium|Low", "originalText": "string", "suggestion": {"whyItMatters": "string", "strategy": "Tactical defense", "counterOffer": "Professional copy-paste ready demand", "psychologicalInsight": "Likely intent of the drafter", "tacticalTips": ["Tips for the signer"]}}],
