export const SUPPORTED_MIME_TYPES = [
  "application/pdf",
  "image/png",
  "image/jpeg",
  "image/webp",
  "image/heic",
  "image/heif",
  "text/plain",
  "text/html",
  "text/css",
  "text/md",
  "text/csv",
  "text/xml",
  "text/rtf"
];

/**
 * Helper to execute API calls with exponential backoff retries for 429 and 5xx errors.
 */
async function withRetry<T>(fn: () => Promise<T>, maxRetries = 3, baseDelay = 2000): Promise<T> {
  let lastError: any;
  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (error: any) {
      lastError = error;
      const errorMessage = error?.message || "";
      const isRateLimit = errorMessage.includes("429") || errorMessage.includes("quota") || errorMessage.includes("RESOURCE_EXHAUSTED");
      const isServerError = errorMessage.includes("500") || errorMessage.includes("503") || errorMessage.includes("504");

      if (isRateLimit || isServerError) {
        const delay = baseDelay * Math.pow(2, i) + Math.random() * 1000;
        console.warn(`Guardian retry attempt ${i + 1}/${maxRetries} in ${Math.round(delay)}ms due to: ${errorMessage}`);
        await new Promise(resolve => setTimeout(resolve, delay));
        continue;
      }
      throw error;
    }
  }
  throw lastError;
}

const filterFiles = (files: { base64: string; mimeType: string }[]) => {
  return files.filter(f => SUPPORTED_MIME_TYPES.includes(f.mimeType));
};

export const analyzeBatch = async (
  rawFiles: { base64: string; mimeType: string }[],
  preferences: UserPreferences
): Promise<ContractAnalysis> => {
  return withRetry(async () => {
    // Dynamically select model based on user settings
    const model = preferences.preferredModel || "gemini-3-pro-preview";
    const files = filterFiles(rawFiles);

    if (files.length === 0) {
      throw new Error("No supported documents found. Please ensure the ZIP contains PDFs, Images, or Text files.");
    }

    const parts: any[] = [];
    files.forEach((f, i) => {
      parts.push({ text: `--- Start of Document ${i + 1} ---` });
      parts.push({ inlineData: { data: f.base64, mimeType: f.mimeType } });
      parts.push({ text: `--- End of Document ${i + 1} ---` });
    });

    const isProject = files.length > 1;

    // Define tools based on user preferences
    const tools: any[] = [];
    if (preferences.enableSearch) tools.push({ googleSearch: {} });
    if (preferences.enableMaps) tools.push({ googleMaps: {} });

    const prompt = `
      Act as "GuardianPact AI", the ultimate world-class signer-first forensic legal bodyguard. Your mission is to protect the individual signer from one-sided, predatory, or risky contracts. You reverse the traditional imbalance.

      ${isProject ? "This is a PROJECT-WIDE forensic audit of multiple related documents. Perform a deep-dive for cross-document collisions and contradictions." : "Perform a forensic audit for traps and asymmetry."}

      SIGNER PROFILE: The user is the SIGNER (freelancer, founder, or project lead).
      JURISDICTION: ${preferences.defaultJurisdiction || 'Florida, US'} (specifically analyze Florida's 2025 CHOICE Act non-compete rules if applicable).

      PROCESSING STEPS:
      1. INVENTORY: List docs by type and purpose.
      2. PROJECT CONTEXT: Build timeline, call out conflicts.
      3. VENUE FORENSICS: If maps tool is enabled, analyze the physical location of the Venue/Governing Law courtroom.
      4. FORENSIC MODULES: Data Shield, Force Majeure, Titan Asymmetry, Liability Modeling.

      REQUIRED JSON OUTPUT:
      {
        "summary": "string",
        "signerScore": 0-100,
        "worstCaseScenario": "string",
        "silentOmissions": ["string"],
        "projectAudit": {
          "overallScore": 0-100,
          "executiveSummary": "string",
          "crossDocumentConflicts": [{"id": "uuid", "documents": ["string"], "issue": "string", "severity": "High|Medium|Low", "description": "string", "resolution": "string"}],
          "projectTimeline": [{"date": "string", "event": "string", "impact": "string", "riskLevel": "High|Medium|Low"}]
        },
        "jurisdictionAudit": {
          "governingLaw": "string",
          "venue": "string",
          "favorabilityScore": 0-100,
          "warning": "string",
          "venueForensics": {"locationName": "string", "distanceRisk": "Description of travel burden", "mapUrl": "string"}
        },
        "dataShield": { "dataOwnership": "string", "aiTrainingRights": true|false },
        "redFlags": [{"id": "uuid", "issue": "string", "riskLevel": "High|Medium|Low", "originalText": "string", "suggestion": {"whyItMatters": "string", "strategy": "string", "counterOffer": "string", "psychologicalInsight": "string"}}]
      }
    `;

    parts.push({ text: prompt });

    // Build configuration
    const config: any = {
      responseMimeType: "application/json",
    };

    // Only 3-series models support thinking budget
    if (model.startsWith('gemini-3')) {
      config.thinkingConfig = { thinkingBudget: 32768 };
    }

    if (tools.length > 0) {
      config.tools = tools;
    }

    const response = await ai.models.generateContent({
      model,
      contents: { parts: parts },
      config,
    });

    return JSON.parse(response.text || '{}');
  });
};

export const chatWithDocument = async (
  query: string,
  analysis: ContractAnalysis,
  history: ChatMessage[],
  preferences: UserPreferences
): Promise<{ text: string; citations: string[] }> => {
  return withRetry(async () => {
    const model = preferences.preferredModel || "gemini-3-pro-preview";

    const tools: any[] = [];
    if (preferences.enableSearch) tools.push({ googleSearch: {} });
    if (preferences.enableMaps) tools.push({ googleMaps: {} });

    const chat = ai.chats.create({
      model,
      config: {
        systemInstruction: `
          You are the GuardianPact AI Sentinel. Act as a Forensic Legal Bodyguard for the signer.
          Analysis context provided: ${analysis.summary}
          Signer Score: ${analysis.signerScore}
          Jurisdiction: ${preferences.defaultJurisdiction}
        `,
        tools: tools.length > 0 ? tools : undefined
      }
    });

    const response = await chat.sendMessage({ message: query });
    const citations: string[] = [];

    // Extract search grounding
    if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
      response.candidates[0].groundingMetadata.groundingChunks.forEach((chunk: any) => {
        if (chunk.web?.uri) citations.push(chunk.web.uri);
        if (chunk.maps?.uri) citations.push(chunk.maps.uri);
      });
    }

    return { text: response.text || "GuardianPact processing...", citations };
  });
};

export const classifyUpload = async (base64Data: string, mimeType: string, preferences: UserPreferences): Promise<ClassificationResult> => {
  return withRetry(async () => {
    const model = preferences.preferredModel || "gemini-3-flash-preview";
    if (!SUPPORTED_MIME_TYPES.includes(mimeType)) {
      return { intent: 'REVIEW', reasoning: 'Fallback' };
    }
    const response = await ai.models.generateContent({
      model,
      contents: { 
        parts: [
          { inlineData: { data: base64Data, mimeType } }, 
          { text: "Predict intent: REVIEW, CREATE, or COMPARE. Return JSON {intent: '...', reasoning: '...'}" }
        ] 
      },
      config: { responseMimeType: "application/json" }
    });
    return JSON.parse(response.text || '{"intent": "REVIEW"}');
  });
};

