import { refineContract } from '../services/geminiService';

interface ContractCreatorProps {
  initialContent: string;
  onConfirm: (content: string) => void;
  onRestart: () => void;
  // Added preferences to ensure refinement uses the correct AI model and tools
  preferences: UserPreferences;
}

const ContractCreator: React.FC<ContractCreatorProps> = ({ initialContent, onConfirm, onRestart, preferences }) => {
  const [content, setContent] = useState(initialContent);
  const [isRefining, setIsRefining] = useState(false);

  const handleRefine = async (instruction: string) => {
    setIsRefining(true);
    try {
      // Fixed: Passed preferences as the 3rd required argument to refineContract
      const refined = await refineContract(content, instruction, preferences);
      setContent(refined);
    } catch (e) {
      alert("Refining failed.");
    } finally {
      setIsRefining(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto px-4 py-8">
      <div className="mb-8 flex items-center justify-between">
        <div>
          <span className="px-3 py-1 bg-emerald-100 text-emerald-700 text-[10px] font-black uppercase tracking-widest rounded-full">AI Contract Architect</span>
          <h2 className="text-3xl font-black text-slate-900 mt-2">Drafter Mode</h2>
        </div>
        <button 
          onClick={onRestart}
          className="text-slate-400 hover:text-slate-600 font-bold text-sm transition"
        >
          Discard & Restart
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white rounded-3xl shadow-xl shadow-slate-200 overflow-hidden border border-slate-200">
            <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex items-center justify-between">
              <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Legal Document Editor</span>
              {isRefining && <span className="text-xs font-bold text-indigo-600 animate-pulse">Refining with AI...</span>}
            </div>
            <textarea
              value={content}
              onChange={(e) => setContent(e.target.value)}
              className="w-full h-[600px] p-8 font-serif text-lg leading-relaxed focus:outline-none resize-none bg-white text-slate-800"
              placeholder="Your contract will appear here..."
            />
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-indigo-600 rounded-3xl p-6 text-white shadow-xl shadow-indigo-100">
             <div className="flex items-center gap-3 mb-4">
                <i className="fa-solid fa-wand-magic-sparkles text-2xl text-indigo-200"></i>
                <h3 className="text-xl font-bold">Smart Controls</h3>
             </div>

             <div className="space-y-3">
               <button 
                onClick={() => handleRefine("Apply standard fair terms for all parties and ensure compliance with typical consumer protection laws.")}
                disabled={isRefining}
                className="w-full bg-white/10 hover:bg-white/20 py-3 rounded-xl text-sm font-bold transition flex items-center justify-center gap-2"
               >
                 <i className="fa-solid fa-scale-balanced"></i>
                 Standardize Terms
               </button>
               <button 
                onClick={() => handleRefine("Simplify the language to a 10th-grade reading level, removing complex legalese while preserving legal intent.")}
                disabled={isRefining}
                className="w-full bg-white/10 hover:bg-white/20 py-3 rounded-xl text-sm font-bold transition flex items-center justify-center gap-2"
               >
                 <i className="fa-solid fa-language"></i>
                 Simplify Language
               </button>
               <button 
                onClick={() => handleRefine("Add a clear termination clause that allows the signer to exit with 30 days notice.")}
                disabled={isRefining}
                className="w-full bg-white/10 hover:bg-white/20 py-3 rounded-xl text-sm font-bold transition flex items-center justify-center gap-2"
               >
                 <i className="fa-solid fa-door-open"></i>
                 Add Exit Clause
               </button>
             </div>
          </div>

          <div className="bg-white rounded-3xl p-6 border border-slate-100 shadow-sm">
             <h4 className="font-bold text-slate-900 mb-4 flex items-center gap-2">
                <i className="fa-solid fa-file-signature text-emerald-500"></i>
                Deployment
             </h4>
             <button 
                onClick={() => onConfirm(content)}
                className="w-full bg-slate-900 text-white font-bold py-4 rounded-xl hover:bg-slate-800 transition shadow-lg shadow-slate-200 flex items-center justify-center gap-2"
             >
                Prepare for E-Sign
                <i className="fa-solid fa-arrow-right"></i>
             </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ContractCreator;

import React, { useState, useEffect, useMemo } from 'react';
import Layout from './components/Layout';
import UploadArea from './components/UploadArea';
import Dashboard from './components/Dashboard';
import ContractCreator from './components/ContractCreator';
import SignaturePad from './components/SignaturePad';
import Settings from './components/Settings';
import { analyzeBatch, classifyUpload, generateContractContent } from './services/geminiService';
import { AppStep, ContractAnalysis, ContractHistoryItem, UserPreferences, AuditEntry, VerificationMethod } from './types';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.Upload);
  const [analysis, setAnalysis] = useState<ContractAnalysis | null>(null);
  const [generatedContent, setGeneratedContent] = useState<string>('');
  const [loadingMessage, setLoadingMessage] = useState('Sentinel Shield Activating...');
  const [vault, setVault] = useState<ContractHistoryItem[]>([]);
  const [signature, setSignature] = useState<string | null>(null);
  const [currentAuditTrail, setCurrentAuditTrail] = useState<AuditEntry[]>([]);
  const [verificationMethod, setVerificationMethod] = useState<VerificationMethod>('Standard');
  const [currentPreferences, setCurrentPreferences] = useState<UserPreferences>({
    strictMode: false,
    focusAreas: ['Liability', 'Financial', 'Privacy'],
    languagePreference: 'English',
    playbookRules: [],
    preferredModel: 'gemini-3-pro-preview',
    enableSearch: true,
    enableMaps: true,
    defaultJurisdiction: 'Florida, US'
  });

  useEffect(() => {
    const savedVault = localStorage.getItem('signwise_vault_v4');
    if (savedVault) setVault(JSON.parse(savedVault));
    const savedPrefs = localStorage.getItem('guardianpact_prefs');
    if (savedPrefs) setCurrentPreferences(JSON.parse(savedPrefs));
  }, []);

  const savePreferences = (prefs: UserPreferences) => {
    setCurrentPreferences(prefs);
    localStorage.setItem('guardianpact_prefs', JSON.stringify(prefs));
  };

  const addToAudit = (event: string, details: string) => {
    setCurrentAuditTrail(prev => [...prev, { event, timestamp: new Date().toISOString(), details }]);
  };

  const handleUpload = async (files: { base64: string; mimeType: string }[], preferences: UserPreferences) => {
    setStep(AppStep.Analyzing);
    // Merge provided upload prefs with global settings
    const activePrefs = { ...currentPreferences, ...preferences };
    setCurrentPreferences(activePrefs);

    addToAudit("GuardianPact Batch Intake", `${files.length} docs securely processed.`);

    try {
      if (files.length === 1) {
        const classification = await classifyUpload(files[0].base64, files[0].mimeType, activePrefs);
        if (classification.intent === 'CREATE') {
          setLoadingMessage("Architecting Protective Draft...");
          const content = await generateContractContent(files[0].base64, files[0].mimeType, activePrefs);
          setGeneratedContent(content);
          setStep(AppStep.Creator);
          return;
        }
      }
      setLoadingMessage(files.length > 1 ? "Executing Strategic Project Audit..." : "Auditing Forensics & Playbook...");
      const result = await analyzeBatch(files, activePrefs);
      setAnalysis(result);
      addToAudit("Audit Complete", `Safety Score: ${result.projectAudit?.overallScore || result.signerScore}.`);
      setStep(AppStep.Dashboard);
    } catch (e: any) {
      console.error(e);
      const isRateLimit = e?.message?.includes("429") || e?.message?.toLowerCase().includes("quota");
      if (isRateLimit) {
        alert("GuardianPact Alert: API Quota Exceeded. The forensic engine is temporarily overwhelmed. Please wait 60 seconds and try again.");
      } else {
        alert("Structural failure in analysis. Ensure files are legible and the forensic engine is responsive.");
      }
      setStep(AppStep.Upload);
    }
  };

  const finalizeDocument = (status: 'Signed' | 'Declined') => {
    const newItem: ContractHistoryItem = {
      id: Math.random().toString(36).substr(2, 9),
      name: `GuardianPact_Audit_${new Date().toLocaleDateString().replace(/\//g, '_')}`,
      date: new Date().toLocaleDateString(),
      type: analysis?.projectAudit ? 'Forensic Project Audit' : 'Protective Audit',
      status,
      summary: analysis?.summary || "Direct drafting session.",
      analysis: analysis || undefined,
      auditTrail: [...currentAuditTrail, { event: status, timestamp: new Date().toISOString(), details: `Identity Verified via ${verificationMethod}` }],
      signatureData: signature || undefined
    };
    const updated = [newItem, ...vault];
    setVault(updated);
    localStorage.setItem('signwise_vault_v4', JSON.stringify(updated));
    setStep(AppStep.Vault);
  };

  const analytics = useMemo(() => {
    const historicalScores = vault.map(v => v.analysis?.projectAudit?.overallScore || v.analysis?.signerScore || 0).reverse();
    const hazardCounts: Record<string, number> = {};
    vault.forEach(v => {
      v.analysis?.redFlags?.forEach(rf => {
        hazardCounts[rf.issue] = (hazardCounts[rf.issue] || 0) + 1;
      });
    });
    const sortedHazards = Object.entries(hazardCounts)
      .sort((a, b) => b[1] - a[1])
      .slice(0, 5)
      .map(([label, count]) => ({ label, count }));

    return { historicalScores, sortedHazards };
  }, [vault]);

  const handleNavigate = (v: string) => {
    const routeMap: Record<string, AppStep> = {
      upload: AppStep.Upload,
      vault: AppStep.Vault,
      analytics: AppStep.Analytics,
      pricing: AppStep.Pricing,
      help: AppStep.Help,
      privacy: AppStep.Privacy,
      terms: AppStep.Terms,
      auth: AppStep.Auth,
      obligations: AppStep.Obligations,
      collaboration: AppStep.Collaboration,
      settings: AppStep.Settings
    };
    setStep(routeMap[v] || AppStep.Upload);
    window.scrollTo(0, 0);
  };

  const renderContent = () => {
    switch (step) {
      case AppStep.Settings:
        return <Settings preferences={currentPreferences} onUpdate={savePreferences} onBack={() => setStep(AppStep.Upload)} />;
      case AppStep.Upload:
        return (
          <div className="max-w-7xl mx-auto px-4 py-12 md:py-20">
            <div className="text-center mb-12 md:mb-24 animate-in fade-in slide-in-from-bottom-6 duration-700">
              <span className="inline-block px-4 md:px-6 py-1.5 md:py-2 bg-slate-900 text-white text-[8px] md:text-[10px] font-black uppercase tracking-[0.3em] rounded-full mb-6 md:mb-12 border border-slate-700 shadow-sm">Signer-First Forensic Shield</span>
              <h1 className="text-4xl sm:text-6xl md:text-7xl lg:text-9xl font-black text-slate-900 mb-6 md:mb-12 tracking-tighter leading-[0.9] text-balance">Signer-First <span className="text-indigo-600">Bodyguard.</span></h1>
              <p className="text-lg md:text-2xl text-slate-500 max-w-4xl mx-auto leading-relaxed font-medium px-2">GuardianPact AI: Flip the power dynamic. Spot traps, expose asymmetry, and secure your negotiation leverage before you sign.</p>
            </div>
            <UploadArea onUpload={handleUpload} />
          </div>
        );

      case AppStep.Analyzing:
        return (
          <div className="flex flex-col items-center justify-center min-h-[60vh] px-4 animate-in zoom-in-95 duration-500">
            <div className="relative w-48 h-48 md:w-80 md:h-80">
               <div className="absolute inset-0 border-x-[8px] md:border-x-[12px] border-slate-900 rounded-full animate-spin"></div>
               <div className="absolute inset-0 border-y-[8px] md:border-y-[12px] border-indigo-100 rounded-full"></div>
               <div className="absolute inset-8 md:inset-12 bg-white rounded-full shadow-2xl flex items-center justify-center">
                  <i className="fa-solid fa-user-shield text-indigo-600 text-4xl md:text-7xl animate-pulse"></i>
               </div>
            </div>
            <h2 className="text-xl md:text-4xl font-black mt-12 md:mt-20 text-slate-900 tracking-[0.1em] md:tracking-[0.2em] uppercase text-center">{loadingMessage}</h2>
            <p className="text-slate-400 font-bold mt-4 uppercase text-[8px] md:text-[10px] tracking-[0.3em] md:tracking-[0.5em]">Forensic Agent at Work</p>
          </div>
        );

      case AppStep.Dashboard:
        return <Dashboard 
          analysis={analysis!} 
          onRestart={() => setStep(AppStep.Upload)} 
          onDecline={() => finalizeDocument('Declined')}
          onConfirm={() => setStep(AppStep.Verification)} 
          auditTrail={currentAuditTrail}
          // Passed preferences to support the internal Forensic Chat logic
          preferences={currentPreferences}
        />;

      case AppStep.Creator:
        return (
          <ContractCreator 
            initialContent={generatedContent} 
            onConfirm={(content) => {
              setGeneratedContent(content);
              setStep(AppStep.Verification);
            }} 
            onRestart={() => setStep(AppStep.Upload)}
            // Passed preferences for AI refinement engine
            preferences={currentPreferences}
          />
        );

      case AppStep.Verification:
        return (
          <div className="max-w-4xl mx-auto px-4 py-12 md:py-24 animate-in zoom-in-95">
             <div className="bg-white p-8 md:p-20 rounded-[2.5rem] md:rounded-[4rem] shadow-2xl border border-slate-100 text-center relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-2 bg-indigo-600"></div>
                <i className="fa-solid fa-fingerprint text-indigo-600 text-6xl md:text-8xl mb-8 md:mb-12"></i>
                <h2 className="text-3xl md:text-5xl font-black text-slate-900 mb-4 md:mb-8 tracking-tighter">Secure Identification</h2>
                <p className="text-slate-500 mb-8 md:mb-16 max-w-lg mx-auto font-medium text-base md:text-lg leading-relaxed">Identity confirmation required to finalize this forensic project audit.</p>
                <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 md:gap-8 mb-8 md:mb-16">
                   {(['Standard', 'Biometric', 'Behavioral'] as VerificationMethod[]).map(method => (
                     <button 
                       key={method}
                       onClick={() => setVerificationMethod(method)}
                       className={`p-6 md:p-10 rounded-[1.5rem] md:rounded-[3rem] border-2 transition-all duration-300 flex sm:flex-col items-center gap-4 md:gap-6 ${verificationMethod === method ? 'border-indigo-600 bg-indigo-50 shadow-xl scale-102' : 'border-slate-50 hover:border-slate-200'}`}
                     >
                       <div className={`w-12 h-12 md:w-16 md:h-16 rounded-2xl md:rounded-3xl flex items-center justify-center text-xl md:text-3xl shrink-0 ${verificationMethod === method ? 'bg-indigo-600 text-white' : 'bg-slate-50 text-slate-300'}`}>
                         <i className={`fa-solid ${method === 'Standard' ? 'fa-id-card' : method === 'Biometric' ? 'fa-eye' : 'fa-brain'}`}></i>
                       </div>
                       <span className={`text-[9px] md:text-xs font-black uppercase tracking-widest ${verificationMethod === method ? 'text-indigo-900' : 'text-slate-400'}`}>{method}</span>
                     </button>
                   ))}
                </div>
                <button 
                  onClick={() => setStep(AppStep.Signing)}
                  className="w-full sm:w-auto bg-slate-900 text-white px-10 md:px-20 py-4 md:py-8 rounded-[1.5rem] md:rounded-[2.5rem] font-black text-[10px] md:text-xs uppercase tracking-[0.2em] md:tracking-[0.4em] hover:bg-indigo-600 transition shadow-2xl active:scale-95"
                >
                  Verify Guard Identity
                </button>
             </div>
          </div>
        );

      case AppStep.Signing:
        return (
          <div className="max-w-4xl mx-auto px-4 py-12 md:py-24">
             <div className="bg-white p-8 md:p-20 rounded-[2.5rem] md:rounded-[4rem] shadow-2xl border border-slate-100">
                <h2 className="text-3xl md:text-5xl font-black text-slate-900 mb-8 md:mb-12 tracking-tighter uppercase text-center leading-none">Apply Protective <span className="text-indigo-600">Seal</span></h2>
                <SignaturePad onSign={setSignature} onClear={() => setSignature(null)} />
                <button 
                  disabled={!signature}
                  onClick={() => finalizeDocument('Signed')}
                  className={`w-full py-5 md:py-8 rounded-[1.5rem] md:rounded-[2.5rem] font-black text-[10px] md:text-xs uppercase tracking-[0.2em] md:tracking-[0.4em] mt-8 md:mt-12 transition shadow-2xl ${signature ? 'bg-indigo-600 text-white hover:bg-indigo-700' : 'bg-slate-100 text-slate-300 cursor-not-allowed'}`}
                >
                  Confirm Forensic Signature
                </button>
             </div>
          </div>
        );

      case AppStep.Vault:
        return (
          <div className="max-w-7xl mx-auto px-4 py-12 md:py-20">
             <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 mb-12 md:mb-20">
                <div>
                  <h2 className="text-5xl md:text-8xl font-black text-slate-900 tracking-tighter">Vault.</h2>
                  <p className="text-slate-400 font-bold uppercase text-[9px] md:text-xs tracking-[0.3em] md:tracking-[0.5em] mt-3 md:mt-6 flex items-center gap-2">
                    <i className="fa-solid fa-shield-check text-emerald-500"></i> Encrypted Session Access
                  </p>
                </div>
                <div className="flex w-full md:w-auto gap-3">
                  <button onClick={() => setStep(AppStep.Analytics)} className="flex-1 md:flex-none bg-white border border-slate-200 text-slate-700 px-6 py-3 rounded-xl md:rounded-[2rem] font-black text-[9px] md:text-xs uppercase tracking-widest hover:bg-slate-50 transition">Analytics</button>
                  <button onClick={() => setStep(AppStep.Upload)} className="flex-1 md:flex-none bg-indigo-600 text-white px-6 py-3 rounded-xl md:rounded-[2rem] font-black text-[9px] md:text-xs uppercase tracking-widest shadow-2xl hover:bg-indigo-700 transition">Audit New Project</button>
                </div>
             </div>

             <div className="grid gap-4 md:gap-6">
               {vault.map(item => (
                 <div key={item.id} className="bg-white p-6 md:p-12 rounded-[1.5rem] md:rounded-[4rem] border border-slate-100 shadow-sm flex flex-col sm:flex-row items-start sm:items-center justify-between group hover:shadow-xl transition-all cursor-pointer gap-6" onClick={() => { if(item.analysis) { setAnalysis(item.analysis); setStep(AppStep.Dashboard); } }}>
                    <div className="flex items-center gap-6 md:gap-12 w-full">
                       <div className={`w-16 h-16 md:w-24 md:h-24 rounded-[1.5rem] md:rounded-[3rem] shrink-0 flex items-center justify-center text-2xl md:text-4xl ${item.status === 'Signed' ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
                          <i className={`fa-solid ${item.status === 'Signed' ? 'fa-signature' : 'fa-ban'}`}></i>
                       </div>
                       <div className="min-w-0 flex-1">
                          <h4 className="text-lg md:text-3xl font-black text-slate-900 tracking-tighter mb-1 md:mb-2 truncate">{item.name}</h4>
                          <div className="flex flex-wrap gap-3 md:gap-6">
                            <span className="text-[9px] md:text-xs font-black text-slate-400 uppercase tracking-widest">{item.date}</span>
                            <span className={`text-[9px] md:text-xs font-black uppercase tracking-widest ${item.status === 'Signed' ? 'text-emerald-500' : 'text-red-500'}`}>{item.status}</span>
                            <span className="text-[9px] md:text-xs font-black text-indigo-500 uppercase tracking-widest">{item.type}</span>
                          </div>
                       </div>
                    </div>
                 </div>
               ))}
               {vault.length === 0 && (
                 <div className="bg-slate-50 border-4 border-dashed border-slate-100 rounded-[2rem] md:rounded-[5rem] p-16 md:p-32 text-center">
                    <i className="fa-solid fa-box-archive text-5xl md:text-8xl text-slate-200 mb-6 md:mb-10"></i>
                    <h3 className="text-xl md:text-3xl font-black text-slate-300 uppercase tracking-widest">Vault Empty</h3>
                 </div>
               )}
             </div>
          </div>
        );

      case AppStep.Analytics:
        return (
          <div className="max-w-7xl mx-auto px-4 py-12 md:py-24 animate-in slide-in-from-bottom-6">
            <h2 className="text-5xl md:text-8xl font-black mb-8 md:mb-16 tracking-tighter">Forensics.</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 md:gap-10">
               <div className="bg-white p-8 md:p-12 rounded-[2rem] md:rounded-[4rem] shadow-sm border border-slate-100 md:col-span-2 text-center flex flex-col justify-center items-center">
                  <h4 className="text-sm md:text-lg font-black uppercase tracking-widest text-slate-400 mb-8 md:mb-12 self-start">Historical Safety Trends</h4>
                  <div className="h-64 md:h-80 w-full flex items-end gap-3 md:gap-6 p-4 md:p-8 bg-slate-50 rounded-[1.5rem] md:rounded-[3rem] shadow-inner relative overflow-hidden">
                    {analytics.historicalScores.slice(-7).map((h, i) => (
                      <div key={i} className="flex-1 bg-indigo-600 rounded-t-lg md:rounded-t-2xl relative group" style={{ height: `${h}%` }}>
                        <div className="absolute -top-8 left-1/2 -translate-x-1/2 opacity-0 group-hover:opacity-100 bg-slate-900 text-white text-[8px] px-2 py-0.5 rounded font-black transition whitespace-nowrap">Safety: {h}%</div>
                      </div>
                    ))}
                    {analytics.historicalScores.length === 0 && <div className="absolute inset-0 flex items-center justify-center text-slate-300 font-black uppercase">No Data Points</div>}
                  </div>
               </div>
               <div className="bg-slate-900 text-white p-8 md:p-12 rounded-[2rem] md:rounded-[4rem] shadow-2xl flex flex-col justify-between">
                  <div>
                    <h4 className="text-xs md:text-sm font-black text-emerald-400 uppercase tracking-widest mb-6 md:mb-10">Detected Hazards</h4>
                    <div className="space-y-6 md:space-y-8">
                       {analytics.sortedHazards.map((item, i) => (
                         <div key={i} className="flex justify-between items-center border-b border-white/10 pb-3 md:pb-4">
                           <span className="text-[10px] md:text-xs font-bold text-slate-400 truncate mr-2">{item.label}</span>
                           <span className="text-lg md:text-xl font-black">{item.count}</span>
                         </div>
                       ))}
                       {analytics.sortedHazards.length === 0 && <p className="text-xs opacity-30 italic">No project flags archived.</p>}
                    </div>
                  </div>
               </div>
            </div>
          </div>
        );

      default:
        return <div className="text-center py-20 font-black">Route Not Found</div>;
    }
  };

  return (
    <Layout onNavigate={handleNavigate}>
      {renderContent()}
    </Layout>
  );
};

export default App;

export interface AuditEntry {
  event: string;
  timestamp: string;
  details: string;
}

export interface Obligation {
  id: string;
  party: string;
  requirement: string;
  deadline?: string;
  status: 'Pending' | 'Met' | 'Overdue';
  category: string;
}

export interface CrossDocumentConflict {
  id: string;
  documents: string[];
  issue: string;
  severity: 'High' | 'Medium' | 'Low';
  description: string;
  resolution: string;
}

export interface ProjectTimelineEvent {
  date: string;
  event: string;
  impact: string;
  riskLevel: 'High' | 'Medium' | 'Low';
}

export interface ProjectAudit {
  overallScore: number;
  executiveSummary: string;
  crossDocumentConflicts: CrossDocumentConflict[];
  projectTimeline: ProjectTimelineEvent[];
  globalRisks: string[];
  strategicAlignment: string;
}

export interface RedFlag {
  id: string;
  issue: string;
  riskLevel: 'High' | 'Medium' | 'Low';
  suggestion: {
    whyItMatters: string;
    strategy: string;
    counterOffer: string;
    rephrasedClause: string;
    renegotiationKeywords: string[];
    tacticalTips: string[];
    psychologicalInsight: string;
  };
  originalText: string;
}

export interface JurisdictionAudit {
  governingLaw: string;
  venue: string;
  favorabilityScore: number;
  warning: string;
  venueForensics?: {
    locationName: string;
    distanceRisk: string;
    mapUrl?: string;
  };
}

export interface LiabilityModel {
  estimatedExposure: string;
  capStatus: 'Capped' | 'Uncapped' | 'Ambiguous';
  hiddenCosts: string[];
}

export interface DataShield {
  dataOwnership: 'Signer' | 'Counterparty' | 'Joint' | 'Ambiguous';
  aiTrainingRights: boolean;
  thirdPartySharing: string;
  securityStandard?: string;
}

export interface ForceMajeureAudit {
  isIncluded: boolean;
  coversPandemics: boolean;
  signerExitRights: string;
}

export interface ReciprocityGap {
  issue: string;
  counterpartyProtection: string;
  missingSignerProtection: string;
  negotiationChip: string;
}

export interface ContractAnalysis {
  summary: string;
  signerScore: number;
  redFlags: RedFlag[];
  projectAudit?: ProjectAudit;
  jurisdictionAudit?: JurisdictionAudit;
  dataShield?: DataShield;
  forceMajeure?: ForceMajeureAudit;
  reciprocityGaps?: ReciprocityGap[];
  liabilityModel?: LiabilityModel;
  asymmetricClauses?: {
    category: string;
    counterpartyRight: string;
    signerRight: string;
    imbalanceLevel: string;
  }[];
  industryComparison?: { metric: string; assessment: string; isStandard: boolean }[];
  worstCaseScenario?: string;
  silentOmissions?: string[];
}

export type LLMModel = 'gemini-3-pro-preview' | 'gemini-3-flash-preview' | 'gemini-flash-lite-latest' | 'gemini-2.5-flash';

export interface UserPreferences {
  strictMode: boolean;
  preferredModel: LLMModel;
  enableSearch: boolean;
