          <div className="max-w-7xl mx-auto px-4 py-12 md:py-20">
             <h2 className="text-5xl md:text-8xl font-black text-slate-900 tracking-tighter mb-12">Vault.</h2>
             <div className="grid gap-6">
               {vault.map(item => (
                 <div key={item.id} className="bg-white p-12 rounded-[4rem] border border-slate-100 shadow-sm flex items-center justify-between group hover:shadow-xl transition-all cursor-pointer" onClick={() => { if(item.analysis) { setAnalysis(item.analysis); setSealUrl(item.sealUrl || ''); setStep(AppStep.Dashboard); } }}>
                    <div className="flex items-center gap-12 w-full">
