const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.Upload);
  const [analysis, setAnalysis] = useState<ContractAnalysis | null>(null);
  const [sealUrl, setSealUrl] = useState<string>('');
  const [generatedContent, setGeneratedContent] = useState<string>('');
  const [loadingMessage, setLoadingMessage] = useState('Sentinel Shield Activating...');
  const [vault, setVault] = useState<ContractHistoryItem[]>([]);
  const [currentAuditTrail, setCurrentAuditTrail] = useState<AuditEntry[]>([]);
  const [verificationMethod] = useState<VerificationMethod>('Standard');
  const [currentPreferences, setCurrentPreferences] = useState<UserPreferences>({
    strictMode: false,
    provider: 'GEMINI',
    preferredModel: 'gemini-3-pro-preview',
    highQualitySeals: false,
    enableSearch: true,
    enableMaps: true,
    defaultJurisdiction: 'Florida, US',
    voiceSentinelEnabled: false,
    externalKeys: {
      GEMINI: '',
      ANTHROPIC: '',
      MISTRAL: '',
      DEEPSEEK: '',
      OPENAI: ''
    }
  });

  useEffect(() => {
    const savedVault = localStorage.getItem('signwise_vault_v4');
    if (savedVault) setVault(JSON.parse(savedVault));
    const savedPrefs = localStorage.getItem('guardianpact_prefs');
    if (savedPrefs) setCurrentPreferences(JSON.parse(savedPrefs));
  }, []);

  const savePreferences = (prefs: UserPreferences) => {
    setCurrentPreferences(prefs);
    localStorage.setItem('guardianpact_prefs', JSON.stringify(prefs));
  };

  const addToAudit = (event: string, details: string) => {
    setCurrentAuditTrail(prev => [...prev, { event, timestamp: new Date().toISOString(), details }]);
  };

  const handleUpload = async (files: { base64: string; mimeType: string }[], preferences: UserPreferences) => {
    setStep(AppStep.Analyzing);
    const activePrefs = { ...currentPreferences, ...preferences };
    setCurrentPreferences(activePrefs);
    addToAudit("GuardianPact Batch Intake", `${files.length} documents processed.`);

    try {
      if (files.length === 1) {
        const classification = await classifyUpload(files[0].base64, files[0].mimeType, activePrefs);
        if (classification.intent === 'CREATE') {
          setLoadingMessage("Architecting Protective Draft...");
          const content = await generateContractContent(files[0].base64, files[0].mimeType, activePrefs);
          setGeneratedContent(content);
          setStep(AppStep.Creator);
          return;
        }
      }
      setLoadingMessage(`Engaging ${activePrefs.provider} Core...`);
      const result = await analyzeBatch(files, activePrefs);
      setAnalysis(result);

      if (activePrefs.highQualitySeals || activePrefs.enableMaps) {
        setLoadingMessage("Forging Forensic Seal...");
        const seal = await generateForensicSeal(result.summary, activePrefs);
        setSealUrl(seal);
      }

      addToAudit("Audit Complete", `Provider: ${activePrefs.provider}. Score: ${result.signerScore}.`);
      setStep(AppStep.Dashboard);
    } catch (e: any) {
      console.error(e);
      const isRateLimit = e?.message?.includes("429") || e?.message?.toLowerCase().includes("quota");
      if (isRateLimit) {
        alert("Guardian Alert: The selected engine is at capacity. Switch providers in Settings for higher throughput.");
      } else {
        alert("Structural failure in analysis. Engine tier might be restricted.");
      }
      setStep(AppStep.Upload);
    }
  };

  const finalizeDocument = (status: 'Signed' | 'Declined') => {
    const newItem: ContractHistoryItem = {
      id: Math.random().toString(36).substr(2, 9),
      name: `GuardianPact_${new Date().toLocaleDateString().replace(/\//g, '_')}`,
      date: new Date().toLocaleDateString(),
      type: 'Forensic Audit',
      status,
      summary: analysis?.summary || "Draft session.",
      analysis: analysis || undefined,
      sealUrl,
      auditTrail: [...currentAuditTrail, { event: status, timestamp: new Date().toISOString(), details: `Provider: ${currentPreferences.provider}` }]
    };
    const updated = [newItem, ...vault];
    setVault(updated);
    localStorage.setItem('signwise_vault_v4', JSON.stringify(updated));
    setStep(AppStep.Vault);
  };

  const handleNavigate = (v: string) => {
    const routeMap: Record<string, AppStep> = {
      upload: AppStep.Upload,
      vault: AppStep.Vault,
      settings: AppStep.Settings
    };
    setStep(routeMap[v] || AppStep.Upload);
    window.scrollTo(0, 0);
  };

  const renderContent = () => {
    switch (step) {
      case AppStep.Settings:
        return <Settings preferences={currentPreferences} onUpdate={savePreferences} onBack={() => setStep(AppStep.Upload)} />;
      case AppStep.Upload:
        return (
          <div className="max-w-7xl mx-auto px-4 py-12 md:py-20">
            <div className="text-center mb-12 md:mb-24 animate-in fade-in slide-in-from-bottom-6">
              <span className="inline-block px-6 py-2 bg-slate-900 text-white text-[10px] font-black uppercase tracking-[0.3em] rounded-full mb-12 border border-slate-700">Multi-Model Forensic Shield</span>
              <h1 className="text-5xl md:text-9xl font-black text-slate-900 mb-12 tracking-tighter leading-none">GuardianPact <span className="text-indigo-600">AI.</span></h1>
              <p className="text-xl md:text-2xl text-slate-500 max-w-4xl mx-auto leading-relaxed font-medium">Select your engine. Claude, Gemini, DeepSeek, or GPT. Universal protection against predatory terms.</p>
            </div>
            <UploadArea onUpload={handleUpload} />
          </div>
        );
      case AppStep.Analyzing:
        return (
          <div className="flex flex-col items-center justify-center min-h-[60vh] px-4">
            <div className="relative w-48 h-48 md:w-80 md:h-80">
               <div className={`absolute inset-0 border-x-[12px] rounded-full animate-spin ${currentPreferences.provider === 'DEEPSEEK' ? 'border-cyan-500' : currentPreferences.provider === 'ANTHROPIC' ? 'border-orange-500' : 'border-slate-900'}`}></div>
               <div className="absolute inset-8 bg-white rounded-full shadow-2xl flex items-center justify-center">
                  <i className={`fa-solid fa-user-shield text-4xl md:text-7xl animate-pulse ${currentPreferences.provider === 'GEMINI' ? 'text-indigo-600' : 'text-slate-900'}`}></i>
               </div>
            </div>
            <h2 className="text-xl md:text-4xl font-black mt-20 text-slate-900 tracking-[0.2em] uppercase text-center">{loadingMessage}</h2>
            <p className="text-slate-400 font-bold mt-4 uppercase text-[8px] tracking-[0.3em]">{currentPreferences.provider} Protocol Active</p>
          </div>
        );
      case AppStep.Dashboard:
        return <Dashboard 
          analysis={analysis!} 
          sealUrl={sealUrl}
          onRestart={() => setStep(AppStep.Upload)} 
          onDecline={() => finalizeDocument('Declined')}
          onConfirm={() => setStep(AppStep.Signing)} 
          auditTrail={currentAuditTrail}
          preferences={currentPreferences}
        />;
      case AppStep.Creator:
        return <ContractCreator initialContent={generatedContent} onConfirm={(c) => { setGeneratedContent(c); setStep(AppStep.Signing); }} onRestart={() => setStep(AppStep.Upload)} preferences={currentPreferences} />;
      case AppStep.Vault:
        return (
          <div className="max-w-7xl mx-auto px-4 py-12 md:py-20">
             <h2 className="text-5xl md:text-8xl font-black text-slate-900 tracking-tighter mb-12">Vault.</h2>
             <div className="grid gap-6">
               {vault.map(item => (
                 <div key={item.id} className="bg-white p-12 rounded-[4rem] border border-slate-100 shadow-sm flex items-center justify-between group hover:shadow-xl transition-all cursor-pointer" onClick={() => { if(item.analysis) { setAnalysis(item.analysis); setSealUrl(item.sealUrl || ''); setStep(AppStep.Dashboard); } }}>
                    <div className="flex items-center gap-12 w-full">
                       <div className="w-24 h-24 rounded-[3rem] bg-slate-50 flex items-center justify-center border-2 border-slate-100 overflow-hidden">
                          {item.sealUrl ? <img src={item.sealUrl} className="w-full h-full object-cover" /> : <i className="fa-solid fa-signature text-4xl text-indigo-600"></i>}
                       </div>
                       <div className="flex-1">
                          <h4 className="text-3xl font-black text-slate-900 tracking-tighter mb-2">{item.name}</h4>
                          <span className="text-xs font-black text-slate-400 uppercase tracking-widest">{item.date}</span>
                       </div>
                    </div>
                 </div>
               ))}
               {vault.length === 0 && <div className="text-center py-20 text-slate-300 font-black uppercase">Vault Empty</div>}
             </div>
          </div>
        );
      default:
        return <div className="text-center py-20 font-black">Route Not Found</div>;
    }
  };

  return <Layout onNavigate={handleNavigate}>{renderContent()}</Layout>;
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { ContractAnalysis, ChatMessage, AuditEntry, UserPreferences } from '../types';
import RedFlagCard from './RedFlagCard';
import { 
  generateVoiceSummary, 
  decodeBase64, 
  decodeAudioData, 
  chatWithDocument
} from '../services/geminiService';

interface DashboardProps {
  analysis: ContractAnalysis;
  sealUrl?: string;
  onConfirm: () => void;
  onRestart: () => void;
  onDecline: () => void;
  auditTrail: AuditEntry[];
  preferences: UserPreferences;
}

const Dashboard: React.FC<DashboardProps> = ({ analysis, sealUrl, onConfirm, onRestart, onDecline, auditTrail, preferences }) => {
  const [activeTab, setActiveTab] = useState<'risk' | 'negotiate' | 'intel'>('risk');
  const [isGeneratingVoice, setIsGeneratingVoice] = useState(false);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [chatInput, setChatInput] = useState('');
  const [chatHistory, setChatHistory] = useState<ChatMessage[]>([]);
  const [isChatLoading, setIsChatLoading] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (chatEndRef.current) chatEndRef.current.scrollIntoView({ behavior: 'smooth' });
  }, [chatHistory, isChatOpen]);

  const score = analysis?.signerScore || 0;
  const getScoreColor = (s: number) => {
    if (s > 75) return 'bg-emerald-500';
    if (s > 40) return 'bg-amber-500';
    return 'bg-red-600';
  };

  const handleListen = async () => {
    setIsGeneratingVoice(true);
    try {
      const b64 = await generateVoiceSummary(analysis?.summary || "Analyzing document risks.");
      const ctx = new AudioContext();
      const b = await decodeAudioData(decodeBase64(b64), ctx);
      const s = ctx.createBufferSource();
      s.buffer = b; s.connect(ctx.destination); s.start();
    } catch (e) { alert("Audio interrupted."); } finally { setIsGeneratingVoice(false); }
  };

  const handleSendChat = async () => {
    if (!chatInput.trim() || isChatLoading) return;
    const userMsg = chatInput;
    setChatHistory(prev => [...prev, { role: 'user', text: userMsg }]);
    setChatInput('');
    setIsChatLoading(true);
    try {
      const r = await chatWithDocument(userMsg, analysis, chatHistory, preferences);
      setChatHistory(prev => [...prev, { role: 'model', text: r.text, citations: r.citations }]);
    } finally { setIsChatLoading(false); }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 space-y-8 animate-in fade-in duration-500">
      <div className="bg-white p-10 rounded-[3rem] border border-slate-200 shadow-xl overflow-hidden relative">
         <div className="absolute top-0 right-0 p-6 flex items-center gap-4">
           {sealUrl && (
             <div className="w-24 h-24 rounded-2xl overflow-hidden shadow-lg border-2 border-slate-100 group hover:scale-110 transition-transform">
               <img src={sealUrl} alt="Forensic Seal" className="w-full h-full object-cover" />
             </div>
           )}
           <button onClick={handleListen} disabled={isGeneratingVoice} className="w-10 h-10 bg-slate-100 rounded-full flex items-center justify-center text-slate-400 hover:text-indigo-600 transition shadow-sm">
             <i className={`fa-solid ${isGeneratingVoice ? 'fa-spinner fa-spin' : 'fa-volume-high'}`}></i>
           </button>
         </div>
         <div className="flex flex-col md:flex-row items-center gap-12">
            <div className="relative shrink-0">
               <svg className="w-48 h-48 transform -rotate-90">
                  <circle cx="50%" cy="50%" r="45%" stroke="currentColor" strokeWidth="12" fill="transparent" className="text-slate-100" />
                  <circle cx="50%" cy="50%" r="45%" stroke="currentColor" strokeWidth="12" fill="transparent" strokeDasharray={`${score * 2.82} 282`} strokeLinecap="round" className={getScoreColor(score).replace('bg-', 'text-')} />
               </svg>
               <div className="absolute inset-0 flex flex-col items-center justify-center">
                  <span className="text-5xl font-black text-slate-900">{score}</span>
                  <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Safety Score</span>
               </div>
            </div>
            <div className="flex-1 text-center md:text-left">
               <div className="flex items-center gap-3 mb-2">
                 <span className="px-3 py-1 bg-slate-900 text-white text-[8px] font-black uppercase rounded-full">{preferences.provider} CORE</span>
                 <span className="text-slate-400 font-bold text-[8px] uppercase tracking-widest">{preferences.preferredModel}</span>
               </div>
               <h2 className="text-4xl font-black text-slate-900 tracking-tighter mb-4 uppercase">Forensic Audit Result</h2>
               <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
                 <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                   <span className="text-[8px] font-black text-slate-400 uppercase block mb-1">Exposure</span>
                   <p className="text-xs font-bold text-slate-900">{analysis?.liabilityModel?.estimatedExposure || 'TBD'}</p>
                 </div>
                 <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                   <span className="text-[8px] font-black text-slate-400 uppercase block mb-1">Risk Logic</span>
                   <p className="text-xs font-bold text-indigo-600 truncate">{preferences.provider}</p>
                 </div>
                 <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                   <span className="text-[8px] font-black text-slate-400 uppercase block mb-1">Jurisdiction</span>
                   <p className="text-xs font-bold text-slate-900 truncate">{preferences.defaultJurisdiction}</p>
                 </div>
                 <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                   <span className="text-[8px] font-black text-slate-400 uppercase block mb-1">Hazards</span>
                   <p className="text-xs font-bold text-red-600">{analysis?.redFlags?.length || 0} Flags</p>
                 </div>
               </div>
            </div>
         </div>
      </div>

      <div className="flex flex-col lg:flex-row gap-8">
        <div className="flex-grow bg-white rounded-[4rem] shadow-sm border border-slate-100 overflow-hidden">
          <nav className="flex border-b border-slate-100 bg-slate-50/50">
            {[
              { id: 'risk', label: 'Forensic Audit', icon: 'fa-shield-halved' },
              { id: 'intel', label: 'Titan Logic', icon: 'fa-brain' },
              { id: 'negotiate', label: 'Arsenal', icon: 'fa-handshake' },
            ].map(tab => (
              <button 
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`flex-1 py-6 text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-3 transition ${activeTab === tab.id ? 'bg-white text-indigo-600 border-b-4 border-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}
              >
                <i className={`fa-solid ${tab.icon} text-sm`}></i>
                {tab.label}
              </button>
            ))}
          </nav>

          <div className="p-10 min-h-[500px]">
            {activeTab === 'risk' && (
              <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
                <div className="space-y-6">
                  {(analysis?.redFlags || []).map((f, i) => <RedFlagCard key={i} {...f} id={i.toString()} />)}
                </div>
                <div className="space-y-6">
                   <div className="bg-slate-900 text-white p-8 rounded-[3rem] shadow-2xl">
                     <h4 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-4">Executive Briefing</h4>
                     <p className="text-sm leading-relaxed opacity-90">{analysis?.summary}</p>
                   </div>
                </div>
              </div>
            )}

            {activeTab === 'intel' && (
              <div className="space-y-8 animate-in zoom-in-95">
                <div className="bg-white p-12 rounded-[3rem] border-2 border-slate-100">
                   <h4 className="text-sm font-black uppercase tracking-widest text-slate-400 mb-8 flex items-center gap-3">
                     <i className="fa-solid fa-scale-unbalanced-flip text-indigo-500"></i> Asymmetry Scanner
                   </h4>
                   <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                     {(analysis?.asymmetricClauses || []).map((ac, i) => (
                       <div key={i} className="bg-slate-50 p-6 rounded-[2rem] border border-slate-100">
                         <h5 className="text-[10px] font-black uppercase text-indigo-600 mb-4">{ac.category}</h5>
                         <div className="grid grid-cols-2 gap-6">
                           <div>
                             <span className="text-[7px] font-black uppercase text-slate-400 block mb-1">Counterparty</span>
                             <p className="text-[10px] font-bold text-slate-800 leading-relaxed">{ac.counterpartyRight}</p>
                           </div>
                           <div className="border-l border-slate-200 pl-6">
                             <span className="text-[7px] font-black uppercase text-slate-400 block mb-1">Signer</span>
                             <p className="text-[10px] font-bold text-slate-800 leading-relaxed">{ac.signerRight}</p>
                           </div>
                         </div>
                       </div>
                     ))}
                   </div>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Global Chat Sentinel */}
        <div className={`fixed bottom-8 right-8 w-[450px] bg-white rounded-[3rem] shadow-2xl border border-slate-200 flex flex-col transition-all duration-500 z-[100] ${isChatOpen ? 'h-[600px] opacity-100' : 'h-20 w-20 rounded-full'}`}>
           {!isChatOpen ? (
             <button onClick={() => setIsChatOpen(true)} className="w-full h-full bg-slate-900 rounded-full flex items-center justify-center text-white shadow-2xl hover:scale-105 transition">
                <i className="fa-solid fa-user-shield text-2xl"></i>
             </button>
           ) : (
             <div className="flex flex-col h-full overflow-hidden">
                <div className="p-8 bg-slate-900 text-white flex justify-between items-center shrink-0">
                   <div className="flex items-center gap-4">
                      <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center">
                        <i className="fa-solid fa-shield-halved text-sm"></i>
                      </div>
                      <div>
                        <h4 className="text-sm font-black uppercase tracking-widest">Sentinel Chat</h4>
                        <span className="text-[8px] text-emerald-400 font-bold uppercase">{preferences.provider} ENGINE</span>
                      </div>
                   </div>
                   <button onClick={() => setIsChatOpen(false)} className="text-slate-400 hover:text-white transition"><i className="fa-solid fa-xmark text-lg"></i></button>
                </div>
                <div className="flex-grow overflow-y-auto p-8 space-y-6">
                   {chatHistory.map((msg, i) => (
                     <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
